function cleanContractType(v){
  const raw=String(v||"").trim();
  if(!raw)return "";
  if(/^\d{4,6}$/.test(raw))return "";
  if(/^\d{1,2}[\/.-]\d{1,2}[\/.-]\d{2,4}$/.test(raw))return "";
  if(/^\d{4}-\d{1,2}-\d{1,2}$/.test(raw))return "";
  const normalized=raw.normalize("NFD").replace(/[\u0300-\u036f]/g,"").toUpperCase().replace(/\s+/g," ").trim();
  if(normalized==="CDD"||normalized.includes("CDD"))return "CDD";
  const known=TYPES_CONTRAT.find(t=>t.normalize("NFD").replace(/[\u0300-\u036f]/g,"").toUpperCase()===normalized);
  return known||"";
}
