function normalizeSocieteName(name){
  const normalized=String(name||"").trim().replace(/\s+/g," ").toUpperCase();
  const key=normalized.normalize("NFD").replace(/[\u0300-\u036f]/g,"");
  if(key==="IRON GLOBAL SECURITE")return "IRON GLOBAL SÉCURITÉ";
  return normalized;
}
function isRemovedSociete(name){
  return REMOVED_SOCIETES.some(s=>normalizeSocieteName(s)===normalizeSocieteName(name));
}
function isAllowedSociete(name){
  return !!normalizeSocieteName(name);
}
function societeExists(name){
  const n=normalizeSocieteName(name);
  return SOCIETES.some(s=>normalizeSocieteName(s)===n);
}
function canonicalSocieteName(name,source){
  const n=normalizeSocieteName(name);
  if(!n)return "";
  const list=Array.isArray(source)&&source.length?source:SOCIETES;
  return list.find(s=>normalizeSocieteName(s)===n)||n;
}
function defaultSocieteAccessPasswords(){
  return {};
}
function purgeRemovedSocietesFromStorage(){}
function uniqueSocieteNames(names){
  const out=[];
  (names||[]).forEach(name=>{
    const normalized=normalizeSocieteName(name);
    if(normalized&&!out.some(s=>normalizeSocieteName(s)===normalized))out.push(normalized);
  });
  return out;
}
function deriveSocietesFromData(source){
  const src=source||db||{};
  const names=[];
  ["agents","candidats","sites","materiel","clients","prospects","opportunites","devis","factures","paiements","demandesPersonnel","demandesStructure","pointages","feuillePresence","opsMouvements"].forEach(key=>{
    if(!Array.isArray(src[key]))return;
    src[key].forEach(item=>{if(item&&item.societe)names.push(item.societe)});
  });
  return uniqueSocieteNames(names);
}
function societeConfig(){
  const remote=(db&&db.societesConfig&&typeof db.societesConfig==="object")?db.societesConfig:{};
  const remoteAccess=(remote.access&&typeof remote.access==="object")?remote.access:{};
  const custom=[...DEFAULT_SOCIETES,...(Array.isArray(remote.custom)?remote.custom:[]),...deriveSocietesFromData()];
  return {
    custom:uniqueSocieteNames(custom).filter(s=>!isRemovedSociete(s)),
    descriptions:{...(remote.descriptions||{})},
    images:{...(remote.images||{})},
    access:{...remoteAccess,requirePassword:false,passwords:{}},
    removed:REMOVED_SOCIETES.slice()
  };
}
function saveSocieteConfig(patch){
  const cur=societeConfig();
  const next={...cur,...(patch||{}),removed:REMOVED_SOCIETES.slice()};
  next.custom=uniqueSocieteNames(next.custom).filter(s=>!isRemovedSociete(s));
  if(db)db.societesConfig=next;
}
function loadCustomSocietes(){
  purgeRemovedSocietesFromStorage();
  SOCIETES.splice(0,SOCIETES.length,...societeConfig().custom);
}
function saveCustomSocietes(){
  saveSocieteConfig({custom:SOCIETES.slice()});
}
function buildSocieteConfigWith(name,description,image){
  const cfg=societeConfig();
  const normalized=normalizeSocieteName(name);
  const custom=Array.isArray(cfg.custom)?cfg.custom.slice():[];
  if(normalized&&!custom.some(s=>normalizeSocieteName(s)===normalized))custom.push(normalized);
  cfg.custom=custom.filter(s=>s&&!isRemovedSociete(s));
  cfg.descriptions={...(cfg.descriptions||{})};
  cfg.images={...(cfg.images||{})};
  if(description)cfg.descriptions[normalized]=description;else delete cfg.descriptions[normalized];
  if(image)cfg.images[normalized]=image;else delete cfg.images[normalized];
  cfg.removed=REMOVED_SOCIETES.slice();
  return cfg;
}
function unwrapIrongsCollection(value){
  return value&&typeof value==="object"&&value.data&&typeof value.data==="object"?value.data:value;
}
async function verifySocietePersisted(name){
  if(!name||!sgdiAuthToken())return false;
  let cfg=unwrapIrongsCollection(await sgdiApi("/api/irongs/collections/societesConfig",{method:"GET",legacy:false}));
  const custom=cfg&&Array.isArray(cfg.custom)?cfg.custom:[];
  if(custom.some(s=>normalizeSocieteName(s)===normalizeSocieteName(name)))return true;
  const snapshot=await sgdiApi("/api/irongs/db",{method:"GET",legacy:false});
  cfg=snapshot&&snapshot.societesConfig;
  const snapshotCustom=cfg&&Array.isArray(cfg.custom)?cfg.custom:[];
  return snapshotCustom.some(s=>normalizeSocieteName(s)===normalizeSocieteName(name));
}
async function persistSocieteConfig(nameToVerify){
  if(!db)throw new Error("Base non chargée");
  if(nameToVerify&&!isAllowedSociete(nameToVerify))throw new Error("Nom de société obligatoire");
  db.societesConfig=societeConfig();
  let saved=unwrapIrongsCollection(await sgdiApi("/api/irongs/collections/societesConfig",{method:"PUT",body:{data:db.societesConfig},legacy:false}));
  if(!saved||typeof saved!=="object"||Array.isArray(saved))throw new Error("Réponse PostgreSQL invalide");
  db.societesConfig=saved;
  let cfg=saved;
  if(nameToVerify){
    let custom=Array.isArray(cfg.custom)?cfg.custom:[];
    let ok=custom.some(s=>normalizeSocieteName(s)===normalizeSocieteName(nameToVerify));
    if(!ok){
      const forcedCustom=[...custom,nameToVerify].filter((s,i,a)=>s&&a.findIndex(x=>normalizeSocieteName(x)===normalizeSocieteName(s))===i);
      cfg={...cfg,custom:forcedCustom};
      db.societesConfig=cfg;
      saved=unwrapIrongsCollection(await sgdiApi("/api/irongs/collections/societesConfig",{method:"PUT",body:{data:cfg},legacy:false}));
      if(!saved||typeof saved!=="object"||Array.isArray(saved))throw new Error("Réponse PostgreSQL invalide après correction");
      db.societesConfig=saved;
      cfg=saved;
      custom=Array.isArray(cfg.custom)?cfg.custom:[];
      ok=custom.some(s=>normalizeSocieteName(s)===normalizeSocieteName(nameToVerify));
    }
    if(!ok)throw new Error("Société absente après écriture PostgreSQL");
  }
  if(typeof loadCustomSocietes==="function")loadCustomSocietes();
  sgdiPostgresReady=true;
  sgdiDirty=false;
  return cfg;
}
