function upsertServerEmployee(row){
  const a=employeeFromApi(row);
  if(!db)db={};
  if(!Array.isArray(db.agents))db.agents=[];
  const existing=db.agents.find(x=>String(x.backendId||"")===String(a.backendId)||String(x.id||"")===String(a.id)||String(x.matricule||"")===String(a.matricule));
  if(existing)Object.assign(existing,a);else db.agents.push(a);
  return existing||a;
}
function employeeApiPayload(a){
  if(!a)throw new Error("Employé invalide");
  const firstName=String(a.prenom||a.first_name||"").trim();
  const lastName=String(a.nom||a.last_name||"").trim();
  if(!firstName||!lastName)throw new Error("Nom et prénom employé obligatoires");
  const extra={...a};
  delete extra.backendId;
  delete extra.extra;
  extra._legacy={...(a.extra?._legacy||{}),...extra};
  const validNin=validEmployeeNinOrNull(a.nin);
  if(a.nin&&!validNin){
    extra.ninInvalidOriginal=String(a.nin||"").trim();
    extra.ninAlert=true;
    extra.importNinWarning=extra.importNinWarning||a.importNinWarning||true;
    extra.nin="";
    if(extra._legacy)extra._legacy.nin="";
  }else{
    extra.nin=validNin||"";
    if(extra._legacy)extra._legacy.nin=validNin||"";
  }
  const existingBackendId=sqlBackendId(a.backendId);
  const code=existingBackendId
    ? (normalizeEmployeeCodeFormat(a.matricule||a.code||"")||nextMatricule(db.agents,a.societe))
    : nextMatricule(db.agents,a.societe);
  return {
    code,
    first_name:firstName,
    last_name:lastName,
    father_name:a.nomPere||null,
    mother_name:a.nomMere||null,
    nin:validNin,
    birth_date:a.dateNaissance||null,
    birth_place:a.lieuNaissance||null,
    family_status:a.situation||null,
    children_count:parseInt(a.nombreEnfants??a.children_count??0,10)||0,
    phone:a.telephone||null,
    email:a.email||null,
    address:a.adresse||a.address||null,
    commune:a.commune||null,
    wilaya:a.wilaya||null,
    position:a.fonction||a.posteContrat||a.posteSouhaite||null,
    society:a.societe||null,
    status:a.statut||"actif",
    contract_type:cleanContractType(a.typeContrat)||"CDD",
    salary_net:Number(a.salaireNet||0)||0,
    recruit_date:a.dateRecrutement||null,
    trial_end_date:a.dateFinEssai||null,
    contract_end_date:employeePositionContractEndDate(a)||null,
    locked:a.locked?1:0,
    extra
  };
}
async function sgdiPullEmployees(options){
  const opt=options||{};
  if(!sgdiBackendShouldUse()||!sgdiAuthToken())return null;
  try{
    const employees=await window.SGDI_API.employees.list();
    if(!Array.isArray(employees))return null;
    db.agents=dedupeEmployeesByBackendId(employees.map(employeeFromApi));
    normalizeEmployeeCodesInDB();
    if(opt.render&&typeof render==="function")render();
    if(!opt.silent&&typeof toast==="function")toast("Employés backend chargés","success");
    return db.agents;
  }catch(e){
    if(!opt.silent&&typeof toast==="function")toast("Impossible de charger les employés backend : "+(e.message||e),"error");
  }
  return null;
}
function dedupeEmployeesByBackendId(list){
  const byBackend=new Map();
  const out=[];
  (list||[]).forEach(a=>{
    const key=String(a?.backendId||"").trim();
    if(key){
      byBackend.set(key,a);
      return;
    }
    out.push(a);
  });
  return[...byBackend.values(),...out];
}
async function sgdiStartupBackendSync(){
  if(!sgdiBackendShouldUse())return;
  await sgdiPullState({silent:true,render:true});
}
