async function sgdiRunLegacyAction(action,payload){
  const out=await SGDI.actions.run(action,payload||{});
  if(out&&out.data&&typeof out.data==="object"){
    const data=out.data;
    if(data.item&&payload?.collection)sgdiUpsertServerItem(payload.collection,data.item);
    if(data.movement&&typeof opsUpsertMovementHistory==="function")opsUpsertMovementHistory(data.movement);
    if(data.client)sgdiUpsertServerItem("clients",data.client);
    if(data.prospect)sgdiUpsertServerItem("prospects",data.prospect);
  }
  return out;
}
function sgdiServerPageKey(scope,extra){
  return "sgdi:page:"+String(scope||"list")+":"+String(extra||"");
}
function sgdiServerCurrentPage(scope,extra){
  return Math.max(1,parseInt(sessionStorage.getItem(sgdiServerPageKey(scope,extra))||"1",10)||1);
}
function sgdiServerSetPage(scope,extra,page){
  sessionStorage.setItem(sgdiServerPageKey(scope,extra),String(Math.max(1,parseInt(page||"1",10)||1)));
  if(typeof renderView==="function")renderView();
  else if(typeof render==="function")render();
}
function sgdiServerPaginationHTML(scope,extra,result){
  const page=Math.max(1,parseInt(result?.page||"1",10)||1);
  const pages=Math.max(1,parseInt(result?.pages||"1",10)||1);
  const total=parseInt(result?.total||"0",10)||0;
  if(total===0||pages<=1)return "";
  return `<div class="flex items-center justify-between gap-3 mt-4 text-sm">
    <div class="text-slate-500 font-semibold">${total} élément(s) · page ${page}/${pages}</div>
    <div class="flex gap-2">
      <button class="btn btn-ghost text-xs" ${page<=1?"disabled":""} onclick="sgdiServerSetPage('${scope}','${extra}',${page-1})">← Précédent</button>
      <button class="btn btn-ghost text-xs" ${page>=pages?"disabled":""} onclick="sgdiServerSetPage('${scope}','${extra}',${page+1})">Suivant →</button>
    </div>
  </div>`;
}
function sgdiUpsertServerItem(listName,item){
  if(!item)return null;
  if(!db[listName])db[listName]=[];
  const list=db[listName];
  const idx=list.findIndex(x=>(item.backendId&&x.backendId===item.backendId)||(item.id&&x.id===item.id));
  if(idx>=0)list[idx]={...list[idx],...item};
  else list.push(item);
  return idx>=0?list[idx]:item;
}
window.SGDI_SIDEBAR_STATS=null;
function sgdiActiveStatsSociety(){
  try{
    return (typeof currentStructureSocieteFilter==="function"&&currentStructureSocieteFilter())||session?.societe||(typeof mySoc==="function"&&mySoc())||"";
  }catch(e){return session?.societe||""}
}
async function sgdiRefreshSidebarStats(society){
  if(!window.SGDI_API?.ui?.sidebarStats)return null;
  try{
    const activeSociety=society!==undefined?society:sgdiActiveStatsSociety();
    const stats=await window.SGDI_API.ui.sidebarStats(activeSociety?{society:activeSociety}:{});
    window.SGDI_SIDEBAR_STATS=stats;
    window.dispatchEvent(new CustomEvent("sgdi:sidebar-stats",{detail:stats}));
    return stats;
  }catch(error){
    console.warn("Stats sidebar indisponibles",error);
    return null;
  }
}
window.sgdiRefreshSidebarStats=sgdiRefreshSidebarStats;
let sgdiCountersRefreshRunning=false;
let sgdiCountersRefreshQueued=false;
let sgdiSidebarStatsTimer=null;
let sgdiSidebarLastStatsAt=0;
async function sgdiRefreshCountersNow(options){
  if(!session||!sgdiAuthToken())return null;
  if(sgdiCountersRefreshRunning){sgdiCountersRefreshQueued=true;return null}
  sgdiCountersRefreshRunning=true;
  try{
    const stats=await sgdiRefreshSidebarStats();
    try{refreshModuleCountersRibbon()}catch(e){}
    return stats;
  }catch(e){
    console.warn("Rafraîchissement compteurs SGDI échoué",e);
    return null;
  }finally{
    sgdiCountersRefreshRunning=false;
    if(sgdiCountersRefreshQueued){
      sgdiCountersRefreshQueued=false;
      setTimeout(()=>sgdiRefreshCountersNow(options),250);
    }
  }
}
window.sgdiRefreshCountersNow=sgdiRefreshCountersNow;
function scheduleSidebarStatsRefresh(){
  if(!session||!sgdiAuthToken()||sgdiCountersRefreshRunning)return;
  const now=Date.now();
  if(now-sgdiSidebarLastStatsAt<5000)return;
  sgdiSidebarLastStatsAt=now;
  clearTimeout(sgdiSidebarStatsTimer);
  sgdiSidebarStatsTimer=setTimeout(()=>sgdiRefreshCountersNow({reason:"schedule"}),350);
}
window.addEventListener("sgdi:sidebar-stats",()=>{
  try{refreshModuleCountersRibbon()}catch(e){}
  try{renderSidebar()}catch(e){}
  try{
    const hash=String(location.hash||"");
    if(hash==="#/materiel"||hash.startsWith("#/materiel/dashboard"))renderView();
  }catch(e){}
});
function userPermissionCache(){
  if(!db.settings||typeof db.settings!=="object")db.settings={};
  if(!db.settings.userSocietePermissions||typeof db.settings.userSocietePermissions!=="object")db.settings.userSocietePermissions={};
  return db.settings.userSocietePermissions;
}
function rememberUserPermissions(username,societes,niveau,structures,validationCodeEnabled){
  if(!username)return;
  const cache=userPermissionCache();
  const prev=cache[username]||{};
  cache[username]={societesAutorisees:Array.isArray(societes)?societes:[],structuresAutorisees:normalizeStructureList(Array.isArray(structures)?structures:(Array.isArray(prev.structuresAutorisees)?prev.structuresAutorisees:[])),niveau:niveau||"",validationCodeEnabled:validationCodeEnabled!==undefined?!!validationCodeEnabled:!!prev.validationCodeEnabled};
}
async function sgdiLoadAuthState(){
  if(!sgdiAuthToken()||!db)return;
  if(!isAdmin())return;
  try{
    const users=await SGDI.auth.listUsers();
    const cache=userPermissionCache();
    const previous={};
    (db.users||[]).forEach(u=>{if(u&&u.username)previous[u.username]=u});
    db.users=(users||[]).map(u=>{
      const cached=cache[u.username]||{};
      const prev=previous[u.username]||{};
      const pgSoc=Array.isArray(u.authorized_societies)?u.authorized_societies:[];
      const pgStruct=normalizeStructureList(u.authorized_structures);
      const savedSoc=Array.isArray(cached.societesAutorisees)?cached.societesAutorisees:(Array.isArray(prev.societesAutorisees)?prev.societesAutorisees:[]);
      const savedStruct=normalizeStructureList(Array.isArray(cached.structuresAutorisees)?cached.structuresAutorisees:(Array.isArray(prev.structuresAutorisees)?prev.structuresAutorisees:[]));
      const socs=pgSoc.length?pgSoc:savedSoc;
      const structs=pgStruct.length?pgStruct:savedStruct;
      const niveau=u.access_level||u.niveau||cached.niveau||prev.niveau||(String(u.role||"").toUpperCase().startsWith("ADM")||u.role==="admin"?"H5":"H3");
      const validationCodeEnabled=!!(cached.validationCodeEnabled??prev.validationCodeEnabled);
      rememberUserPermissions(u.username,socs,niveau,structs,validationCodeEnabled);
      return {
        username:u.username,
        nom:u.full_name||u.username,
        role:u.role||"agent",
        niveau,
        actif:u.is_active!==false,
        societesAutorisees:socs,
        structuresAutorisees:structs,
        validationCodeEnabled
      };
    });
  }catch(e){
    console.warn("Utilisateurs PostgreSQL indisponibles",e);
  }
  try{
    const rules=await SGDI.auth.accessRules();
    const droits={};
    (rules||[]).forEach(r=>{droits[(r.module_key||r.moduleKey)+":"+r.role]=!!r.allowed});
    db.droitsAcces=droits;
  }catch(e){
    console.warn("Droits PostgreSQL indisponibles",e);
  }
}

function normalizeCandidateIdentity(c){
  if(!c||typeof c!=="object")return c;
  c.nom=String(c.nom??c.last_name??c.lastName??"").trim();
  c.prenom=String(c.prenom??c.first_name??c.firstName??"").trim();
  return c;
}
function candidateIdentityMissing(c){
  normalizeCandidateIdentity(c);
  const missing=[];
  if(!String(c?.nom||"").trim())missing.push("Nom");
  if(!String(c?.prenom||"").trim())missing.push("Prénom");
  return missing;
}
function candidateHasMinimumData(c){
  if(!c||typeof c!=="object")return false;
  normalizeCandidateIdentity(c);
  return String(c.nom||"").trim().length>=2&&String(c.prenom||"").trim().length>=2;
}
function candidateMinimumDataMessage(c){
  const missing=candidateIdentityMissing(c);
  return missing.length?"Champs obligatoires manquants : "+missing.join(", "):"Nom et prénom doivent contenir au moins 2 caractères";
}
function isTempCandidateId(id){return String(id||"").startsWith("tmp_cd_")}
function newTempCandidateId(){return uid("cd")}
function pruneEmptyCandidates(){
  return sanitizeCandidatesInDB();
}
function isRemovedQQQCandidate(c){
  if(!c||typeof c!=="object")return false;
  normalizeCandidateIdentity(c);
  const full=String(`${c.nom||""} ${c.prenom||""}`).trim().toLowerCase().replace(/\s+/g," ");
  const reversed=String(`${c.prenom||""} ${c.nom||""}`).trim().toLowerCase().replace(/\s+/g," ");
  const phone=String(c.telephone||c.phone||c.tel||"").replace(/\D+/g,"");
  return (full==="qqq qq"||reversed==="qqq qq")&&phone==="0770112034";
}
function removeQQQCandidateFromDB(){
  if(!db||!Array.isArray(db.candidats))return 0;
  const before=db.candidats.length;
  db.candidats=db.candidats.filter(c=>!isRemovedQQQCandidate(c));
  return before-db.candidats.length;
}
function sanitizeCandidatesInDB(){
  if(!db||!Array.isArray(db.candidats))return 0;
  db.candidats.forEach(sanitizeCandidatePosteFields);
  return removeQQQCandidateFromDB()+cleanupDuplicateCandidates(false);
}
function candidateApiPayload(c){
  const firstName=String(c.prenom||c.first_name||"").trim();
  const lastName=String(c.nom||c.last_name||"").trim();
  if(firstName.length<2||lastName.length<2)throw new Error("Nom et prénom obligatoires avant création PostgreSQL");
  sanitizeCandidatePosteFields(c);
  const data={...c};
  if(isTempCandidateId(data.id))delete data.id;
  delete data.isNew;
  const allowedSocieties=currentAllowedSocietes();
  const society=canonicalSocieteName(c.societe||c.society||"",allowedSocieties);
  if(society){
    data.societe=society;
    data.society=society;
  }
  return {
    first_name:firstName,
    last_name:lastName,
    phone:c.telephone||c.phone||null,
    email:c.email||null,
    desired_position:candidatePosteCleanValue(c.posteSouhaite||c.poste||c.desired_position)||null,
    society:society||null,
    expected_salary:c.salairePrevu===""||c.salairePrevu===undefined?null:Number(c.salairePrevu)||null,
    recruiter_opinion:c.avisCommentaire||c.avisRecruteur||c.recruiter_opinion||null,
    status:c.statut||c.status||"nouvelle",
    data
  };
}
function candidateFromApi(row){
  const data=row&&row.data&&typeof row.data==="object"?row.data:{};
  const apiId=String(row.id);
  const localId=data.id&&!isTempCandidateId(data.id)?String(data.id):apiId;
  const candidate={
    ...data,
    id:localId,
    backendId:row.id,
    nom:data.nom||row.last_name||"",
    prenom:data.prenom||row.first_name||"",
    telephone:data.telephone||row.phone||"",
    email:data.email||row.email||"",
    posteSouhaite:data.posteSouhaite||row.desired_position||"",
    societe:data.societe||row.society||"",
    salairePrevu:data.salairePrevu??row.expected_salary??"",
    avisCommentaire:data.avisCommentaire||row.recruiter_opinion||"",
    statut:candidatIsRecruited({statut:row.status})?row.status:(data.statut||row.status||"nouvelle"),
    createdAt:data.createdAt||String(row.created_at||"").slice(0,10)||today()
  };
  sanitizeCandidatePosteFields(candidate);
  return candidate;
}
async function syncCandidatesFromPostgres(){
  if(!sgdiAuthToken()||!db)return;
  try{
    const rows=await SGDI.rh.candidates();
    const mappedRows=(rows||[]).map(candidateFromApi);
    mappedRows.filter(c=>!candidateHasMinimumData(c)&&sqlBackendId(c.backendId)).forEach(c=>deleteCandidateFromPostgres(c).catch(e=>console.warn("Candidat vide non supprimé",e)));
    mappedRows.filter(c=>isRemovedQQQCandidate(c)&&sqlBackendId(c.backendId)).forEach(c=>deleteCandidateFromPostgres(c).catch(e=>console.warn("Candidat QQQ QQ non supprimé PostgreSQL",e)));
    const fromPg=mappedRows.filter(c=>candidateHasMinimumData(c)&&!isRemovedQQQCandidate(c));
    sanitizeCandidatesInDB();
    const byKey=new Map();
    (db.candidats||[]).filter(candidateHasMinimumData).forEach(c=>{const k=candidateDedupeKey(c)||String(c.backendId||c.id);if(!byKey.has(k)||candidateCompletenessScore(c)>candidateCompletenessScore(byKey.get(k)))byKey.set(k,c)});
    fromPg.forEach(c=>{
      const k=candidateDedupeKey(c)||String(c.backendId||c.id);
      const prev=byKey.get(k);
      if(prev&&prev.backendId&&c.backendId&&String(prev.backendId)!==String(c.backendId)){
        const keep=candidateCompletenessScore(prev)>=candidateCompletenessScore(c)?prev:c;
        const drop=keep===prev?c:prev;
        if(sqlBackendId(drop.backendId))deleteCandidateFromPostgres(drop).catch(e=>console.warn("Doublon candidat non supprimé",e));
        byKey.set(k,{...prev,...keep});
      }else{
        byKey.set(k,{...(prev||{}),...c});
      }
    });
    db.candidats=[...byKey.values()].filter(candidateHasMinimumData);
  }catch(e){
    console.warn("Candidats PostgreSQL indisponibles",e);
    throw e;
  }
}
async function persistCandidateToPostgres(c,options){
  if(!c)return null;
  const originalId=String(c.id||"");
  const originalBackendId=String(c.backendId||"");
  sgdiRequireServerWrite();
  const opt=options||{};
  const backendId=sqlBackendId(c.backendId);
  if(isTempCandidateId(c.id)){
    if(!opt.allowCreate)return null;
    c.id=candidatTempRealIds[c.id]||(candidatTempRealIds[c.id]=uid("cd"));
    rememberCandidatAlias(originalId,c.id);
  }
  if(!candidateHasMinimumData(c)){
    if(backendId)await deleteCandidateFromPostgres(c);
    return null;
  }
  if(!backendId&&!opt.allowCreate)return null;
  const payload=candidateApiPayload(c);
  const action=backendId?await SGDI.rh.updateCandidate(backendId,payload):await SGDI.rh.createCandidate(payload);
  const saved=action&&action.status==="success"?action.data:action;
  if(!saved||!saved.id)throw new Error("Confirmation PostgreSQL invalide");
  const mapped=candidateFromApi(saved);
  Object.assign(c,mapped,{id:c.id||mapped.id,backendId:saved.id});
  rememberCandidatAlias(originalId,c.id);
  rememberCandidatAlias(originalId,saved.id);
  rememberCandidatAlias(originalBackendId,c.id);
  rememberCandidatAlias(saved.id,c.id);
  stashCandidatForRoute(c,[originalId,originalBackendId,saved.id,mapped.id]);
  window.__sgdiLastLocalSaveAt=Date.now();
  if(db){
    if(!Array.isArray(db.candidats))db.candidats=[];
    if(!db.candidats.some(x=>x===c||String(x.id)===String(c.id)||String(x.backendId||"")===String(c.backendId||""))){
      db.candidats.push(c);
    }
  }
  return c;
}
async function deleteCandidateFromPostgres(c){
  if(isAdminSystemSession()&&!(await ensureAdminSystemApiToken()))throw new Error("jeton Administration système absent");
  const backendId=sqlBackendId(c?.backendId);
  if(backendId&&sgdiAuthToken())await SGDI.rh.deleteCandidate(backendId);
}

function sqlInt(v){const n=parseInt(v,10);return Number.isFinite(n)?n:null}
function sqlBackendId(v){if(v===null||v===undefined||v===""||v==="None")return null;const s=String(v).trim();if(!new RegExp("^[1-9]"+"\\d*$").test(s))return null;return parseInt(s,10)}
function sqlNum(v){const n=parseFloat(String(v??"").replace(/\s/g,"").replace(",","."));return Number.isFinite(n)?n:0}
function sqlDate(v){return v?String(v).slice(0,10):null}
function sqlRelationId(list,id){const row=(list||[]).find(x=>String(x.id)===String(id)||String(x.backendId)===String(id));return row&&row.backendId?row.backendId:sqlInt(id)}
function sgdiIsNotFoundError(e){return /(^|\D)404(\D|$)|not\s*found|introuvable/i.test(String(e?.message||e||""))}
function siteSafeSociete(site){
  const u=typeof currentUserRecord==="function"?currentUserRecord():null;
  const explicit=uniqueSocieteNames([
    ...(Array.isArray(u?.societesAutorisees)?u.societesAutorisees:[]),
    ...(Array.isArray(session?.societesAutorisees)?session.societesAutorisees:[])
  ]).filter(s=>!isRemovedSociete(s));
  const configured=(typeof societeConfig==="function"?(societeConfig().custom||[]):[]);
  const allowed=uniqueSocieteNames([...(explicit.length?explicit:(typeof currentAllowedSocietes==="function"?currentAllowedSocietes():SOCIETES.slice())),...configured]).filter(s=>!isRemovedSociete(s));
  const candidates=[
    typeof currentStructureSocieteFilter==="function"?currentStructureSocieteFilter():"",
    typeof mySoc==="function"?mySoc():"",
    session?.societe||"",
    sessionStorage.getItem("mtSociete")||"",sessionStorage.getItem("opsSociete")||"",sessionStorage.getItem("dashSociete")||"",
    allowed.length===1?allowed[0]:"",
    site?.societe,site?.society,site?.equipment_plan?.societe,site?.equipment_plan?.society,
    allowed[0]||""
  ].filter(Boolean);
  const found=candidates.find(s=>allowed.some(a=>normalizeSocieteName(a)===normalizeSocieteName(s)));
  return found?canonicalSocieteName(found,allowed):"";
}
function siteApiPayload(site){
  const effectifs=site.effectifs||{};
  const plan=site&&site.equipment_plan&&typeof site.equipment_plan==="object"?site.equipment_plan:{};
  const legacy=plan._legacy&&typeof plan._legacy==="object"?plan._legacy:{};
  const {equipment_plan,_legacy,isNew,...siteData}=site||{};
  const safeSociete=siteSafeSociete(site);
  if(safeSociete){site.societe=safeSociete;site.society=safeSociete}
  const data={...siteData,societe:safeSociete||siteData.societe||"",society:safeSociete||siteData.society||"",dateOuverture:site?.dateOuverture||legacy.dateOuverture||"",siteOuvertPar:site?.siteOuvertPar||legacy.siteOuvertPar||""};
  return {name:String(site.nom||site.name||"Site").trim()||"Site",indicatif:site.indicatif||null,client_name:site.client||site.client_name||null,address:site.adresse||site.address||null,commune:site.commune||null,wilaya:site.wilaya||null,site_type:site.type||site.site_type||null,rotation_system:site.rotationSystem||site.rotation_system||null,contractual_staff:parseInt(effectifs.totalContractuel??site.contractual_staff)||0,day_staff:parseInt(effectifs.jour??site.day_staff)||0,night_staff:parseInt(effectifs.nuit??site.night_staff)||0,weekend_staff:parseInt(effectifs.weekend??site.weekend_staff)||0,holiday_staff:parseInt(effectifs.feries??site.holiday_staff)||0,groups_count:parseInt(effectifs.groupes??site.groups_count)||0,active:site.actif===false||site.active===0?0:1,equipment_plan:{...plan,...data,_legacy:{...legacy,...data}}};
}
function siteFromApi(row){
  const plan=row&&row.equipment_plan&&typeof row.equipment_plan==="object"?row.equipment_plan:{};
  const legacy=plan._legacy&&typeof plan._legacy==="object"?plan._legacy:{};
  const data={...legacy,...plan};
  delete data._legacy;
  return {...data,isNew:false,id:data.id||String(row.id),backendId:row.id,nom:data.nom||row.name||"",indicatif:data.indicatif||row.indicatif||"",client:data.client||row.client_name||"",adresse:data.adresse||row.address||"",commune:data.commune||row.commune||"",wilaya:data.wilaya||row.wilaya||"",type:data.type||row.site_type||"",rotationSystem:data.rotationSystem||row.rotation_system||"",dateOuverture:data.dateOuverture||data.date_ouverture||"",siteOuvertPar:data.siteOuvertPar||data.site_ouvert_par||"",actif:row.active!==0,effectifs:{...(data.effectifs||{}),totalContractuel:data.effectifs?.totalContractuel??row.contractual_staff??0,jour:data.effectifs?.jour??row.day_staff??0,nuit:data.effectifs?.nuit??row.night_staff??0,weekend:data.effectifs?.weekend??row.weekend_staff??0,feries:data.effectifs?.feries??row.holiday_staff??0,groupes:data.effectifs?.groupes??row.groups_count??0}}}
async function persistSiteToPostgres(site){if(!site)return null;sgdiRequireServerWrite();const saved=site.backendId?await SGDI.sites.update(site.backendId,siteApiPayload(site)):await SGDI.sites.create(siteApiPayload(site));Object.assign(site,siteFromApi(saved),{id:site.id||String(saved.id),backendId:saved.id,isNew:false});return site}
async function syncSitesFromPostgres(){if(!sgdiAuthToken()||!db)return;try{let rows=await SGDI.sites.list();if((!rows||!rows.length)&&(db.sites||[]).length){for(const s of db.sites){await persistSiteToPostgres(s)}rows=await SGDI.sites.list()}db.sites=(rows||[]).map(siteFromApi)}catch(e){console.warn("Sites PostgreSQL indisponibles",e);throw e}}
function assignmentFromApi(row){
  const employee=(db.agents||[]).find(a=>String(a.backendId||"")===String(row.employee_id||"")||String(a.id||"")===String(row.employee_id||""));
  const site=(db.sites||[]).find(s=>String(s.backendId||"")===String(row.site_id||"")||String(s.id||"")===String(row.site_id||""));
  return {
    id:String(row.id),
    backendId:row.id,
    employee_id:row.employee_id,
    site_id:row.site_id,
    agentId:employee?.id||String(row.employee_id||""),
    agentBackendId:row.employee_id,
    siteId:site?.id||String(row.site_id||""),
    siteBackendId:row.site_id,
    siteName:site?.nom||site?.intitule||"",
    clientName:site?.client||"",
    societe:employee?.societe||site?.societe||"",
    groupe:row.group_code||"A",
    poste:row.position||employee?.fonction||employee?.position||"",
    date:sqlDate(row.start_date)||"",
    dateDebut:sqlDate(row.start_date)||"",
    dateFin:sqlDate(row.end_date)||"",
    motifChangement:row.change_reason||"",
    active:row.active!==0
  };
}
function applyAssignmentsToEmployees(assignments){
  const active=(assignments||db.assignments||[]).filter(x=>x&&x.active!==false&&x.active!==0);
  active.forEach(aff=>{
    const a=findEmployeeByRef(aff.agentBackendId)||findEmployeeByRef(aff.agentId);
    if(!a)return;
    const site=(db.sites||[]).find(s=>String(s.id)===String(aff.siteId)||String(s.backendId||"")===String(aff.siteBackendId||aff.site_id||""));
    const current=a.affectationCourante||{};
    const sqlDateValue=String(aff.dateDebut||aff.date||"").slice(0,10);
    if((current.siteId||current.siteName)&&String(current.siteId||"")!==String(aff.siteId||"")){
      a.affectationsHistorique=Array.isArray(a.affectationsHistorique)?a.affectationsHistorique:[];
      const already=a.affectationsHistorique.some(h=>String(h.siteId||"")===String(current.siteId||"")&&String(h.dateFin||"")===sqlDateValue);
      if(!already)a.affectationsHistorique.push({...current,dateFin:sqlDateValue,motifChangement:aff.motifChangement||"Nouvelle affectation SQL"});
    }
    a.affectationCourante={
      ...current,
      siteId:aff.siteId||site?.id||"",
      siteBackendId:aff.siteBackendId||site?.backendId||aff.site_id||null,
      siteName:aff.siteName||site?.nom||site?.intitule||current.siteName||"",
      clientName:aff.clientName||site?.client||current.clientName||"",
      poste:aff.poste||current.poste||a.fonction||a.position||"",
      horaire:current.horaire||"Mixte",
      groupe:aff.groupe||current.groupe||"",
      dateDebut:sqlDateValue||current.dateDebut||"",
      natureMouvement:aff.motifChangement||current.natureMouvement||"Affectation",
      assignmentBackendId:aff.backendId||aff.id||current.assignmentBackendId||""
    };
  });
}
async function syncAssignmentsFromPostgres(){
  if(!sgdiAuthToken()||!db||!window.SGDI?.assignments?.page)return;
  const result=await SGDI.assignments.page({active:1,page_size:5000});
  const rows=Array.isArray(result?.items)?result.items:Array.isArray(result)?result:[];
  db.assignments=rows.map(assignmentFromApi);
  applyAssignmentsToEmployees(db.assignments);
  await backfillLegacyAssignmentsToPostgres();
}
async function persistAssignmentFromMovement(date,employee,site,patch){
  if(!patch||patch.siteId==="autres")return null;
  sgdiRequireServerWrite();
  const employeeId=sqlBackendId(patch.employee_id||patch.agentBackendId||employee?.backendId);
  const siteId=sqlBackendId(patch.siteBackendId||site?.backendId||patch.site_id);
  if(!employeeId)throw new Error("Employé PostgreSQL introuvable pour l'affectation");
  if(!siteId)throw new Error("Site PostgreSQL introuvable pour l'affectation");
  const payload={
    employee_id:employeeId,
    site_id:siteId,
    group_code:String(patch.groupe||"A").trim()||"A",
    position:patch.poste||employee?.affectationCourante?.poste||employee?.fonction||employee?.position||null,
    start_date:sqlDate(date)||today(),
    end_date:null,
    change_reason:patch.mouvementMotif||patch.mouvementType||"Affectation",
    active:1
  };
  const saved=await SGDI.assignments.create(payload);
  const item=assignmentFromApi(saved);
  (db.assignments||[]).forEach(x=>{if(String(x.agentBackendId||x.employee_id||"")===String(employeeId)&&String(x.backendId||x.id||"")!==String(item.backendId||item.id||""))x.active=false});
  sgdiUpsertServerItem("assignments",item);
  applyAssignmentsToEmployees([item]);
  return item;
}
async function backfillLegacyAssignmentsToPostgres(){
  if(!sgdiAuthToken()||!db||!window.SGDI?.assignments?.create)return;
  const activeSql=new Set((db.assignments||[]).filter(x=>x.active!==false&&x.active!==0).map(x=>String(x.agentBackendId||x.employee_id||"")).filter(Boolean));
  const created=[];
  for(const a of (db.agents||[])){
    const employeeId=sqlBackendId(a.backendId);
    if(!employeeId||activeSql.has(String(employeeId))||String(a.statut||"").toLowerCase()!=="actif")continue;
    const aff=typeof opsEmployeeLiveAffectation==="function"?opsEmployeeLiveAffectation(a):(a.affectationCourante||{});
    if(!aff?.siteId)continue;
    const site=(db.sites||[]).find(s=>String(s.id)===String(aff.siteId)||String(s.backendId||"")===String(aff.siteBackendId||aff.site_id||""));
    const siteId=sqlBackendId(aff.siteBackendId||site?.backendId);
    if(!siteId)continue;
    try{
      const saved=await SGDI.assignments.create({
        employee_id:employeeId,
        site_id:siteId,
        group_code:String(aff.groupe||"A").trim()||"A",
        position:aff.poste||a.fonction||a.position||null,
        start_date:sqlDate(aff.dateDebut||aff.date)||today(),
        end_date:null,
        change_reason:aff.natureMouvement||aff.motifChangement||"Affectation importée",
        active:1
      });
      const item=assignmentFromApi(saved);
      sgdiUpsertServerItem("assignments",item);
      activeSql.add(String(employeeId));
      created.push(item);
    }catch(e){
      console.warn("Affectation legacy non migrée",a.matricule||a.id,e);
    }
  }
  if(created.length){
    applyAssignmentsToEmployees(created);
    console.info(`${created.length} affectation(s) migrée(s) vers PostgreSQL`);
  }
}
