function sgdiAutoRepairDB(options){
  const opt=options||{};
  const report=[];
  if(!db||typeof db!=="object"||Array.isArray(db)){db=emptyDB();report.push("Base SGDI reconstruite")}
  const base=emptyDB();
  Object.keys(base).forEach(k=>{
    if(Array.isArray(base[k])){
      if(!Array.isArray(db[k])){db[k]=[];report.push("Collection recréée: "+k)}
    }else if(!db[k]||typeof db[k]!=="object"||Array.isArray(db[k])){
      db[k]=JSON.parse(JSON.stringify(base[k]));report.push("Objet recréé: "+k);
    }
  });
  const fixListIds=(key,prefix)=>{
    const used=new Set();
    (db[key]||[]).forEach((item,idx)=>{
      if(!item||typeof item!=="object")return;
      let id=String(item.id||"").trim();
      if(!id||id==="None"||id==="undefined"||id==="null"||used.has(id)){
        id=`${prefix}_${Date.now()}_${idx}`;
        item.id=id;
        report.push("ID corrigé: "+key);
      }
      used.add(id);
    });
  };
  [["users","usr"],["agents","ag"],["candidats","cand"],["sites","site"],["clients","cl"],["stockArticles","art"],["stockMouvements","mvt"],["magasins","mag"],["fournisseurs","four"],["demandesPersonnel","dp"],["demandesStructure","ds"],["echanges","msg"],["workflowTasks","wft"]].forEach(([k,p])=>fixListIds(k,p));
  db.societesConfig={custom:uniqueSocieteNames([...DEFAULT_SOCIETES,...(db.societesConfig?.custom||[]),...deriveSocietesFromData(db)]).filter(s=>!isRemovedSociete(s)),descriptions:{...(db.societesConfig?.descriptions||{})},images:{...(db.societesConfig?.images||{})},removed:REMOVED_SOCIETES.slice(),access:{...defaultSocieteAccessPasswords(),...(db.societesConfig?.access||{})}};
  if(!db.settings||typeof db.settings!=="object")db.settings={unlockCode:"",unlockLog:[],autoRefresh:{enabled:true,intervalSeconds:20}};
  if(typeof db.settings.unlockCode!=="string")db.settings.unlockCode="";
  if(!Array.isArray(db.settings.unlockLog))db.settings.unlockLog=[];
  if(!db.settings.autoRefresh||typeof db.settings.autoRefresh!=="object")db.settings.autoRefresh={enabled:true,intervalSeconds:20};
  if(typeof ensureNiveauxAcces==="function")ensureNiveauxAcces();
  if(typeof sanitizeCandidatesInDB==="function")sanitizeCandidatesInDB();
  if(typeof migrateStructureDemandes==="function")migrateStructureDemandes();
  if(typeof normalizeEmployeeCodesInDB==="function"){
    const codeFixes=normalizeEmployeeCodesInDB();
    if(codeFixes)report.push("Codes employés normalisés");
  }
  if(report.length){
    db.activityLog=db.activityLog||[];
    db.activityLog.unshift({id:"repair_"+Date.now(),date:new Date().toISOString(),user:session?.username||"system",action:"Auto-correction SGDI",details:report.slice(0,12).join(" · ")});
    if(db.activityLog.length>500)db.activityLog=db.activityLog.slice(0,500);
    if(!opt.silent)console.info("Auto-correction SGDI",report);
  }
  return report;
}
function hydrateDB(source){
  const base=emptyDB();
  const incoming=(source&&typeof source==="object"&&!Array.isArray(source))?source:{};
  db={...base,...incoming};
  Object.keys(base).forEach(k=>{
    if(Array.isArray(base[k])&&!Array.isArray(db[k]))db[k]=[];
  });
  if(!db.settings||typeof db.settings!=="object")db.settings=base.settings;
  if(!db.societesConfig||typeof db.societesConfig!=="object")db.societesConfig=base.societesConfig;
  const repaired=sgdiAutoRepairDB({silent:true});
  if(repaired.length&&sgdiAuthToken())setTimeout(()=>{if(sgdiPostgresReady)sgdiBackendSave()},200);
  return db;
}
function loadDB(){return emptyDB()}
function dbSizeKB(){try{return Math.round((JSON.stringify(db||{}).length/1024))}catch(e){return 0}}
function dbStorageStats(){
  const stats={total:0,parts:[]};
  if(!db)return stats;
  Object.keys(db).forEach(k=>{try{const s=JSON.stringify(db[k]).length;stats.parts.push({k,bytes:s});stats.total+=s}catch(e){}});
  stats.parts.sort((a,b)=>b.bytes-a.bytes);
  return stats;
}
function trimActivityLog(max){
  if(!db||!Array.isArray(db.activityLog))return 0;
  if(typeof max!=="number")max=300;
  const before=db.activityLog.length;
  if(before<=max)return 0;
  db.activityLog=db.activityLog.slice(-max);
  return before-db.activityLog.length;
}
function feedChangedSections(){
  return [];
}
function recordSaveOperation(){
  if(feedRecording||!session||!db)return;
  const changed=feedChangedSections();
  if(!changed.length)return;
  const msg="Modification enregistrée : "+changed.slice(0,5).join(", ")+(changed.length>5?"...":"");
  recordOperationFeed(msg,"Opération enregistrée");
}
function saveDB(){
  try{
    sgdiDirty=true;
    if(typeof migrateStructureDemandes==="function")migrateStructureDemandes();
    sanitizeCandidatesInDB();
    normalizeEmployeeCodesInDB();
    uiSaveState("Enregistrement...","");
    recordSaveOperation();
    try{sgdiRequireServerWrite()}catch(e){sgdiServerOnlyFailure(e.message||String(e));uiSaveState("Sauvegarde refusée","error");if(window._sgdiSaveOverlayShown)closeSaveOverlay();return false}
    if(!sgdiBackendSave()){uiSaveState("Sauvegarde échouée","error");if(window._sgdiSaveOverlayShown)closeSaveOverlay();return false}
    uiSaveState("Enregistrement en cours...","");
    setTimeout(()=>refreshRealtimeFeed(),0);
    return true;
  }catch(err){
    console.error("saveDB error:",err);
    if(typeof toast==="function")toast("Erreur d'enregistrement: "+(err.message||err),"error");
    uiSaveState("Erreur sauvegarde","error");
    return false;
  }
}
function purgeRemovedSocieteData(d){
  if(!d)return false;
  let changed=false;
  const filterSoc=(key)=>{
    if(!Array.isArray(d[key]))return;
    const before=d[key].length;
    d[key]=d[key].filter(x=>!isRemovedSociete(x&&x.societe));
    if(d[key].length!==before)changed=true;
  };
  const stockIds=new Set((d.stockArticles||[]).filter(x=>isRemovedSociete(x&&x.societe)).map(x=>x.id));
  ["agents","candidats","sites","materiel","stockArticles","magasins","fournisseurs","clients","prospects","opportunites","visites","catalogue","devis","factures","paiements","avances","avoirs","caisse","incidents","pointages","feuillePresence","opsMouvements","demandesPersonnel","demandesStructure","missions","siteInspections"].forEach(filterSoc);
  if(Array.isArray(d.stockMouvements)){
    const before=d.stockMouvements.length;
    d.stockMouvements=d.stockMouvements.filter(x=>!isRemovedSociete(x&&x.societe)&&!stockIds.has(x&&x.articleId));
    if(d.stockMouvements.length!==before)changed=true;
  }
  if(Array.isArray(d.users)){
    d.users.forEach(u=>{
      if(Array.isArray(u.societesAutorisees)){
        const before=u.societesAutorisees.length;
        u.societesAutorisees=u.societesAutorisees.filter(s=>!isRemovedSociete(s));
        if(u.societesAutorisees.length!==before)changed=true;
      }
    });
  }
  if(d.societesConfig&&typeof d.societesConfig==="object"){
    const cfg=d.societesConfig;
    const beforeCustom=Array.isArray(cfg.custom)?cfg.custom.join("|"):"";
    cfg.custom=uniqueSocieteNames([...DEFAULT_SOCIETES,...(Array.isArray(cfg.custom)?cfg.custom:[]),...deriveSocietesFromData(d)]).filter(s=>!isRemovedSociete(s));
    if(cfg.custom.join("|")!==beforeCustom)changed=true;
    ["images","descriptions"].forEach(key=>{
      if(!cfg[key]||typeof cfg[key]!=="object")return;
      Object.keys(cfg[key]).forEach(name=>{
        if(isRemovedSociete(name)){delete cfg[key][name];changed=true}
      });
    });
    cfg.removed=REMOVED_SOCIETES.slice();
  }
  return changed;
}
function loadSession(){const raw=sessionStorage.getItem(SESSION_KEY);if(raw){try{return JSON.parse(raw)}catch(e){}}return null}
function saveSession(s){if(s)sessionStorage.setItem(SESSION_KEY,JSON.stringify(s));else sessionStorage.removeItem(SESSION_KEY)}
function loadUnlocked(){const raw=sessionStorage.getItem(UNLOCK_SESSION_KEY);if(raw){try{return new Set(JSON.parse(raw))}catch(e){}}return new Set()}
function saveUnlocked(){sessionStorage.setItem(UNLOCK_SESSION_KEY,JSON.stringify([...unlockedAgents]))}
function normalizePosteValue(v){
  if(!v)return v;
  const s=String(v).trim();
  return POSTE_ALIASES[s]||s;
}
function normalizePostesInDB(persist=true){
  if(!db)return;
  let changed=false;
  const setNorm=(obj,key)=>{if(obj&&obj[key]){const n=normalizePosteValue(obj[key]);if(n!==obj[key]){obj[key]=n;changed=true}}};
  (db.agents||[]).forEach(a=>{
    ["posteSouhaite","posteContrat","fonction"].forEach(k=>setNorm(a,k));
    if(a.affectationCourante)setNorm(a.affectationCourante,"poste");
    (a.affectationsHistorique||[]).forEach(h=>setNorm(h,"poste"));
  });
  (db.candidats||[]).forEach(c=>["posteSouhaite","posteContrat","fonction","poste"].forEach(k=>setNorm(c,k)));
  (db.feuillePresence||[]).forEach(f=>setNorm(f,"poste"));
  (db.sites||[]).forEach(s=>{
    const old=s.postes||{};
    const next={};
    POSTES.forEach(p=>next[p]={total:0,jour:0,nuit:0});
    Object.entries(old).forEach(([k,v])=>{
      const nk=normalizePosteValue(k);
      if(!next[nk])next[nk]={total:0,jour:0,nuit:0};
      if(nk!==k)changed=true;
      next[nk].total+=(+v.total||0);
      next[nk].jour+=(+v.jour||0);
      next[nk].nuit+=(+v.nuit||0);
    });
    s.postes=next;
  });
  if(changed&&persist)saveDB();
}

function uid(p="x"){return p+"_"+Math.random().toString(36).slice(2,10)}
function today(){return new Date().toISOString().slice(0,10)}
function addDays(d,n){const x=new Date(d);x.setDate(x.getDate()+n);return x.toISOString().slice(0,10)}
function addYears(d,n){const x=new Date(d);x.setFullYear(x.getFullYear()+n);return x.toISOString().slice(0,10)}
function candidatBirthMaxDate(){return addYears(today(),-20)}
function candidatAgeAtSave(dateNaissance){
  if(!dateNaissance)return null;
  const birth=new Date(dateNaissance), ref=new Date(today());
  if(isNaN(birth.getTime()))return null;
  let age=ref.getFullYear()-birth.getFullYear();
  const beforeBirthday=ref.getMonth()<birth.getMonth()||(ref.getMonth()===birth.getMonth()&&ref.getDate()<birth.getDate());
  if(beforeBirthday)age--;
  return age;
}
function ageFromDate(dateValue){
  if(!dateValue)return null;
  const birth=new Date(dateValue), ref=new Date(today());
  if(Number.isNaN(birth.getTime()))return null;
  let age=ref.getFullYear()-birth.getFullYear();
  if(ref.getMonth()<birth.getMonth()||(ref.getMonth()===birth.getMonth()&&ref.getDate()<birth.getDate()))age--;
  return age;
}
function elapsedYMD(fromDate,toDate){
  if(!fromDate)return null;
  const start=new Date(fromDate), end=toDate?new Date(toDate):new Date(today());
  if(Number.isNaN(start.getTime())||Number.isNaN(end.getTime())||end<start)return null;
  let years=end.getFullYear()-start.getFullYear();
  let months=end.getMonth()-start.getMonth();
  let days=end.getDate()-start.getDate();
  if(days<0){months--;days+=new Date(end.getFullYear(),end.getMonth(),0).getDate()}
  if(months<0){years--;months+=12}
  return{years,months,days};
}
function formatElapsedYMD(fromDate){
  const d=elapsedYMD(fromDate);
  if(!d)return"—";
  const parts=[];
  if(d.years)parts.push(`${d.years} an${d.years>1?"s":""}`);
  if(d.months)parts.push(`${d.months} mois`);
  if(d.days)parts.push(`${d.days} jour${d.days>1?"s":""}`);
  if(!parts.length)return"aujourd'hui";
  if(parts.length===1)return parts[0];
  return `${parts.slice(0,-1).join(", ")} et ${parts[parts.length-1]}`;
}
function validateCandidatBirthField(el){
  if(!el)return true;
  const age=candidatAgeAtSave(el.value);
  const msg=document.getElementById("date-naissance-alert");
  const invalid=age!==null&&age<20;
  el.classList.toggle("input-error",invalid);
  el.setCustomValidity(invalid?"Le candidat doit avoir au moins 20 ans.":"");
  if(msg){
    msg.className=invalid?"text-[11px] text-red-700 font-semibold mt-1":"text-[11px] text-slate-500 mt-1";
    msg.textContent=invalid?`Âge non conforme : ${age} ans. Minimum requis : 20 ans révolus.`:"Âge minimum requis : 20 ans révolus à la date d'enregistrement.";
  }
  return !invalid;
}
function clearRequiredFieldError(el){
  if(!el)return;
  const empty=!String(el.value||"").trim();
  if(!empty&&el.checkValidity()){
    el.classList.remove("input-error");
    el.removeAttribute("aria-invalid");
  }
}
function markRequiredFields(form){
  form=form||document.getElementById("candidat-form");
  if(!form)return true;
  let ok=true;
  form.querySelectorAll("input[required],select[required],textarea[required]").forEach(el=>{
    if(el.disabled)return;
    const empty=!String(el.value||"").trim();
    const invalid=empty||!el.checkValidity();
    el.classList.toggle("input-error",invalid);
    if(invalid)ok=false;
  });
  return ok;
}
function candidatAllRequiredFieldMap(){
  const out=new Map();
  CANDIDAT_SECTIONS.forEach(s=>candidatRequiredFieldsForSection(s.key).forEach(([field,label])=>out.set(field,label)));
  return out;
}
function candidatFieldIssue(field,value,data,requiredFields){
  const v=String(value??"").trim();
  if(requiredFields?.has(field)&&!v)return "Champ obligatoire non renseigné";

  if(field==="numeroCnas"&&v&&!/^\d{10} \d{2}$/.test(v))return "N° CNAS non conforme : 10 chiffres, espace, 2 chiffres";
  if((field==="telephone"||field==="contactUrgenceTel")&&v&&String(v).replace(/\D/g,"").length!==10)return "Téléphone non conforme : format 0000 00 00 00";
  if(field==="dateNaissance"){
    const age=candidatAgeAtSave(v);
    if(age!==null&&age<20)return "Âge non conforme : minimum 20 ans";
  }
  return "";
}
function markCandidatFormIssues(data){
  const form=document.getElementById("candidat-form");
  if(!form)return;
  const requiredFields=candidatAllRequiredFieldMap();
  form.querySelectorAll("input,select,textarea").forEach(el=>{
    const field=el.name||"";
    if(!field||field.startsWith("hab_")||field.startsWith("lang_")||field.startsWith("doc_")||field.startsWith("exp_")||field.startsWith("verif")||field.startsWith("cv_"))return;
    const issue=candidatFieldIssue(field,data?.[field]??el.value,data,requiredFields);
    el.classList.toggle("input-error",!!issue);
    if(issue){
      el.setAttribute("aria-invalid","true");
      el.setAttribute("title",issue);
      el.dataset.issueMessage=issue;
      if(el.disabled&&el.closest("[data-candidat-section][data-locked='1']")){
        el.disabled=false;
        el.dataset.unlockedForCorrection="1";
        el.classList.add("candidate-correction-field");
      }
    }else if(el.dataset.issueMessage){
      el.removeAttribute("aria-invalid");
      el.removeAttribute("title");
      delete el.dataset.issueMessage;
      if(el.dataset.unlockedForCorrection==="1"&&el.closest("[data-candidat-section][data-locked='1']")){
        el.disabled=true;
        delete el.dataset.unlockedForCorrection;
        el.classList.remove("candidate-correction-field");
      }
    }
  });
}
function bindRequiredFieldCleanup(form){
  form=form||document.getElementById("candidat-form");
  if(!form)return;
  form.querySelectorAll("input,select,textarea").forEach(el=>{
    if(el.dataset.requiredCleanupBound==="1")return;
    const fn=()=>{if(el.name==="dateNaissance")validateCandidatBirthField(el);clearRequiredFieldError(el);markCandidatFormIssues(collectCandidatFormData()||{})};
    el.addEventListener("input",fn);
    el.addEventListener("change",fn);
    el.dataset.requiredCleanupBound="1";
  });
}
function money(n){if(n===null||n===undefined||n==="")return"—";const v=Number(n);if(isNaN(v))return"—";return v.toLocaleString("fr-FR",{minimumFractionDigits:2,maximumFractionDigits:2})+" DA"}
function parseMoneyInput(v){if(v===null||v===undefined||v==="")return"";const n=Number(String(v).replace(/\s/g,"").replace(",",".").replace(/[^\d.-]/g,""));return isNaN(n)?"":n}
function formatMoneyInputValue(v){const n=parseMoneyInput(v);return n===""?"":n.toLocaleString("fr-FR",{minimumFractionDigits:2,maximumFractionDigits:2})}
function formatMoneyInputValueDA(v){const s=formatMoneyInputValue(v);return s?`${s} DA`:""}
function formatMoneyField(el){if(el)el.value=formatMoneyInputValue(el.value)}
function numberToFrenchWords(n){
  n=Math.floor(Math.abs(Number(n)||0));
  const small=["zéro","un","deux","trois","quatre","cinq","six","sept","huit","neuf","dix","onze","douze","treize","quatorze","quinze","seize"];
  const tens=["","","vingt","trente","quarante","cinquante","soixante"];
  function underHundred(x){
    if(x<17)return small[x];
    if(x<20)return "dix-"+small[x-10];
    if(x<70){const d=Math.floor(x/10),r=x%10;return tens[d]+(r===1?" et un":r?("-"+small[r]):"")}
    if(x<80)return "soixante-"+underHundred(x-60);
    if(x===80)return "quatre-vingts";
    return "quatre-vingt-"+underHundred(x-80);
  }
  function underThousand(x){
    if(x<100)return underHundred(x);
    const h=Math.floor(x/100),r=x%100;
    const head=h===1?"cent":small[h]+" cent";
    if(!r)return h>1?head+"s":head;
    return head+" "+underHundred(r);
  }
  if(n<1000)return underThousand(n);
  if(n<1000000){
    const th=Math.floor(n/1000),r=n%1000;
    const head=(th===1?"mille":underThousand(th)+" mille");
    return r?head+" "+underThousand(r):head;
  }
  const m=Math.floor(n/1000000),r=n%1000000;
  const head=(m===1?"un million":underThousand(m)+" millions");
  return r?head+" "+numberToFrenchWords(r):head;
}
function moneyToFrenchWords(v){
  const amount=parseMoneyInput(v);
  if(amount===""||amount<=0)return "";
  const dinars=Math.floor(amount);
  const centimes=Math.round((amount-dinars)*100);
  let text=numberToFrenchWords(dinars)+" dinar"+(dinars>1?"s":"")+" algérien"+(dinars>1?"s":"");
  if(centimes>0)text+=" et "+numberToFrenchWords(centimes)+" centime"+(centimes>1?"s":"");
  return text+" net par mois";
}
function qty(n){if(n===null||n===undefined||n==="")return"—";const v=Number(n);if(isNaN(v))return"—";const isInt=v===Math.floor(v);return v.toLocaleString("fr-FR",{minimumFractionDigits:isInt?0:2,maximumFractionDigits:isInt?0:2})}
function formatDate(d){if(!d)return"—";try{return new Date(d).toLocaleDateString("fr-FR")}catch(e){return d}}
function formatTime(d){if(!d)return"—";try{return new Date(d).toLocaleTimeString("fr-FR",{hour:"2-digit",minute:"2-digit"})}catch(e){return"—"}}
function stockMovementDateTimeLabel(m){
  const source=m?.createdAt||m?.created_at||m?.date||"";
  const hasTime=/[T\s]\d{2}:\d{2}/.test(String(source));
  return `${hasTime?formatTime(source):"—"} ${formatDate(m?.date||source)}`;
}
function stockStoreHistoryPeriodFilter(){
  const period=sessionStorage.getItem("matStoreHistoryPeriod")||"30";
  const now=new Date();
  if(period==="today")return{key:period,label:"Aujourd'hui",from:today()};
  if(period==="month")return{key:period,label:"Mois en cours",from:new Date(now.getFullYear(),now.getMonth(),1).toISOString().slice(0,10)};
  if(period==="year")return{key:period,label:"Année en cours",from:new Date(now.getFullYear(),0,1).toISOString().slice(0,10)};
  if(period==="all")return{key:period,label:"Tout l'historique",from:"0000-00-00"};
  const days=parseInt(period,10)||30;
  return{key:period,label:`${days} derniers jours`,from:new Date(Date.now()-days*86400000).toISOString().slice(0,10)};
}
function stockStoreMovementSizeLabels(m){
  const rep=m?.repartitionTailles||{};
  const keys=Object.keys(rep).filter(k=>(parseFloat(rep[k])||0)>0);
  if(keys.length)return keys;
  return [m?.tailleType&&m?.tailleValue?`${m.tailleType} ${m.tailleValue}`:"",m?.taille?`Taille ${m.taille}`:"",m?.pointure?`Pointure ${m.pointure}`:""].filter(Boolean);
}
function stockStoreMovementEmployeeLabel(m){
  const a=findEmployeeByRef(m?.beneficiaireAgentId||m?.agentId||m?.employeeId||m?.employee_id||m?.retourAgentId);
  if(a)return [a.matricule,`${a.nom||""} ${a.prenom||""}`.trim()].filter(Boolean).join(" · ");
  if((m?.cibleType||m?.targetType)==="employee"&&m?.cibleNom)return m.cibleNom;
  return m?.beneficiaireNom||m?.retourAgentNom||"Non lié";
}
function stockStoreMovementSiteLabel(m){
  const site=(db.sites||[]).find(s=>String(s.id)===String(m?.siteId||m?.site_id||m?.cibleId||"")||String(s.backendId||"")===String(m?.siteId||m?.site_id||m?.cibleId||""));
  if(site)return site.nom||site.intitule||"Site";
  if((m?.cibleType||m?.targetType)==="site"&&m?.cibleNom)return m.cibleNom;
  const a=findEmployeeByRef(m?.beneficiaireAgentId||m?.agentId||m?.employeeId||m?.employee_id||m?.retourAgentId);
  return a?.affectationCourante?.siteName||m?.siteName||"Non lié";
}
function stockStoreHistoryCounters(mvts){
  const blank=()=>({count:0,inQty:0,outQty:0});
  const add=(map,label,m,qtyOverride)=>{
    const key=String(label||"Non renseigné").trim()||"Non renseigné";
    const row=map.get(key)||blank();
    const q=qtyOverride!==undefined?qtyOverride:(parseFloat(m.quantite)||0);
    row.count++;
    if(stockMvtIsIn(m.type))row.inQty+=q;else row.outQty+=q;
    map.set(key,row);
  };
  const maps={size:new Map(),date:new Map(),site:new Map(),employee:new Map(),period:new Map()};
  mvts.forEach(m=>{
    const q=parseFloat(m.quantite)||0;
    const sizes=stockStoreMovementSizeLabels(m);
    if(sizes.length)sizes.forEach(k=>add(maps.size,k,m,parseFloat(m.repartitionTailles?.[k])||q));
    else add(maps.size,"Sans taille / pointure",m,q);
    add(maps.date,formatDate(m.date),m,q);
    add(maps.site,stockStoreMovementSiteLabel(m),m,q);
    add(maps.employee,stockStoreMovementEmployeeLabel(m),m,q);
    add(maps.period,String(m.date||"").slice(0,7)||"Sans période",m,q);
  });
  return maps;
}
function stockStoreCounterListHTML(title,map,limit){
  const rows=[...map.entries()].map(([label,v])=>({label,...v,total:v.inQty+v.outQty,net:v.inQty-v.outQty})).sort((a,b)=>b.total-a.total||b.count-a.count||a.label.localeCompare(b.label)).slice(0,limit||6);
  return `<div class="border border-slate-200 rounded-lg p-3 bg-slate-50"><div class="text-xs font-black uppercase text-slate-500 mb-2">${escapeHTML(title)}</div>${rows.length?rows.map(r=>`<div class="flex justify-between gap-3 border-t border-slate-200 py-2 first:border-t-0"><div class="text-xs font-semibold text-slate-700">${escapeHTML(r.label)}</div><div class="text-right whitespace-nowrap"><div class="text-xs font-black">${r.count} mvt</div><div class="text-[10px] text-slate-500">+${qty(r.inQty)} / -${qty(r.outQty)}</div></div></div>`).join(""):`<div class="text-xs text-slate-400 py-2">Aucun mouvement.</div>`}</div>`;
}
function stockStoreHistoryCountersHTML(mvts){
  const filter=stockStoreHistoryPeriodFilter();
  const periodRows=[["today","Aujourd'hui"],["7","7 jours"],["30","30 jours"],["90","90 jours"],["month","Mois"],["year","Année"],["all","Tout"]];
  const rows=mvts.filter(m=>filter.key==="all"||String(m.date||"")>=filter.from);
  const inQty=rows.filter(m=>stockMvtIsIn(m.type)).reduce((s,m)=>s+(parseFloat(m.quantite)||0),0);
  const outQty=rows.filter(m=>!stockMvtIsIn(m.type)).reduce((s,m)=>s+(parseFloat(m.quantite)||0),0);
  const maps=stockStoreHistoryCounters(rows);
  return `<div class="card p-5 mb-4">
    <div class="flex items-center justify-between gap-3 mb-3 flex-wrap"><div><h3 class="font-bold">Historique des mouvements</h3><p class="text-xs text-slate-500">${escapeHTML(filter.label)} · compteurs par taille, date, site, employé et période</p></div><div class="flex gap-1 flex-wrap">${periodRows.map(([k,l])=>`<button type="button" onclick="sessionStorage.setItem('matStoreHistoryPeriod','${k}');renderView()" class="px-3 py-1 rounded-md text-xs font-bold" style="background:${filter.key===k?"#0f172a":"#fff"};color:${filter.key===k?"#fff":"#475569"};border:1px solid #cbd5e1">${escapeHTML(l)}</button>`).join("")}</div></div>
    <div class="grid grid-cols-2 md:grid-cols-4 gap-3 mb-3 text-center">
      <div class="p-3 rounded bg-slate-50 border"><div class="text-[10px] uppercase font-bold text-slate-500">Mouvements</div><div class="text-2xl font-black">${rows.length}</div></div>
      <div class="p-3 rounded bg-emerald-50 border border-emerald-100"><div class="text-[10px] uppercase font-bold text-emerald-700">Entrées</div><div class="text-2xl font-black text-emerald-700">${qty(inQty)}</div></div>
      <div class="p-3 rounded bg-red-50 border border-red-100"><div class="text-[10px] uppercase font-bold text-red-700">Sorties</div><div class="text-2xl font-black text-red-700">${qty(outQty)}</div></div>
      <div class="p-3 rounded bg-blue-50 border border-blue-100"><div class="text-[10px] uppercase font-bold text-blue-700">Solde période</div><div class="text-2xl font-black text-blue-800">${qty(inQty-outQty)}</div></div>
    </div>
    <div class="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-5 gap-3">
      ${stockStoreCounterListHTML("Par taille / pointure",maps.size)}
      ${stockStoreCounterListHTML("Par date",maps.date)}
      ${stockStoreCounterListHTML("Par site",maps.site)}
      ${stockStoreCounterListHTML("Par employé",maps.employee)}
      ${stockStoreCounterListHTML("Par période",maps.period)}
    </div>
  </div>`;
}
function daysBetween(a,b){return Math.ceil((new Date(b)-new Date(a))/(1000*60*60*24))}
function escapeHTML(s){return String(s??"").replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]))}
function jsString(s){return String(s??"").replace(/\\/g,"\\\\").replace(/'/g,"\\'").replace(/\n/g,"\\n").replace(/\r/g,"")}
function safe(s){return s===null||s===undefined||s===""?"—":escapeHTML(s)}
