function setLoginBusy(active,message){
  const form=document.getElementById("login-form");
  const submit=document.querySelector(".sgdi-login-submit[form='login-form']");
  const status=document.querySelector(".sgdi-login-status");
  if(form){
    form.setAttribute("aria-busy",active?"true":"false");
    form.querySelectorAll("input,button").forEach(el=>{el.disabled=!!active});
  }
  if(submit){
    if(!submit.dataset.idleLabel)submit.dataset.idleLabel=submit.textContent||"Se connecter";
    submit.disabled=!!active;
    submit.classList.toggle("is-loading",!!active);
    submit.textContent=active?(message||"Connexion..."):submit.dataset.idleLabel;
  }
  if(status){
    status.hidden=!active;
    status.textContent=active?(message||"Connexion..."):"";
  }
}
