let _sgdiPreferredVoice=null;
let _sgdiCurrentUtterance=null;
let _sgdiVoiceRetryTimer=null;
let _sgdiRemoteAudio=null;
const SGDI_VOICE_ENABLED_KEY="sgdi_atlas_voice_enabled";
function _sgdiVoiceEnabled(){
  return localStorage.getItem(SGDI_VOICE_ENABLED_KEY)!=="false";
}
function _sgdiSetVoiceEnabled(enabled){
  localStorage.setItem(SGDI_VOICE_ENABLED_KEY,enabled?"true":"false");
  if(!enabled){
    try{window.speechSynthesis?.cancel?.()}catch(e){}
    try{if(_sgdiRemoteAudio){_sgdiRemoteAudio.pause();_sgdiRemoteAudio.src=""}}catch(e){}
    _sgdiCurrentUtterance=null;
  }
  _sgdiUpdateVoiceToggle();
}
function _sgdiUpdateVoiceToggle(){
  const btn=document.getElementById("ai-voice-toggle");
  if(!btn)return;
  const enabled=_sgdiVoiceEnabled();
  btn.textContent=enabled?"Voix ON":"Voix OFF";
  btn.classList.toggle("is-off",!enabled);
  btn.setAttribute("aria-pressed",enabled?"true":"false");
  btn.title=enabled?"Désactiver la voix":"Activer la voix";
}
function _sgdiIsClearlyMaleVoice(voice){
  const text=(String(voice?.name||"")+" "+String(voice?.lang||"")).toLowerCase();
  return /thomas|daniel|paul|henri|alain|antoine|louis|luc|nicolas|bernard|jacques|jean|pierre|yves|male|homme|man\b/i.test(text);
}
function _sgdiIsPreferredFemaleVoice(voice){
  const text=(String(voice?.name||"")+" "+String(voice?.lang||"")).toLowerCase();
  return /audrey|marie|julie|aurelie|aurélie|virginie|celine|céline|lea|léa|hortense|chantal|denise|vivienne|eloquence|monica|samantha|ava|siri|flo|sandy|shelley|female|femme|woman|voix féminine/i.test(text);
}
function _sgdiIsSilentVoice(voice){
  const text=(String(voice?.name||"")+" "+String(voice?.lang||"")).toLowerCase();
  return /amelie|amélie/i.test(text);
}
function _sgdiVoiceScore(voice){
  const name=String(voice?.name||"");
  const lang=String(voice?.lang||"");
  const text=(name+" "+lang).toLowerCase();
  if(_sgdiIsClearlyMaleVoice(voice))return -999;
  if(_sgdiIsSilentVoice(voice))return -999;
  let score=0;
  if(/^fr/i.test(lang))score+=40;
  if(/fr[-_]fr/i.test(lang))score+=25;
  if(/siri.*(voice|voix).*(4|5)|flo.*fran[cç]ais|sandy.*fran[cç]ais|shelley.*fran[cç]ais/i.test(name))score+=160;
  if(/premium|enhanced|neural|natural|online|google|microsoft|apple/i.test(text))score+=45;
  if(/audrey|marie|julie|aurelie|aurélie|virginie|celine|céline|lea|léa|hortense|chantal|denise|vivienne|eloquence|monica|samantha|ava|siri|flo|sandy|shelley/i.test(name))score+=45;
  if(/female|femme|woman|voix féminine/i.test(text))score+=10;
  if(/thomas|daniel|paul|henri|alain|male|homme/i.test(text))score-=80;
  if(/compact|basic/i.test(text))score-=35;
  return score;
}
function _sgdiSelectVoice(){
  const voices=(window.speechSynthesis?.getVoices?.()||[]).filter(Boolean);
  if(!voices.length)return null;
  const scored=voices
    .filter(v=>!_sgdiIsClearlyMaleVoice(v)&&!_sgdiIsSilentVoice(v)&&_sgdiIsPreferredFemaleVoice(v)&&(/^fr/i.test(String(v.lang||""))||/fran[cç]ais|french|audrey|marie|julie|aurelie|aurélie|virginie|denise|vivienne|siri|flo|sandy|shelley/i.test(String(v.name||""))))
    .map(v=>({voice:v,score:_sgdiVoiceScore(v)}))
    .sort((a,b)=>b.score-a.score);
  return (scored[0]&&scored[0].score>0?scored[0].voice:null)||null;
}
function _sgdiVoiceDiagnostic(){
  if(!window.speechSynthesis)return "Synthèse vocale indisponible dans ce navigateur.";
  const voices=(window.speechSynthesis.getVoices?.()||[]).filter(Boolean);
  const voice=_sgdiPreferredVoice||_sgdiSelectVoice();
  return "Voix: "+(_sgdiVoiceEnabled()?"activée":"désactivée")+
    " · voix détectées: "+voices.length+
    " · mode: voix navigateur féminine uniquement"+
    (voice?" · voix sélectionnée: "+voice.name+" ["+voice.lang+"]":" · aucune voix féminine compatible")+
    " · état: speaking="+window.speechSynthesis.speaking+
    ", pending="+window.speechSynthesis.pending+
    ", paused="+window.speechSynthesis.paused;
}
if(window.speechSynthesis){
  window.speechSynthesis.onvoiceschanged=()=>{
    _sgdiPreferredVoice=_sgdiSelectVoice();
  };
}
function _sgdiSpeakNow(text,attempt=0){
  const synth=window.speechSynthesis;
  const voice=_sgdiSelectVoice();
  _sgdiPreferredVoice=voice||_sgdiPreferredVoice;
  if(!voice){
    try{synth.cancel()}catch(e){}
    if(typeof toast==="function")toast("Aucune voix féminine française disponible sur ce navigateur.","error");
    return false;
  }
  const msg=new SpeechSynthesisUtterance(text);
  msg.lang=voice.lang||"fr-FR";
  msg.voice=voice;
  msg.rate=0.92;
  msg.pitch=1.0;
  msg.volume=1;
  let started=false;
  _sgdiCurrentUtterance=msg;
  clearTimeout(_sgdiVoiceRetryTimer);
  msg.onstart=()=>{started=true;try{synth.resume()}catch(e){}};
  msg.onend=()=>{if(_sgdiCurrentUtterance===msg)_sgdiCurrentUtterance=null;};
  msg.onerror=()=>{
    if(_sgdiCurrentUtterance===msg)_sgdiCurrentUtterance=null;
    if(attempt<1)setTimeout(()=>_sgdiSpeakNow(text,attempt+1),80);
  };
  try{synth.cancel()}catch(e){}
  try{synth.resume()}catch(e){}
  synth.speak(msg);
  try{synth.resume()}catch(e){}
  setTimeout(()=>{try{synth.resume()}catch(e){}},80);
  setTimeout(()=>{try{synth.resume()}catch(e){}},300);
  _sgdiVoiceRetryTimer=setTimeout(()=>{
    if(!started&&_sgdiCurrentUtterance===msg&&attempt<1){
      try{synth.cancel()}catch(e){}
      _sgdiCurrentUtterance=null;
      _sgdiSpeakNow(text,attempt+1);
    }
  },1200);
  return true;
}
function _sgdiPlayTestBeep(){
  try{
    const AudioCtx=window.AudioContext||window.webkitAudioContext;
    if(!AudioCtx)throw new Error("AudioContext indisponible");
    const ctx=new AudioCtx();
    const osc=ctx.createOscillator();
    const gain=ctx.createGain();
    osc.type="sine";
    osc.frequency.value=660;
    gain.gain.setValueAtTime(0.0001,ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.18,ctx.currentTime+0.03);
    gain.gain.exponentialRampToValueAtTime(0.0001,ctx.currentTime+0.45);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start();
    osc.stop(ctx.currentTime+0.5);
    setTimeout(()=>ctx.close().catch(()=>null),700);
    return true;
  }catch(e){
    if(typeof toast==="function")toast("Son bloqué : "+(e.message||e),"error");
    return false;
  }
}
function _sgdiVoiceChunks(text){
  const clean=String(text||"").replace(/\s+/g," ").trim();
  if(!clean)return [];
  const chunks=[];
  let rest=clean;
  while(rest.length>180){
    let cut=Math.max(rest.lastIndexOf(". ",180),rest.lastIndexOf(", ",180),rest.lastIndexOf(" ",180));
    if(cut<80)cut=180;
    chunks.push(rest.slice(0,cut).trim());
    rest=rest.slice(cut).trim();
  }
  if(rest)chunks.push(rest);
  return chunks;
}
function _sgdiPlayRemoteTTS(text){
  try{
    const chunks=_sgdiVoiceChunks(text);
    if(!chunks.length)return false;
    try{
      if(_sgdiRemoteAudio){
        _sgdiRemoteAudio.pause();
        _sgdiRemoteAudio.src="";
      }
    }catch(e){}
    try{window.speechSynthesis?.cancel?.()}catch(e){}
    let index=0;
    const playNext=()=>{
      if(index>=chunks.length)return;
      const q=encodeURIComponent(chunks[index++]);
      const audio=new Audio("https://translate.google.com/translate_tts?ie=UTF-8&client=tw-ob&tl=fr&q="+q);
      _sgdiRemoteAudio=audio;
      audio.volume=1;
      audio.playbackRate=0.98;
      audio.preload="auto";
      audio.onended=playNext;
      audio.onerror=()=>{
        if(index<=1)_sgdiSpeakNow(text,0);
      };
      const started=audio.play();
      if(started&&typeof started.catch==="function"){
        started.catch(()=>{if(index<=1)_sgdiSpeakNow(text,0)});
      }
    };
    playNext();
    return true;
  }catch(e){
    return false;
  }
}
async function _sgdiPlayServerTTS(text){
  const chunks=_sgdiVoiceChunks(text);
  if(!chunks.length)return false;
  try{
    try{
      if(_sgdiRemoteAudio){
        _sgdiRemoteAudio.pause();
        _sgdiRemoteAudio.src="";
      }
    }catch(e){}
    try{window.speechSynthesis?.cancel?.()}catch(e){}
    let index=0;
    const playNext=async()=>{
      if(index>=chunks.length)return;
      const url=sgdiApiUrl("/assistant/tts?text="+encodeURIComponent(chunks[index++]),false);
      const res=await fetch(url,{cache:"no-store",headers:sgdiAuthHeaders({"accept":"audio/mpeg"})});
      if(!res.ok)throw new Error("HTTP "+res.status);
      const blob=await res.blob();
      const audio=new Audio(URL.createObjectURL(blob));
      _sgdiRemoteAudio=audio;
      audio.volume=1;
      audio.playbackRate=0.98;
      audio.onended=()=>{
        try{URL.revokeObjectURL(audio.src)}catch(e){}
        playNext().catch(()=>{if(window.speechSynthesis)_sgdiSpeakNow(text,0)});
      };
      audio.onerror=()=>{if(window.speechSynthesis)_sgdiSpeakNow(text,0)};
      await audio.play();
    };
    await playNext();
    return true;
  }catch(e){
    if(window.speechSynthesis)_sgdiSpeakNow(text,0);
    else if(_sgdiPlayRemoteTTS(text))return true;
    return false;
  }
}
function _sgdiSpeakText(text){
  if(!_sgdiVoiceEnabled())return false;
  if(!window.speechSynthesis)return false;
  return _sgdiSpeakNow(text,0);
}
