function validationCodeDateKey(){return today()}
function validationCodeForUser(username,dateKey=validationCodeDateKey()){
  const raw=String(username||"")+"|"+String(dateKey||"")+"|SGDI-VALIDATION-CODE";
  let h=2166136261;
  for(let i=0;i<raw.length;i++){h^=raw.charCodeAt(i);h=Math.imul(h,16777619)}
  const n=Math.abs(h)%10000;
  return String(n).padStart(4,"0");
}
function showDailyValidationCodeIfNeeded(){
  if(!validationCodeFeatureActive())return;
  const key="sgdiDailyValidationCodeShown:"+session.username+":"+validationCodeDateKey();
  if(sessionStorage.getItem(key)==="1")return;
  sessionStorage.setItem(key,"1");
  const code=validationCodeForUser(session.username);
  setTimeout(()=>openModal(`<h3 class="font-bold text-lg mb-2">Code de validation du jour</h3><p class="text-sm text-slate-500 mb-3">Utilisez ce code pour les créations, modifications, validations, suppressions et enregistrements sensibles aujourd'hui.</p><div class="text-center p-5 rounded-lg mb-4" style="background:#eff6ff;border:1px solid #bfdbfe"><div class="text-xs font-black uppercase text-slate-500 mb-1">${escapeHTML(session.username)} · ${formatDate(validationCodeDateKey())}</div><div class="font-mono font-black" style="font-size:42px;letter-spacing:.18em;color:#043970">${code}</div></div><div class="flex justify-end"><button class="btn btn-primary" onclick="closeModal()">J'ai noté le code</button></div>`),250);
}
const CRITICAL_ACTION_WORDS=["supprimer","valider","modifier","creer","créer","enregistrer","ajouter"];

const criticalActionAuthorized=new WeakSet();
function normalizeCriticalActionText(value){
  return String(value||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase();
}
function criticalActionElementLabel(el){
  if(!el)return"";
  return [el.innerText,el.textContent,el.value,el.getAttribute("aria-label"),el.getAttribute("title")].filter(Boolean).join(" ");
}
function criticalActionName(el){
  const text=normalizeCriticalActionText(criticalActionElementLabel(el));
  return CRITICAL_ACTION_WORDS.find(word=>text.includes(word))||"";
}
function criticalActionNeedsPassword(el){
  if(!el||criticalActionAuthorized.has(el)||!session||!session.username)return"";
  if(!validationCodeFeatureActive())return"";
  if(el.disabled||el.getAttribute("aria-disabled")==="true")return"";
  if(el.closest("[data-critical-auth], [data-no-critical-auth], #login-form, .login-admin-system-shortcut"))return"";
  if(el.closest("[data-section-action]"))return"";
  return criticalActionName(el);
}
function removeCriticalActionPasswordModal(){
  document.getElementById("critical-action-auth-host")?.remove();
}
function requestCriticalActionPassword(action){
  return new Promise(resolve=>{
    removeCriticalActionPasswordModal();
    const host=document.createElement("div");
    host.id="critical-action-auth-host";
    host.setAttribute("data-critical-auth","1");
    const expected=validationCodeForUser(session?.username||"");
    host.innerHTML=`<div class="modal-bg" data-critical-auth="1">
      <div class="modal p-6" data-critical-auth="1" style="max-width:420px">
        <h3 class="font-bold text-lg mb-2">Code de validation requis</h3>
        <p class="text-sm text-slate-500 mb-4">Saisissez le code journalier à 4 chiffres pour ${escapeHTML(action)}.</p>
        <form data-critical-auth="1">
          <label class="label">Utilisateur</label>
          <input class="input mb-3" value="${escapeHTML(session?.username||"")}" readonly/>
          <label class="label">Code du jour</label>
          <input class="input mb-4 font-mono text-center" type="password" name="code" inputmode="numeric" pattern="[0-9]{4}" maxlength="4" autocomplete="one-time-code" autofocus/>
          <div class="text-xs text-slate-500 mb-4">Le code change automatiquement chaque jour.</div>
          <div class="flex gap-2 justify-end">
            <button type="button" class="btn btn-ghost" data-critical-auth-cancel="1">Annuler</button>
            <button class="btn btn-primary" data-critical-auth-submit="1">Valider</button>
          </div>
        </form>
      </div>
    </div>`;
    document.body.appendChild(host);
    const finish=ok=>{removeCriticalActionPasswordModal();resolve(ok)};
    host.querySelector("[data-critical-auth-cancel]")?.addEventListener("click",()=>finish(false));
    host.querySelector(".modal-bg")?.addEventListener("click",event=>{if(event.target===event.currentTarget)finish(false)});
    host.querySelector("form")?.addEventListener("submit",event=>{
      event.preventDefault();
      const code=String(event.currentTarget.code?.value||"").trim();
      if(!/^\d{4}$/.test(code)){toast("Code à 4 chiffres obligatoire","error");return}
      if(code!==expected){toast("Code de validation incorrect","error");event.currentTarget.code.value="";event.currentTarget.code.focus();return}
      finish(true);
    });
    setTimeout(()=>host.querySelector('[name="code"]')?.focus(),0);
  });
}

document.addEventListener("click",event=>{
  const el=event.target&&event.target.closest?event.target.closest("button,a,[role='button'],input[type='button'],input[type='submit'],input[type='reset']"):null;
  const action=criticalActionNeedsPassword(el);
  if(!action)return;
  event.preventDefault();
  event.stopImmediatePropagation();
  requestCriticalActionPassword(action).then(ok=>{
    if(!ok)return;
    criticalActionAuthorized.add(el);
    el.click();
    setTimeout(()=>criticalActionAuthorized.delete(el),0);
  });
},true);
function currentAccessLevelCode(){const u=currentUserRecord();return String(session?.niveau||u?.niveau||"").trim()}
function isCadreCat01(){return currentAccessLevelCode().toUpperCase().replace(/[\s-]+/g,"_")==="CADRE_CAT_01"}
function structureSocieteFilterKey(mod){
  const m=mod||session?.transverse||"";
  return({drh:"drhSociete",ops:"opsSociete",materiel:"mtSociete",pointage:"pointageSociete",facturation:"facturationSociete",commercial:"commercialSociete",secretariat:"secretariatSociete",admin:"adminSocieteActive"}[m])||"moduleSociete";
}
function currentStructureSocieteFilter(){
  if(session?.societe)return session.societe;
  if(session?.transverse==="global")return "";
  if(isDrhModuleContext()){
    const v=sessionStorage.getItem("drhSociete")||"";
    return v||"";
  }
  if(session?.transverse)return sessionStorage.getItem(structureSocieteFilterKey())||"";
  return "";
}
function storeCurrentStructureSocieteFilter(s){
  try{
    const v=session?.societe||s||"";
    sessionStorage.setItem(structureSocieteFilterKey(),v);
    ["drhSociete","opsSociete","fpSociete","effectifSociete","mtSociete","portalSociete","pointageSociete","ptSociete","fpqSociete","dashSociete","commercialSociete","secretariatSociete","facturationSociete"].forEach(k=>sessionStorage.setItem(k,v));
  }catch(e){}
}
function setCurrentStructureSocieteFilter(s){
  storeCurrentStructureSocieteFilter(s);
  render();
}
function siteMatchesSociete(site,soc){
  if(!soc)return true;
  if(!site)return false;
  const primarySociete=sitePrimarySociete(site);
  if(primarySociete)return normalizeSocieteName(primarySociete)===normalizeSocieteName(soc);
  const ids=new Set([site.id,site.backendId].filter(v=>v!==undefined&&v!==null&&v!=="").map(v=>String(v)));
  return (db.agents||[]).some(a=>normalizeSocieteName(a.societe)===normalizeSocieteName(soc)&&ids.has(String(agentLiveAffectation(a)?.siteId||"")));
}
function sitePrimarySociete(site){
  const plan=site?.equipment_plan&&typeof site.equipment_plan==="object"?site.equipment_plan:{};
  const legacy=plan._legacy&&typeof plan._legacy==="object"?plan._legacy:{};
  return site?.societe||site?.society||plan.societe||plan.society||legacy.societe||legacy.society||"";
}
function siteBelongsToPrimarySociete(site,soc){
  if(!soc)return true;
  return normalizeSocieteName(sitePrimarySociete(site))===normalizeSocieteName(soc);
}
function siteMatchesReference(site,ref){
  if(!site||!ref)return false;
  const ids=new Set([site.id,site.backendId].filter(v=>v!==undefined&&v!==null&&v!=="").map(String));
  if([ref.siteId,ref.siteBackendId,ref.site_id,ref._site?.id,ref._site?.backendId].some(v=>ids.has(String(v||""))))return true;
  const names=new Set([site.nom,site.intitule].filter(Boolean).map(v=>normalizedSearchText(v)));
  return [ref.siteName,ref._site?.nom,ref._site?.intitule,ref.autreAffectation].filter(Boolean).some(v=>names.has(normalizedSearchText(v)));
}
function activeSitesForCurrentScope(){
  const soc=typeof currentStructureSocieteFilter==="function"?currentStructureSocieteFilter():"";
  return siteOpsSitesForScope(soc);
}
function siteOpsSitesForScope(scopeSoc,extraSites,options){
  const byKey=new Map();
  const add=site=>{
    if(!site||(!options?.includeInactive&&(site.actif===false||site.active===0||site.statut==="inactif"))||!siteMatchesSociete(site,scopeSoc))return;
    const key=String(site.backendId||site.id||site.indicatif||site.nom||Math.random());
    byKey.set(key,{...(byKey.get(key)||{}),...site,actif:site.actif!==false});
  };
  const sources=options?.onlyExtra&&Array.isArray(extraSites)?extraSites:[...(db.sites||[]),...(extraSites||[])];
  sources.forEach(add);
  return [...byKey.values()].sort((a,b)=>(a.societe||"").localeCompare(b.societe||"")||(a.nom||a.intitule||"").localeCompare(b.nom||b.intitule||""));
}
function fpSiteFilterKeyFromName(v){
  return normalizedSearchText(v).replace(/\s+/g," ").trim();
}
function fpSiteFilterKeyForSite(site){
  return fpSiteFilterKeyFromName(site?.nom||site?.intitule||site?.name||"")||String(site?.id||site?.backendId||"");
}
function fpSiteFilterKeyForAgent(a){
  const aff=agentLiveAffectation(a)||{};
  const site=findSiteByRef(aff.siteId||aff.siteBackendId||aff.siteName||"");
  return fpSiteFilterKeyFromName(aff.siteName||site?.nom||site?.intitule||"")||String(aff.siteId||aff.siteBackendId||"");
}
function fpUniqueSiteOptions(scopeSoc){
  const byName=new Map();
  siteOpsSitesForScope(scopeSoc).forEach(site=>{
    const key=fpSiteFilterKeyForSite(site);
    if(!key)return;
    const previous=byName.get(key);
    if(!previous||String(site.backendId||"").localeCompare(String(previous.backendId||""))<0)byName.set(key,site);
  });
  return [...byName.values()].sort((a,b)=>String(a.nom||a.intitule||"").localeCompare(String(b.nom||b.intitule||""),"fr"));
}
function movementSitesForSociete(siteSociete){
  const scope=canonicalSocieteName(siteSociete||currentStructureSocieteFilter()||session?.societe||"",societeConfig().custom||SOCIETES);
  return siteOpsSitesForScope("").filter(site=>site.actif!==false&&(!scope||normalizeSocieteName(sitePrimarySociete(site))===normalizeSocieteName(scope)));
}
function incidentMatchesSociete(incident,soc){
  if(!soc)return true;
  if(!incident)return false;
  if(incident.societe===soc)return true;
  if(incident.agentId&&(db.agents||[]).some(a=>a.id===incident.agentId&&a.societe===soc))return true;
  if(incident.siteId&&(db.sites||[]).some(s=>s.id===incident.siteId&&siteMatchesSociete(s,soc)))return true;
  return false;
}
function defaultAccessMap(){
  const map={"DRH":["rh","admin"],"OPS":["rh","dispatch","admin"],"MATERIEL/EQUIP":["rh","dispatch","admin"],"FINANCES/COMPTA":["rh","admin"],"COMMERCIAL":["rh","admin"],"SECRETARIAT GÉNÉRAL":["rh","dispatch","admin"],"POINTAGE":["rh","dispatch","admin"],"PORTAIL RH":["rh","dispatch","agent","admin"],"ADMINISTRATEUR GÉNÉRAL":["admin"],dashboard:["rh","dispatch","agent","admin"],dossiers:["rh","admin"],recrutement:["rh","admin"],reserve:["rh","admin"],candidats_archives:["rh","admin"],demandes_personnel:["rh","admin"],demandes_structure:["rh","dispatch","admin"],contrats:["rh","admin"],a_contractualiser:["rh","admin"],effectif:["rh","dispatch","admin"],agents:["rh","dispatch","admin","agent"],fiches:["rh","dispatch","admin"],badge:["rh","admin"],sites:["rh","dispatch","admin"],incidents:["rh","dispatch","agent","admin"],conges:["rh","dispatch","agent","admin"],paie:["rh","admin"],rapports:["rh","dispatch","admin"],materiel:["rh","dispatch","admin"],facturation:["rh","admin"],commercial:["rh","admin"],secretariat:["rh","dispatch","admin"],drh:["rh","admin"],pointage:["rh","dispatch","admin"],ops:["rh","dispatch","admin"],portail:["rh","dispatch","agent","admin"],parametres:["admin"],admin:["admin"]};
  map["ADMINISTRATION SYSTEME"]=map["ADMINISTRATEUR GÉNÉRAL"];
  ["materiel/articles","materiel/magasins","materiel/fournisseurs","materiel/dotation","materiel/sites-dotation","materiel/reversement"].forEach(k=>map[k]=map.materiel);
  ["facturation/devis","facturation/factures","facturation/paiements","facturation/avances","facturation/avoirs","facturation/caisse","facturation/situation"].forEach(k=>map[k]=map.facturation);
  ["commercial/prospects","commercial/clients","commercial/opportunites","commercial/visites","commercial/devis","commercial/catalogue","commercial/tarifs","commercial/stats"].forEach(k=>map[k]=map.commercial);
  ["secretariat/courriers","secretariat/notes","secretariat/archives"].forEach(k=>map[k]=map.secretariat);
  ["pointage/recap","pointage/societe","pointage/stats","pointage/legende"].forEach(k=>map[k]=map.pointage);
  ["ops/missions","ops/mouvements","ops/supervision"].forEach(k=>map[k]=map.ops);
  Object.values(map).forEach(roles=>{if(roles.includes("rh")&&!roles.includes("ops"))roles.push("ops")});
  return map
}
function canAccess(key){
  if(!session)return false;
  const r=session.role;
  const level=accessLevelRecord(session.niveau);
  if(level&&!levelAllowsModule(level,key))return false;
  const droits=(db&&db.droitsAcces&&typeof db.droitsAcces==="object")?db.droitsAcces:null;
  if(droits&&Object.keys(droits).length){
    const direct=droits[key+":"+r];
    if(direct!==undefined)return !!direct;
    const baseDirect=droits[key+":"+adminAccessBaseRole(r)];
    if(baseDirect!==undefined)return !!baseDirect;
  }
  const map=defaultAccessMap();
  const base=adminAccessBaseRole(r);
  return (map[key]||["admin"]).includes(base);
}
function mySoc(){return session?.societe||""}
function isDrhModuleContext(){const h=(location.hash||"").slice(2);return session?.transverse==="drh"||h.startsWith("drh")}
function globalSocieteBandHTML(){
  if(!session)return"";
  const imgs=typeof loadSocieteImages==="function"?loadSocieteImages():{};
  const drhContext=isDrhModuleContext();
  const active=currentStructureSocieteFilter();
  const visibleSocietes=currentAllowedSocietes();
  const countFor=s=>(db.agents||[]).filter(a=>a.statut==="actif"&&a.societe===s).length;
  const total=(db.agents||[]).filter(a=>a.statut==="actif"&&visibleSocietes.includes(a.societe)).length;
  const allActive=!active;
  const allBtn=`<button type="button" onclick="globalSocieteBandPick('')" class="societe-band-btn flex items-center gap-2 px-3 py-2 rounded-lg transition" style="background:${allActive?"#043970":"#fff"};color:${allActive?"#fff":"#334155"};border:1px solid ${allActive?"#043970":"#dbeafe"};min-height:42px">
    <span style="font-size:20px">🌐</span>
    <span class="font-black uppercase truncate" style="font-size:10px!important;max-width:132px">Toutes</span>
    <span class="pill ${allActive?"pill-amber":"pill-gray"}" style="font-size:10px!important;${allActive?"background:#facc15!important;color:#043970!important;border-color:#facc15!important;font-weight:950":""}">${total}</span>
  </button>`;
  const btn=s=>{
    const img=imgs[s]||defaultSocieteLogo(s);
    const isActive=active===s;
    const visual=img?`<img src="${img}" alt="${escapeHTML(s)}" style="width:26px;height:26px;object-fit:contain;border-radius:999px;background:#fff"/>`:`<span style="font-size:20px">🏢</span>`;
    return`<button type="button" onclick="globalSocieteBandPick('${String(s).replace(/'/g,"\\'")}')" class="societe-band-btn flex items-center gap-2 px-3 py-2 rounded-lg transition" style="background:${isActive?"#043970":"#fff"};color:${isActive?"#fff":"#334155"};border:1px solid ${isActive?"#043970":"#dbeafe"};min-height:42px">
      ${visual}
      <span class="font-black uppercase truncate" style="font-size:10px!important;max-width:132px">${escapeHTML(s)}</span>
      <span class="pill ${isActive?"pill-amber":"pill-gray"}" style="font-size:10px!important;${isActive?"background:#facc15!important;color:#043970!important;border-color:#facc15!important;font-weight:950":""}">${countFor(s)}</span>
    </button>`;
  };
  return`<div class="no-print px-4 py-2" style="background:#f8fafc;border-bottom:1px solid #dbeafe">
    <div class="flex items-center gap-2 flex-wrap">
      <div class="font-black uppercase text-slate-600 mr-1" style="font-size:10px!important;letter-spacing:.08em">Section société</div>
      ${allBtn}
      ${visibleSocietes.map(btn).join("")}
    </div>
  </div>`;
}
function globalSocieteBandPick(s){
  if(session?.societe){
    if(!s){changeSociete();return}
    if(mySoc()===s){toast("Société active : "+s,"success");return}
    pickSociete(s);return;
  }
  if(session?.transverse||isDrhModuleContext()){
    pickSocieteFilter(s||"");return;
  }
  if(!s){changeSociete();return}
  if(mySoc()===s){toast("Société active : "+s,"success");return}
  pickSociete(s);
}
function bySoc(arr,key="societe"){const s=mySoc();return s?arr.filter(x=>x&&x[key]===s):arr}
function clientNbrSites(client){return Math.max(parseInt(client?.tech_nbrSite)||0,Array.isArray(client?.tech_sites)?client.tech_sites.length:0)}
function clientSiteEffectif(site){const saved=parseInt(site?.totalEffectif)||0;if(saved>0)return saved;const g=parseInt(site?.nbrGroupe)||0,j=parseInt(site?.nbrJour)||0,n=parseInt(site?.nbrNuit)||0;return g*n+Math.max(0,j-n)}
function myAgents(){return bySoc(db.agents)}
function mySites(){const s=mySoc();if(!s)return db.sites;const ids=new Set(myAgents().map(a=>agentLiveAffectation(a)?.siteId).filter(Boolean));return db.sites.filter(st=>ids.has(st.id))}
function myCandidats(){return bySoc(db.candidats)}
function myMateriel(){return db.materiel?bySoc(db.materiel):[]}
function myConges(){const ids=new Set(myAgents().map(a=>a.id));return db.conges.filter(c=>ids.has(c.agentId))}
function myIncidents(){const aids=new Set(myAgents().map(a=>a.id));const sids=new Set(mySites().map(st=>st.id));return db.incidents.filter(i=>(i.agentId&&aids.has(i.agentId))||(i.siteId&&sids.has(i.siteId)))}
function workflowTaskAllowedForCurrentUser(t){return !t?.module||canAccessStructureKey(t.module)}
function workflowTasksForModule(module){
  const soc=currentStructureSocieteFilter()||mySoc()||"";
  return (db.workflowTasks||[]).filter(t=>t&&t.module===module&&t.status!=="done"&&workflowTaskAllowedForCurrentUser(t)&&(!soc||t.societe===soc)).sort((a,b)=>String(b.createdAt||"").localeCompare(String(a.createdAt||"")));
}
function workflowUpsertTask(task){
  if(!db.workflowTasks)db.workflowTasks=[];
  const id=String(task?.id||"");
  if(!id)return;
  const i=db.workflowTasks.findIndex(t=>String(t.id||"")===id);
  const row={status:"open",createdAt:new Date().toISOString(),...task};
  if(i>=0)db.workflowTasks[i]={...db.workflowTasks[i],...row,status:db.workflowTasks[i].status==="done"?"open":row.status};
  else db.workflowTasks.unshift(row);
}
function createRecruitmentWorkflowForEmployee(agent,candidate){
  if(!agent)return;
  const name=String((agent.nom||candidate?.nom||"")+" "+(agent.prenom||candidate?.prenom||"")).trim()||"Nouvel employé";
  const soc=agent.societe||candidate?.societe||"";
  const base={
    employeeId:agent.id,
    candidateId:candidate?.id||"",
    candidateBackendId:candidate?.backendId||"",
    candidateName:name,
    matricule:agent.matricule||"",
    societe:soc,
    createdBy:session?.username||"system",
    createdAt:new Date().toISOString()
  };
  workflowUpsertTask({
    ...base,
    id:`recruitment_employee_${agent.id}_ops`,
    module:"ops",
    route:"ops/instance_dotation",
    title:"Employé en instance de dotation",
    message:`${name} est recruté. OPS doit suivre l'avancement sans effectuer la dotation.`
  });
  workflowUpsertTask({
    ...base,
    id:`recruitment_employee_${agent.id}_materiel`,
    module:"materiel",
    route:"materiel/dotation",
    title:"Dotation matériel à préparer",
    message:`${name} est recruté. Matériel doit préparer la dotation.`
  });
}
