function pickSocieteFilter(s){if(session?.societe){storeCurrentStructureSocieteFilter(session.societe);toast("Société active : "+session.societe,"success");return}if(!s){setCurrentStructureSocieteFilter("");toast("Filtre société : Toutes les sociétés","success");return}setCurrentStructureSocieteFilter(s);toast("Filtre société : "+s,"success")}
function confirmPickSocieteFilter(s,p){if(session?.societe){storeCurrentStructureSocieteFilter(session.societe);toast("Société active : "+session.societe,"success");return}setCurrentStructureSocieteFilter(s);toast("Filtre société : "+s,"success")}
