function sgdiModuleHostConfig(){
  const host=String(location.hostname||"").toLowerCase();
  const configs=sgdiModuleHostConfigs();
  const first=host?host.split(".")[0]:"";
  const hostAliases={finances:"facturation",finance:"facturation",comptabilite:"facturation",compta:"facturation",facturation:"facmod"};
  const configKey=hostAliases[first]||first;
  // Domaine dédié (ex: drh.sgdi.com, facturation.sgdi.com)
  if(host&&first!=="localhost"&&host!=="127.0.0.1"&&host!=="0.0.0.0"&&host!=="::1"&&first!=="sgdi"&&first!=="www"&&first!=="atlas"){
    if(first==="administrateur"||first==="general")return configs.admin||null;
    return configs[configKey]||null;
  }
  // Domaine principal ou localhost : détecter les utilisateurs mono-structure
  if(session){
    const structs=currentAllowedStructures();
    if(structs.length===1&&structs[0]!=="admin"&&configs[structs[0]])return configs[structs[0]];
  }
  return null;
}
function sgdiModuleHostDefaultRoute(){
  const cfg=sgdiModuleHostConfig();
  if(!cfg)return null;
  return cfg.key==="admin"?"#/module-portal":"#/select-societe";
}
function sgdiModuleHostRequiresSociete(cfg){return !!cfg&&cfg.key!=="admin"}
function sgdiApplyModuleHostSession(redirect){
  const cfg=sgdiModuleHostConfig();
  if(!cfg||!session)return null;
  if(!canAccessModuleHostKey(cfg.key))return false;
  let changed=false;
  if(session.transverse!==cfg.key){session.transverse=cfg.key;changed=true}
  if(cfg.key==="admin"&&session.societe){session.societe=null;changed=true}
  if(changed)saveSession(session);
  try{
    if(cfg.key==="admin")sessionStorage.removeItem("mtSociete");
    else if(session.societe)storeCurrentStructureSocieteFilter(session.societe);
    sessionStorage.setItem("ficheContext",cfg.key);
  }catch(e){}
  const path=(location.hash||"").replace(/^#\/?/,"");
  const portalPaths=["","login","select-societe","societe-portal","dashboard","module-portal"];
  if(redirect&&portalPaths.includes(path))location.hash=sgdiModuleHostRequiresSociete(cfg)&&!session.societe?"#/select-societe":"#/module-portal";
  return true;
}
function selectModuleHostSociete(s){
  const cfg=sgdiModuleHostConfig();
  if(!cfg||!sgdiModuleHostRequiresSociete(cfg)){selectSocieteDirect(s);return}
  if(!canUseSociete(s)){toast("Société non autorisée pour cet utilisateur","error");return}
  session.societe=s;
  session.transverse=cfg.key;
  saveSession(session);
  try{
    sessionStorage.setItem("dashSociete",s);
    sessionStorage.setItem("fpSociete",s);
    sessionStorage.setItem("mtSociete",s);
    storeCurrentStructureSocieteFilter(s);
    sessionStorage.setItem("ficheContext",cfg.key);
  }catch(e){}
  toast("Société active : "+s,"success");
  location.hash=cfg.skipPortal?"#/"+cfg.homeRoute:"#/module-portal";
  route();
}
function enterModuleHostRoute(routeName){
  const cfg=sgdiModuleHostConfig();
  if(!cfg){navigate(routeName);return}
  if(sgdiApplyModuleHostSession(false)===false){renderModuleHostAccessDenied(cfg);return}
  if(sgdiModuleHostRequiresSociete(cfg)&&!session.societe){renderModuleHostSocieteSelector(cfg);return}
  navigate(routeName||cfg.homeRoute);
}
