async function refreshWorkspace(){
  const btn=document.querySelector(".ws-refresh-tab");
  try{
    if(btn){
      btn.disabled=true;
      btn.classList.add("is-refreshing");
    }
    uiProgressStart();
    if(typeof toast==="function")toast("Actualisation en cours...","info");
    const loaded=await sgdiPullState({silent:true,render:false,force:true});
    if(!loaded)throw new Error("PostgreSQL indisponible");
    await sgdiRefreshCountersNow({reason:"manual"});
    render();
    if(typeof toast==="function")toast("Données actualisées","success");
  }catch(e){
    if(typeof toast==="function")toast("Actualisation impossible : "+(e.message||e),"error");
  }finally{
    if(btn){
      btn.disabled=false;
      btn.classList.remove("is-refreshing");
    }
    uiProgressDone();
  }
}
window.refreshWorkspace=refreshWorkspace;
