function counterOrderSettings(){
  if(!db.settings||typeof db.settings!=="object")db.settings={};
  if(!db.settings.counterOrder||typeof db.settings.counterOrder!=="object")db.settings.counterOrder={};
  return db.settings.counterOrder;
}
function counterKey(item){return String(item?.key||item?.label||"").trim()}
function counterOrderForModule(module){
  const order=counterOrderSettings()[module];
  const list=Array.isArray(order)?order.filter(Boolean):[];
  if(module==="ops"&&!list.includes("NBR SITE"))return ["NBR SITE",...list];
  return list;
}
function applyCounterOrder(module,items){
  const order=counterOrderForModule(module);
  if(!order.length)return items;
  const byKey=new Map((items||[]).map(item=>[counterKey(item),item]));
  const used=new Set();
  const sorted=[];
  order.forEach(key=>{const item=byKey.get(key);if(item){sorted.push(item);used.add(key)}});
  (items||[]).forEach(item=>{const key=counterKey(item);if(!used.has(key))sorted.push(item)});
  return sorted;
}
function moduleCountersRibbon(items){
  if(!items||!items.length)return"";
  const hiddenCounterLabels=new Set(["ATTENTE PV"]);
  const visibleItems=(items||[]).filter(item=>!hiddenCounterLabels.has(String(item?.label||"").trim().toUpperCase()));
  if(!visibleItems.length)return"";
  const ordered=applyCounterOrder(moduleCounterCurrentModule(),visibleItems);
  const total=ordered.reduce((s,x)=>s+(Number(x.value)||0),0);
  return `<div class="module-counters-ribbon drh-workforce-ribbon no-print" style="--ribbon-count:${Math.min(Math.max(ordered.length,1),12)};height:auto!important;min-height:68px!important;overflow-y:visible!important" data-no-lang="1">${ordered.map(i=>moduleCounterItemHTML(i,total)).join("")}</div>`;
}
function sgdiErpStatsForScope(scopeSoc){
  const stats=window.SGDI_SIDEBAR_STATS;
  if(!stats||!stats.erp)return null;
  const active=String(stats.scope?.active_society||"").trim();
  const scope=String(scopeSoc||"").trim();
  if(scope&&active&&active!==scope)return null;
  if(scope&&!active)return null;
  if(!scope&&active)return null;
  return stats.erp;
}
function sgdiErpEmployeeCounters(scopeSoc){
  return sgdiErpStatsForScope(scopeSoc)?.employees||null;
}
function sgdiErpModuleCounters(module,scopeSoc){
  return sgdiErpStatsForScope(scopeSoc)?.[module]||null;
}
const sgdiPendingDotationCountCache=new Map();
function materialPendingDotationCountForSoc(scopeSoc){
  // Les stats serveur (without_equipment) ne lisent que la table EmployeeEquipment SQL
  // et ignorent les dotations enregistrées en JSON (stockMouvements). On utilise
  // toujours le calcul local pour avoir un chiffre cohérent avec la carte OPS.
  // Pendant la synchronisation SQL, les employés arrivent avant les mouvements de
  // dotation. Conserver le dernier total complet évite un faux +1 transitoire.
  const key=normalizeSocieteName(scopeSoc||"__all__");
  if(typeof sgdiSqlSyncInProgress!=="undefined"&&sgdiSqlSyncInProgress&&sgdiPendingDotationCountCache.has(key))return sgdiPendingDotationCountCache.get(key);
  const count=agentsEnInstanceDotationForSoc(scopeSoc).length;
  sgdiPendingDotationCountCache.set(key,count);
  return count;
}
function opsSitesActiveCount(){
  const ops=window.SGDI_SIDEBAR_STATS?.erp?.ops||window.SGDI_SIDEBAR_STATS?.ops?.sites||{};
  const value=ops.sites_active??ops.sites_actifs??ops.actifs??ops.active_sites;
  return Number.isFinite(Number(value))?Number(value):null;
}
function agentHasInstallationPV(a){
  if(!a)return false;
  // clé canonique + toutes les variantes legacy (alignées avec erp/service.py PV_INSTALLATION_KEYS)
  const PV_KEYS=["pvInstallation","pvInstallationValide","pvInstallationAt","installationPvAt","dateInstallationEffective","datePvInstallation","pv_installation","installationPv","installation_pv","date_pv_installation"];
  if(PV_KEYS.some(k=>a[k]))return true;
  const aff=a.affectationCourante||{};
  if(PV_KEYS.some(k=>aff[k]))return true;
  const asRows=v=>Array.isArray(v)?v:(v&&typeof v==="object"?Object.values(v):[]);
  const docs=[...asRows(a.documentsArchive),...asRows(a.documents),...asRows(a.pieces)];
  const events=[...asRows(a.gestionEvents),...asRows(a.careerEvents),...asRows(a.affectationsHistorique)];
  const hasText=row=>/pv\s*d['’]?installation|proc[eè]s\s*verbal\s*d['’]?installation|installation\s+valid[eé]e/i.test([row?.type,row?.title,row?.titre,row?.categorie,row?.category,row?.objet,row?.motif,row?.reference,row?.name,row?.fileName].filter(Boolean).join(" "));
  return docs.some(hasText)||events.some(hasText);
}
function defaultEffectifConfig(){
  return {operationalRequiresDotation:true,operationalRequiresAffectation:true,operationalRequiresPvInstallation:true,lockValidatedSections:true,showPreparationCounters:true,archiveDocumentsByEmployee:true,drhActions:["Détail","Congé","Suspendre","Convoquer","Mise en demeure","Sanctionner","Avenant","Nouveau contrat","Fin relation"],opsActions:["Détail","Suspendre","Blacklister","Affecter","D.Sanction","D.N.Dotation"],statuses:["actif","absent","suspendu","blacklist","conge","maladie","archive"]};
}
function effectifConfigSettings(){
  if(!db.settings||typeof db.settings!=="object")db.settings={};
  const cfg=db.settings.effectifConfig&&typeof db.settings.effectifConfig==="object"?db.settings.effectifConfig:{};
  db.settings.effectifConfig={...defaultEffectifConfig(),...cfg};
  ["drhActions","opsActions","statuses"].forEach(k=>{if(!Array.isArray(db.settings.effectifConfig[k]))db.settings.effectifConfig[k]=defaultEffectifConfig()[k]});
  return db.settings.effectifConfig;
}
function agentLiveAffectation(a){
  return typeof opsEmployeeLiveAffectation==="function"?opsEmployeeLiveAffectation(a):(a?.affectationCourante||{});
}
function agentHasLiveAffectation(a){
  const aff=agentLiveAffectation(a);
  return !!(aff&&(aff.siteId||aff.siteName));
}
function employeeLifecycleStatusKey(a){
  return normalizeEmployeeStatusValue(a?.statut||a?.status||"");
}
function employeeIsFormer(a,asOf=today()){
  if(!a)return false;
  if(EMPLOYEE_FORMER_STATUS_KEYS.has(employeeLifecycleStatusKey(a)))return true;
  const exitDate=String(a.dateSortie||a.departAt||"").slice(0,10);
  if(/^\d{4}-\d{2}-\d{2}$/.test(exitDate)&&exitDate<=asOf)return true;
  return !!(a.finRelationAt&&!exitDate);
}
function employeeIsActive(a){
  return !employeeIsFormer(a)&&["actif","active"].includes(employeeLifecycleStatusKey(a));
}
function agentIsOperational(a){
  return employeeIsActive(a);
}
function agentNeedsDotation(a){
  const cfg=effectifConfigSettings();
  return !!cfg.operationalRequiresDotation&&employeeIsActive(a)&&!agentHasMaterialDotation(a);
}
function agentNeedsAffectation(a){
  const cfg=effectifConfigSettings();
  return !!cfg.operationalRequiresAffectation&&employeeIsActive(a)&&!agentHasLiveAffectation(a);
}
function agentNeedsInstallationPV(a){
  const cfg=effectifConfigSettings();
  return !!cfg.operationalRequiresPvInstallation&&employeeIsActive(a)&&!agentNeedsDotation(a)&&!agentNeedsAffectation(a)&&!agentHasInstallationPV(a);
}
