function sgdiLangMode(){try{const m=localStorage.getItem('sgdiLangMode')||'fr';return m==='ar'?'ar':'fr'}catch(e){return 'fr'}}
function sgdiSetLangMode(mode){try{localStorage.setItem('sgdiLangMode',mode==='ar'?'ar':'fr')}catch(e){}applyLanguagePreference();}
function sgdiLangText(fr,ar){return sgdiLangMode()==='ar'?ar:fr}
function sgdiLanguageSelectorHTML(){const m=sgdiLangMode();const btn=(v,l)=>`<button type="button" data-no-lang="1" class="btn ${m===v?'btn-primary':'btn-secondary'} text-[10px] px-2 py-1" onclick="sgdiSetLangMode('${v}')">${l}</button>`;return `<div data-no-lang="1" class="sgdi-lang-choice flex items-center gap-1 mb-2"><span class="text-[10px] text-slate-400">Langue</span>${btn('fr','FR')}${btn('ar','AR')}</div>`}
function sgdiTranslateText(raw){
  if(!raw||!raw.trim())return raw;
  const mode=sgdiLangMode();
  let out=raw.replace(/[ÉéEe]conomiser/gi,"Enregistrer");
  [...SGDI_LANG_PAIRS].sort((a,b)=>b[0].length-a[0].length).forEach(([fr,ar])=>{
    const both=fr+' / '+ar;
    const target=mode==='ar'?ar:fr;
    out=out.split(both).join(target).split(fr).join(target);
    out=out.split(ar).join(target);
  });
  return out;
}
function applyLanguagePreference(root){
  const mode=sgdiLangMode();
  const scope=root||document.getElementById('app');
  if(!scope)return;
  document.documentElement.lang=mode==='ar'?'ar':'fr';
  document.documentElement.dir=mode==='ar'?'rtl':'ltr';
  const walker=document.createTreeWalker(scope,NodeFilter.SHOW_TEXT,{acceptNode(node){
    const p=node.parentElement;if(!p)return NodeFilter.FILTER_REJECT;
    if(p.closest('[data-no-lang],script,style,textarea'))return NodeFilter.FILTER_REJECT;
    if(!node.nodeValue||!node.nodeValue.trim())return NodeFilter.FILTER_REJECT;
    return NodeFilter.FILTER_ACCEPT;
  }});
  const nodes=[];while(walker.nextNode())nodes.push(walker.currentNode);
  nodes.forEach(n=>{const v=sgdiTranslateText(n.nodeValue);if(v!==n.nodeValue)n.nodeValue=v});
  scope.querySelectorAll('input[placeholder],textarea[placeholder],button[title],select[title]').forEach(el=>{
    ['placeholder','title'].forEach(a=>{const v=el.getAttribute(a);if(v){const t=sgdiTranslateText(v);if(t!==v)el.setAttribute(a,t)}});
  });
  scope.querySelectorAll('.sgdi-lang-choice button').forEach(b=>{b.classList.toggle('btn-primary',b.textContent===mode.toUpperCase());b.classList.toggle('btn-secondary',!b.classList.contains('btn-primary'))});
}

/* ---- SHELL ---- */
function render(){
  sanitizeCandidatesInDB();
  if(!session)renderOverlayHost();
  if(!session){renderLogin();return}
  const hostCfg=sgdiModuleHostConfig();
  if(hostCfg){
    const hostOk=sgdiApplyModuleHostSession(false);
    if(hostOk===false){renderModuleHostAccessDenied(hostCfg);return}
    if(sgdiModuleHostRequiresSociete(hostCfg)&&!session.societe){renderModuleHostSocieteSelector(hostCfg);return}
    const hostPath=(location.hash||"").replace(/^#\/?/,"");
    if(["","login","select-societe","societe-portal","dashboard","module-portal"].includes(hostPath)){renderModuleHostPortal(hostCfg);return}
  }
  if(!session.societe && !session.transverse){renderSocieteSelector();return}
  if(session.societe&&!session.transverse&&["societe-portal","dashboard"].includes((location.hash||"").slice(2)||"dashboard")){
    const _mods=societePortalModules();
    const _keys=[...new Set(_mods.map(m=>m.key))];
    if(_keys.length===1){const _m=_mods[0];enterSocietePortalRoute(_m.key,_m.route);return}
    renderSocietePortal();return
  }
  // En mode transverse, restreindre aux routes du module sélectionné
  if(session.transverse){
    const h=(location.hash||"").slice(2);
    const root=h.split("/")[0];
    const allowedByMod={
      facturation:["facturation","incidents","demandes_structure"],
      facmod:["facturation","incidents","demandes_structure"],
      commercial:["commercial","incidents","demandes_structure"],
      secretariat:["secretariat","incidents","demandes_structure"],
      materiel:["materiel","fiches","agents","effectif","sites","incidents","demandes_structure"],
      admin:["admin","sites","incidents","demandes_structure"],
      pointage:["pointage","incidents","demandes_structure"],
      paie:["paie","effectif","agents","demandes_structure"],
      ops:["ops","pointage","fiches","agents","sites","effectif","incidents","conges","demandes_structure"],
      drh:["drh","dashboard","dossiers","recrutement","reserve","candidats_archives","contrats","fiches","effectif","agents","sites","incidents","conges","materiel","paie","rapports","demandes_personnel","demandes_structure","portail"],
      global:["global-dashboard","effectif","agents","contrats","fiches","sites","pointage","paie","recrutement","reserve","candidats_archives","dossiers","incidents","conges","demandes_personnel","demandes_structure","rapports","ops","drh","admin","facturation","commercial","secretariat","materiel"]
    };
    const allowed=allowedByMod[session.transverse]||[session.transverse];
    if(!allowed.includes(root)){const target=session.transverse==="materiel"?"materiel/dashboard":session.transverse==="pointage"?"pointage":session.transverse==="ops"?"ops/dashboard":session.transverse==="global"?"global-dashboard":session.transverse+"/dashboard";location.hash="#/"+target;return}
  }
  const app=document.getElementById("app");
  const socColors={};
  const isTrans=!!session.transverse;
  const transLabels={facturation:"FINANCES & COMPTABILITÉ",facmod:"FACTURATION",commercial:"MODULE COMMERCIAL",drh:"Direction R-H",materiel:"MATÉRIEL & ÉQUIPEMENT",admin:isAdminSystemSession()?"ADMINISTRATION SYSTÈME":"ADMINISTRATEUR GÉNÉRAL",pointage:"MODULE POINTAGE",ops:"DIRECTION OPS",secretariat:"SECRETARIAT GÉNÉRAL",paie:"MODULE PAIE",global:"🌐 SITUATION GÉNÉRALE"};
  const transColors={facturation:"#043970",facmod:"#0f766e",commercial:"#8b5cf6",drh:"#043970",materiel:"#043970",admin:"#dc2626",pointage:"#043970",ops:"#1e40af",secretariat:"#0f766e",paie:"#0f766e",global:"#0f172a"};
  const transDescs={facturation:"Toutes sociétés confondues",facmod:"Facturation clients · Toutes sociétés",commercial:"Toutes sociétés confondues",drh:"Toutes sociétés confondues",materiel:"Toutes sociétés confondues",admin:"Paramétrage global du système",pointage:"Pointage mensuel · Toutes sociétés",ops:"OPS · Pointage · Fiches · Sites",secretariat:"Courriers · Notes · Archives · Suivi administratif",paie:"Paie · Bulletins · Déclarations · Toutes sociétés",global:"Toutes sociétés confondues — Vue consolidée groupe"};
  const socColor=isTrans?transColors[session.transverse]:(socColors[session.societe]||"#64748b");
  const headerTitle=isTrans?transLabels[session.transverse]:session.societe;
  const headerSub=isTrans?(session.societe?`Société active : ${session.societe}`:transDescs[session.transverse]):"Société active";
  app.innerHTML=`<div class="sgdi-shell h-screen flex flex-col">
    <div class="sgdi-topbar flex items-center justify-between px-4 py-2 no-print" style="background:#011b3f;border-bottom:1px solid #062b5f;gap:12px">
      <div class="sgdi-topbar-left ${isTrans?"sgdi-topbar-left-module":""} flex items-center gap-3 shrink-0">
        <button type="button" class="btn btn-ghost text-xs topbar-back-btn" onclick="goBackSmart()" title="Retour" aria-label="Retour">←</button>
        <div class="text-[10px] uppercase tracking-wider text-slate-500 font-semibold">${headerSub}</div>
      </div>
      <div class="sgdi-topbar-title-right sgdi-topbar-module-title ${isTrans?"sgdi-topbar-module-title-active":""}" style="color:${socColor}">${escapeHTML(headerTitle)}</div>
      <div class="sgdi-topbar-actions flex items-center gap-2 shrink-0"></div>
    </div>
    <div class="sgdi-shell-body flex flex-1 min-h-0">
      <aside class="sidebar w-72 flex flex-col shrink-0">
        <div class="sidebar-user sidebar-user-identity sidebar-user-profile-large px-4 py-5 text-xs">
          <div class="sidebar-profile-mark" aria-hidden="true"><span>${escapeHTML((session.nom||"A").slice(0,1).toUpperCase())}</span></div>
          <div class="sidebar-atlas-brand sidebar-current-user-name">${escapeHTML(session.nom)}</div>
          <div class="sidebar-user-role">${session.role}</div>
        </div>
        <nav class="flex-1 overflow-y-auto py-3 px-2" id="sidebar-nav"></nav>
        <div id="sidebar-back-slot"></div>
        <div class="sidebar-user sidebar-user-logout px-4 py-3 text-xs">
          <button class="btn btn-ghost w-full justify-center" onclick="logout()">Se déconnecter</button>
        </div>
      </aside>
      <main class="flex-1 flex flex-col overflow-hidden min-w-0">
        ${workspaceTabsBarHTML()}
        ${moduleCountersRibbonHTML()}
        <div class="sgdi-view flex-1 overflow-y-auto" id="view"></div>
      </main>
    </div>
    ${dialogueBoxHTML()}
  </div>`;
  renderSidebar();
  sgdiEnterViewMode(true);
  renderView();
  renderOverlayHost();
  sgdiSyncOverlayState();
  sgdiInitEditFab();
  setTimeout(()=>applyLanguagePreference(),0);
}
