function openCreateSocieteModal(){
  if(!isAdm2()){toast("Création société réservée à l'administrateur ADM2","error");return}
  openModal(`<h3 class="font-bold text-lg mb-4">Créer une nouvelle société</h3>
    <form data-no-critical-auth="1" onsubmit="event.preventDefault();confirmCreateSociete()">
      <div class="mb-3">
        <label class="label">Nom de la société *</label>
        <input class="input" name="nom"  autofocus placeholder="Ex. NOUVELLE SOCIETE"/>
      </div>
      <div class="mb-4">
        <label class="label">Description</label>
        <input class="input" name="description" placeholder="Activité, métier, précision..."/>
      </div>
      <div class="mb-4">
        <label class="label">Image / logo</label>
        <input id="societe-image-input" class="hidden" type="file" accept="image/*" onchange="handleSocieteImageUpload(this)"/>
        <input type="hidden" name="image"/>
        <div id="societe-image-holder" class="flex items-center gap-3">
          <button type="button" class="btn btn-secondary" onclick="document.getElementById('societe-image-input').click()">Ajout image</button>
          <span class="text-xs text-slate-500">Logo ou image de la société</span>
        </div>
      </div>
      <div class="flex justify-end gap-2">
        <button type="button" class="btn btn-ghost" onclick="closeModal()">Annuler</button>
        <button class="btn btn-primary">Créer</button>
      </div>
    </form>`);
}
function handleSocieteImageUpload(input){
  const f=input&&input.files&&input.files[0];if(!f)return;
  if(f.size>2*1024*1024){toast("Image > 2 Mo","error");input.value="";return}
  const r=new FileReader();
  r.onload=e=>{
    const url=e.target.result;
    const hidden=document.querySelector('.modal-bg [name="image"]');
    if(hidden)hidden.value=url;
    const holder=document.getElementById("societe-image-holder");
    if(holder)holder.innerHTML=`<img src="${url}" alt="Logo société" style="width:58px;height:58px;border-radius:14px;object-fit:cover;border:1px solid #cbd5e1"/><button type="button" class="btn btn-secondary" onclick="document.getElementById('societe-image-input').click()">Changer image</button><button type="button" class="btn btn-ghost text-red-600" onclick="removeSocieteImage()">Retirer</button>`;
  };
  r.readAsDataURL(f);
}
function removeSocieteImage(){
  const input=document.getElementById("societe-image-input");if(input)input.value="";
  const hidden=document.querySelector('.modal-bg [name="image"]');if(hidden)hidden.value="";
  const holder=document.getElementById("societe-image-holder");
  if(holder)holder.innerHTML=`<button type="button" class="btn btn-secondary" onclick="document.getElementById('societe-image-input').click()">Ajout image</button><span class="text-xs text-slate-500">Logo ou image de la société</span>`;
}
