async function confirmDevis(){
  const fd=new FormData(document.querySelector(".modal-bg form"));
  const qte=parseFloat(fd.get("quantite"))||0;
  const pu=parseFloat(fd.get("prixUnitaire"))||0;
  const tva=parseFloat(fd.get("tva"))||0;
  const rem=parseFloat(fd.get("remise"))||0;
  const totalHT=qte*pu;
  const remiseAmt=totalHT*(rem/100);
  const ht=totalHT-remiseAmt;
  const tvaAmt=ht*(tva/100);
  const ttc=ht+tvaAmt;
  db.devis=db.devis||[];
  db.devis.push({
    id:uid("dv"),numero:fd.get("numero"),date:fd.get("date"),societe:fd.get("societe"),validite:parseInt(fd.get("validite")||"30",10),
    client:fd.get("client"),adresseClient:fd.get("adresseClient")||"",tel:fd.get("tel")||"",email:fd.get("email")||"",
    objet:fd.get("objet"),designation:fd.get("designation")||"",quantite:qte,prixUnitaire:pu,tva,remise:rem,
    totalHT:ht,tvaAmt,ttc,conditions:fd.get("conditions")||"",statut:"brouillon",createdBy:session.username,createdAt:new Date().toISOString()
  });
  if(!(await saveDBAndWaitToast("Devis non confirmé")))return;
  closeModal();
  toast("Devis "+fd.get("numero")+" enregistré · TTC: "+money(ttc),"success");
}
