function sidebarOrderSettings(){
  if(!db.settings||typeof db.settings!=="object")db.settings={};
  if(!db.settings.sidebarOrder||typeof db.settings.sidebarOrder!=="object")db.settings.sidebarOrder={};
  return db.settings.sidebarOrder;
}
function sidebarOrderForModule(module){
  const order=sidebarOrderSettings()[module];
  return Array.isArray(order)?order.filter(Boolean):[];
}
function sidebarCustomSettings(){
  if(!db.settings||typeof db.settings!=="object")db.settings={};
  if(!db.settings.sidebarCustom||typeof db.settings.sidebarCustom!=="object")db.settings.sidebarCustom={};
  return db.settings.sidebarCustom;
}
function sidebarCustomItemsForModule(module){
  const rows=sidebarCustomSettings()[module];
  return Array.isArray(rows)?rows.filter(r=>r&&r.label&&r.route).map(r=>({...r,custom:true})):[];
}
function sidebarMenuSlug(v){
  const base=String(v||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase().replace(/[^a-z0-9]+/g,"-").replace(/^-+|-+$/g,"");
  return base||"rubrique";
}
function sidebarNormalizeRoute(route,module,label){
  let r=String(route||"").normalize("NFD").replace(/[\u0300-\u036f]/g,"").trim().replace(/^#?\/?/,"");
  if(!r)r="custom/"+(module||"module")+"/"+sidebarMenuSlug(label);
  return r.replace(/\s+/g,"-").replace(/[^a-zA-Z0-9_\/-]+/g,"-").replace(/-+/g,"-").replace(/\/+/g,"/").replace(/^\/+|\/+$/g,"");
}
function mergeSidebarCustomItems(module,items){
  const base=(items||[]).slice();
  const routes=new Set(base.map(i=>i.route));
  sidebarCustomItemsForModule(module).forEach(item=>{if(!routes.has(item.route)){base.push(item);routes.add(item.route)}});
  return base;
}
function applySidebarOrder(module,items){
  const pinned=sidebarPinnedDefaultOrder(module);
  const saved=sidebarOrderForModule(module);
  const order=pinned.length?[...pinned,...saved.filter(route=>!pinned.includes(route))]:saved;
  if(!order.length)return items;
  const byRoute=new Map((items||[]).map(item=>[item.route,item]));
  const used=new Set();
  const sorted=[];
  order.forEach(route=>{const item=byRoute.get(route);if(item){sorted.push(item);used.add(route)}});
  (items||[]).forEach(item=>{if(!used.has(item.route))sorted.push(item)});
  return sorted;
}
function sidebarPinnedDefaultOrder(module){
  if(!["drh","ops"].includes(module))return [];
  const defaults=adminSidebarOrganizerDefaults()[module]||[];
  return defaults.map(row=>row[1]).filter(Boolean);
}
