function stripCryptogramText(t){
  if(!t)return t;
  return t
    .replace(/[\p{Extended_Pictographic}\ufe0f]/gu,"")
    .replace(/\s{2,}/g," ")
    .replace(/\s+([·,.;:!?])/g,"$1");
}
function stripCryptogrammes(root){
  root=root||document;
  root.querySelectorAll(".ico").forEach(el=>{el.style.display="none"});
  root.querySelectorAll("span,div,label").forEach(el=>{
    if(el.closest(".ws-browser-chrome"))return;
    if(el.closest("[data-preserve-emoji]"))return;
    if(el.children.length)return;
    const txt=(el.textContent||"").trim();
    if(txt&&stripCryptogramText(txt).trim()==="")el.style.display="none";
  });
  const walker=document.createTreeWalker(root,NodeFilter.SHOW_TEXT,{
    acceptNode(node){
      const p=node.parentElement;
      if(!p||["SCRIPT","STYLE","TEXTAREA"].includes(p.tagName))return NodeFilter.FILTER_REJECT;
      if(p.closest(".ws-browser-chrome"))return NodeFilter.FILTER_REJECT;
      if(p.closest("[data-preserve-emoji]"))return NodeFilter.FILTER_REJECT;
      return /[\p{Extended_Pictographic}\ufe0f]/u.test(node.nodeValue||"")?NodeFilter.FILTER_ACCEPT:NodeFilter.FILTER_SKIP;
    }
  });
  const nodes=[];
  while(walker.nextNode())nodes.push(walker.currentNode);
  nodes.forEach(n=>{n.nodeValue=stripCryptogramText(n.nodeValue)});
}

function isPublicBadgeRoute(){
  const path=(location.hash||"").slice(2);
  return path.startsWith("badge/verify/");
}
function route(){
  if(isPublicBadgeRoute()){
    const [,sub,arg]=(location.hash||"").slice(2).split("/");
    document.getElementById("app").innerHTML=`<div id="view" class="public-badge-view"></div>`;
    renderBadgeVerify(document.getElementById("view"),arg);
    return;
  }
  if(!session||!sgdiAuthToken()){session=null;saveSession(null);sgdiPostgresReady=false;renderLogin();return}
  if(!sgdiPostgresReady){renderPostgresRequired("Chargement PostgreSQL requis. Aucune donnée locale ne sera utilisée.");return}
  render();
}
function renderPostgresRequired(message){
  const app=document.getElementById("app");
  app.innerHTML=`<div class="min-h-screen flex items-center justify-center p-6 bg-slate-50">
    <div class="card p-6 max-w-xl text-center">
      <h1 class="text-xl font-bold text-red-700 mb-2">PostgreSQL obligatoire</h1>
      <p class="text-sm text-slate-600 mb-4">${escapeHTML(message||"Les données n'ont pas été chargées depuis PostgreSQL. L'application est bloquée pour éviter toute donnée locale.")}</p>
      <div class="flex gap-2 justify-center">
        <button class="btn btn-primary" onclick="retryPostgresLoad()">Réessayer</button>
        <button class="btn btn-ghost" onclick="logout()">Déconnexion</button>
      </div>
    </div>
  </div>`;
}
async function retryPostgresLoad(){
  renderPostgresRequired("Rechargement depuis PostgreSQL...");
  const ok=await sgdiPullState({silent:true,render:false,force:true,deferSql:true}).catch(()=>null);
  if(ok){route();return}
  sessionStorage.removeItem(SGDI_API_TOKEN_KEY);
  session=null;
  saveSession(null);
  sgdiPostgresReady=false;
  renderLogin();
  if(typeof toast==="function")toast("Session expirée : reconnectez-vous.","error");
}



function sgdiTitleCaseText(text){
  let out=String(text||"").replace(/\s+/g," ").trim().toLocaleLowerCase("fr-FR");
  const acronyms=["SGDI","DRH","OPS","RH","ERP","CNAS","QR","PV","CDD","CDI","SNMG","OM"];
  acronyms.forEach(code=>{
    out=out.replace(new RegExp(`\\b${code.toLocaleLowerCase("fr-FR")}\\b`,"g"),code);
  });
  return out.replace(/^([\s"'([{«]*)([\p{L}])/u,(m,prefix,ch)=>prefix+ch.toLocaleUpperCase("fr-FR"));
}

function normalizePageHeader(view){
  if(!view||view.querySelector('.candidate-page,.sgdi-login-page,.sgdi-societe-page'))return;
  const children=[...view.children].filter(el=>el.nodeType===1&&!el.classList.contains('module-counters-ribbon'));
  if(!children.length)return;
  let first=children[0];
  if(first.classList.contains('candidate-section-card')||first.classList.contains('modal-bg'))return;
  if(first.matches('h1')){
    const wrap=document.createElement('div');
    wrap.className='module-page-header';
    const left=document.createElement('div');
    left.className='module-page-header-copy';
    view.insertBefore(wrap,first);
    wrap.appendChild(left);
    left.appendChild(first);
    const next=left.nextElementSibling||wrap.nextElementSibling;
    if(next&&next.matches('p,.text-slate-500,.text-sm'))left.appendChild(next);
    first=wrap;
  }
  const h1=first.querySelector&&first.querySelector('h1');
  if(!h1)return;
  const text=(h1.textContent||'').trim();
  if(!text||first.closest('.modal'))return;
  first.classList.add('module-page-header');
  const direct=[...first.children];
  const actionChild=direct.find(el=>el!==h1&&el.querySelector&&el.querySelector('button,.btn,a.btn'));
  if(actionChild)actionChild.classList.add('module-page-header-actions');
  const h1Parent=h1.parentElement;
  if(h1Parent&&h1Parent!==first)h1Parent.classList.add('module-page-header-copy');
  first.querySelectorAll(':scope > button,:scope > .btn,:scope > a.btn').forEach(btn=>{
    let actions=first.querySelector(':scope > .module-page-header-actions');
    if(!actions){actions=document.createElement('div');actions.className='module-page-header-actions';first.appendChild(actions)}
    actions.appendChild(btn);
  });
}

function normalizeCentralPage(view){
  if(!view)return;
  view.classList.add("module-view");
  const iconPattern=/[\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}]/gu;
  const walker=document.createTreeWalker(view,NodeFilter.SHOW_TEXT,{acceptNode(node){
    const parent=node.parentElement;
    if(!parent||["SCRIPT","STYLE","TEXTAREA","INPUT","OPTION"].includes(parent.tagName))return NodeFilter.FILTER_REJECT;
    if(parent.closest("[data-preserve-emoji]"))return NodeFilter.FILTER_REJECT;
    return iconPattern.test(node.nodeValue||"")?NodeFilter.FILTER_ACCEPT:NodeFilter.FILTER_SKIP;
  }});
  const nodes=[];
  while(walker.nextNode())nodes.push(walker.currentNode);
  nodes.forEach(node=>{node.nodeValue=(node.nodeValue||"").replace(iconPattern,"").replace(/\s{2,}/g," ").trimStart()});
  view.querySelectorAll("h1").forEach(h=>{
    h.classList.add("module-title-clean");
    h.textContent=sgdiTitleCaseText(h.textContent||"");
  });
  view.querySelectorAll("h2,h3").forEach(h=>{h.textContent=(h.textContent||"").replace(/\s+/g," ").trim()});
  view.querySelectorAll(".btn").forEach(btn=>{btn.innerHTML=(btn.innerHTML||"").replace(iconPattern,"").replace(/\s{2,}/g," ").trim()});
  view.querySelectorAll(".text-6xl,.text-5xl,.text-4xl,[data-icon-only]").forEach(el=>{
    if(!(el.textContent||"").trim()&&!el.querySelector("img,svg,input,select,button,a"))el.remove();
  });
  normalizePageHeader(view);
  view.querySelectorAll("table").forEach(t=>t.classList.add("module-table-clean"));
  view.querySelectorAll(".card").forEach(c=>c.classList.add("module-card-clean"));
}
function sgdiScrollSnapshot(){
  const view=document.getElementById("view");
  return {
    path:(location.hash||"#/dashboard").slice(2),
    viewTop:view?view.scrollTop:0,
    winX:window.scrollX||0,
    winY:window.scrollY||0
  };
}
function sgdiRestoreScroll(snapshot){
  if(!snapshot)return;
  requestAnimationFrame(()=>{
    if(((location.hash||"#/dashboard").slice(2))!==snapshot.path)return;
    const view=document.getElementById("view");
    if(view)view.scrollTop=snapshot.viewTop||0;
    window.scrollTo(snapshot.winX||0,snapshot.winY||0);
  });
}
function sgdiRestoreScrollPosition(snapshot){
  if(!snapshot)return;
  requestAnimationFrame(()=>{
    const view=document.getElementById("view");
    if(view)view.scrollTop=snapshot.viewTop||0;
    window.scrollTo(snapshot.winX||0,snapshot.winY||0);
  });
}
function navigatePreserveScroll(route){
  sgdiNextScrollRestore=sgdiScrollSnapshot();
  sgdiResetViewScroll=false;
  navigate(route);
}
function sidebarNavigate(event,route){
  if(typeof closeEmployeeRowActions==="function")closeEmployeeRowActions();
  if(event){
    event.preventDefault();
    event.stopPropagation();
  }
  const path=(location.hash||"#/dashboard").slice(2);
  const target=String(route||"").replace(/^#?\/?/,"");
  if(target==="recrutement/candidats"){
    if(path==="recrutement/candidats"||path==="recrutement"||path==="recrutement/liste"){
      syncSidebarActiveState();
      refreshModuleCountersRibbon();
      return;
    }
    switchRecruitmentTab(event,"recrutement/candidats","new");
    return;
  }
  if(path===target||sidebarRouteActive(path,target)){
    syncSidebarActiveState();
    refreshModuleCountersRibbon();
    return;
  }
  navigate(target);
}
function switchRecruitmentTab(event,route,mode){
  if(typeof closeEmployeeRowActions==="function")closeEmployeeRowActions();
  if(event){
    event.preventDefault();
    event.stopPropagation();
  }
  const target="#/"+String(route||"").replace(/^#?\/?/,"");
  sgdiNextScrollRestore=sgdiScrollSnapshot();
  try{
    sgdiMarkUserNavigation();
    uiProgressStart();
    if(location.hash!==target)history.pushState(null,"",target);
    sgdiResetViewScroll=false;
    sgdiLastRenderedPath=target.slice(2);
    syncSidebarActiveState();
    refreshModuleCountersRibbon();
    const view=document.getElementById("view");
    if(view)renderRecrutement(view,mode||"new");
  }catch(e){
    console.error(e);
    navigatePreserveScroll(route);
    return;
  }finally{
    uiProgressDone();
    if(sgdiNextScrollRestore){
      const next=sgdiNextScrollRestore;
      sgdiNextScrollRestore=null;
      sgdiRestoreScrollPosition(next);
    }
  }
}

function renderView(){
  if(typeof closeEmployeeRowActions==="function")closeEmployeeRowActions();
  sanitizeCandidatesInDB();
  uiProgressStart();
  const path=(location.hash||"#/dashboard").slice(2);
  const samePath=sgdiLastRenderedPath===path;
  const preserveScroll=!!sgdiNextScrollRestore;
  const scrollState=samePath&&!sgdiResetViewScroll?sgdiScrollSnapshot():null;
  const view=document.getElementById("view");
  const resetScroll=!preserveScroll&&(sgdiResetViewScroll||!samePath);
  sgdiResetViewScroll=false;
  if(view&&resetScroll)view.scrollTop=0;
  const [root,sub,arg]=path.split("/");
  try{
    switch(root){
      case"dashboard":renderDashboard(view);break;
      case"dossiers":renderDossiers(view);break;
      case"recrutement":if(sub==="nouveau")renderCandidatForm(view,null,{reserveDirect:true});else if(sub==="liste"||sub==="candidats")renderRecrutement(view,"new");else if(sub)renderCandidatForm(view,sub);else renderRecrutement(view,"new");break;
      case"reserve":if(sub==="nouveau")renderCandidatForm(view,null,{reserveDirect:true});else if(sub)renderCandidatForm(view,sub);else renderRecrutement(view,"reserve");break;
      case"candidats_archives":if(sub)renderCandidatForm(view,sub);else renderRecrutement(view,"archive");break;
      case"contrats":
        if(sub==="dashboard")renderContratsDashboard(view);
        else if(sub==="a_contractualiser"&&!arg)renderContrats(view,"a_contractualiser");
        else if(sub==="avenants")renderAvenants(view);
        else if(sub==="situation"||sub==="clients")renderContrats(view,"situation");
        else if(sub==="nouveau_contrat")renderNouveauContratDirect(view);
        else if(sub==="nouveau"&&arg)renderContractualisation(view,arg);
        else if(sub)renderContractualisation(view,sub);
        else renderContratsDashboard(view);
        break;
      case"effectif":if(session?.transverse==="drh"&&sub==="instance_affectation"){navigate("effectif/actifs");return}if(sub==="agent"&&arg)renderAgentForm(view,arg);else if(sub==="sortants")renderElementsSortants(view);else renderEffectif(view,sub||"actifs");break;
      case"agents":if(sub)renderAgentForm(view,sub);else renderEffectif(view,"actifs");break;
      case"fiches":renderFiches(view,sub||"toutes");break;
      case"badge":if(sub==="verify"&&arg)renderBadgeVerify(view,arg);else renderFiches(view,"badge");break;
      case"sites":if(!["ops","admin","materiel","global"].includes(session?.transverse)){view.innerHTML=`<div class="card p-6"><h2 class="text-xl font-bold text-red-700 mb-2">Accès réservé OPS / Matériel / Administration système</h2><p class="text-slate-600">La carte Sites est disponible uniquement dans les modules OPS, Matériel ou Administration système.</p></div>`;break}if(sub==="nouveau"&&!arg)renderSiteForm(view,null);else if(sub==="actifs")renderSites(view);else if(sub)renderSiteForm(view,sub);else renderSites(view);break;
      case"incidents":renderIncidents(view,sub||"dashboard");break;
      case"conges":renderConges(view);break;
      case"portail":if(sub==="comptes")renderPortailComptes(view);else renderPortailPersonnel(view);break;
      case"demandes_personnel":renderDemandesPersonnel(view,sub||"dashboard",arg);break;
      case"demandes_structure":renderDemandesStructure(view,sub||"dashboard",arg);break;
      case"materiel":renderMateriel(view,sub||"inventaire",arg);break;
      case"facturation":renderFacturation(view,sub||"dashboard",arg);break;
      case"accounting":renderAccounting(view,sub||"dashboard",arg);break;
      case"achats":renderAchats(view,sub||"dashboard",arg);break;
      case"ventes":renderVentes(view,sub||"dashboard",arg);break;
      case"reporting":renderReporting(view,sub||"dashboard",arg);break;
      case"commercial":renderCommercial(view,sub||"dashboard",arg);break;
      case"drh":renderDRH(view,sub||"dashboard",arg);break;
      case"admin":renderAdmin(view,sub||"dashboard",arg);break;
      case"custom":renderCustomSidebarPage(view,sub,arg);break;
      case"pointage":renderPointage(view,sub||"dashboard",arg);break;
      case"ops":renderOPS(view,sub||"dashboard",arg);break;
      case"secretariat":renderSecretariat(view,sub||"dashboard",arg);break;
      case"paie":renderPaie(view,sub||"dashboard",arg);break;
      case"rapports":renderRapports(view);break;
      case"parametres":if(sub==="log")renderUnlockLog(view);else renderParametres(view);break;
      case"global-dashboard":renderGlobalDashboard(view);break;
      default:renderDashboard(view);
    }
  }catch(e){console.error(e);view.innerHTML=`<div class="card p-6"><h2 class="text-xl font-bold mb-2 text-red-700">Erreur</h2><pre class="text-xs text-red-700">${escapeHTML(e.message)}\n${escapeHTML(e.stack||"")}</pre></div>`}
  normalizeCentralPage(view);
  uiProgressDone();
  sgdiLastRenderedPath=path;
  if(sgdiNextScrollRestore){const next=sgdiNextScrollRestore;sgdiNextScrollRestore=null;sgdiRestoreScrollPosition(next)}
  else if(scrollState)sgdiRestoreScroll(scrollState);
  else if(view&&resetScroll){view.scrollTop=0;window.scrollTo(window.scrollX||0,0)}
  // Traitement post-rendu différé : le navigateur peint d'abord la page,
  // puis le post-traitement s'exécute — la navigation est perçue comme instantanée
  requestAnimationFrame(()=>{
    filterDomBySearch();
    stripCryptogrammes(view);
    sgdiScrubInvalidCandidateFunctionArtifacts(view);
    uiEnhanceView();
    setTimeout(()=>{applyLanguagePreference(view);sgdiScrubInvalidCandidateFunctionArtifacts(view)},0);
  });
}
window.addEventListener("hashchange",()=>{sgdiMarkUserNavigation();uiProgressStart();sgdiFormHasUnsavedChanges=false;sgdiEnterViewMode(true);render()});
window.addEventListener("popstate",()=>{sgdiMarkUserNavigation();uiProgressStart();render()});
function fpqAutoRefreshRelieveAlert(){
  if(!session||!sgdiPostgresReady)return;
  if(!String(location.hash||"").startsWith("#/pointage/feuille"))return;
  const date=fpqCurrentDate();const soc=fpqCurrentSoc();const sit=fpqCurrentSite();
  const hasDue=(db.feuillePresence||[]).filter(f=>f.date===date&&(!soc||f.societe===soc)&&(!sit||f.siteId===sit)).some(fpqRelieveDueWithoutPointage);
  const domHas=!!document.querySelector(".fpq-site-alert");
  if(hasDue!==domHas)renderView();
}
setInterval(fpqAutoRefreshRelieveAlert,30000);
setInterval(()=>{if(session&&sgdiPostgresReady)refreshDemandesPersonnelFromPostgres({silent:true})},60000);

