function candidateExcelText(row,aliases){return String(excelCell(row,aliases)||"").trim()}
function candidateExcelLooseText(row,aliases){return String(excelCellLoose(row,aliases)||"").trim()}
function candidateExcelLooseDate(row,aliases){return excelDateValue(excelCellLoose(row,aliases))}
function candidateExcelMoney(row,aliases){const v=excelCell(row,aliases);const n=parseMoneyInput(v);return n||""}
function candidateExcelSplitName(full){
  const parts=String(full||"").trim().replace(/\s+/g," ").split(" ").filter(Boolean);
  if(parts.length<2)return {nom:parts[0]||"",prenom:""};
  return {nom:parts[0],prenom:parts.slice(1).join(" ")};
}
function candidateExcelSplitBirth(text){
  const raw=String(text||"").trim();
  if(!raw)return {};
  const dateRaw=(raw.match(/\d{4}[-/]\d{1,2}[-/]\d{1,2}|\d{1,2}[-/]\d{1,2}[-/]\d{2,4}/)||[])[0]||"";
  const date=excelDateValue(dateRaw);
  let place=raw.replace(dateRaw,"").replace(/\b(né|nee|née|ne|naissance|le|a|à)\b/gi," ").replace(/[,:;()_-]+/g," ").trim();
  return {dateNaissance:date,lieuNaissance:place};
}
function candidateExcelSplitAddress(text){
  const parts=String(text||"").split(/[,;|/]+/).map(x=>x.trim()).filter(Boolean);
  if(parts.length>=3)return {adresse:parts.slice(0,-2).join(", "),commune:parts[parts.length-2],wilaya:parts[parts.length-1]};
  if(parts.length===2)return {adresse:parts[0],wilaya:parts[1]};
  return {adresse:String(text||"").trim()};
}
function candidateExcelSmartEnhance(c,row){
  const fullName=candidateExcelText(row,["nom et prenom","nom et prénom","nom/prenom","nom/prénom","nom complet","employe","employé","agent","salarie","salarié"]);
  if((!c.nom||!c.prenom)&&fullName){const sp=candidateExcelSplitName(fullName);c.nom=c.nom||sp.nom;c.prenom=c.prenom||sp.prenom}
  c.nom=c.nom||candidateExcelLooseText(row,["nom","nom candidat","patronyme","family name"]);
  c.prenom=c.prenom||candidateExcelLooseText(row,["prenom","prénom","prenom candidat","first name"]);
  const birthCombined=candidateExcelLooseText(row,["date et lieu de naissance","date/lieu naissance","date lieu naissance","naissance complete","naissance complète","né le","ne le","ne(e) le","né(e) le"]);
  if((!c.dateNaissance||!c.lieuNaissance)&&birthCombined){const sp=candidateExcelSplitBirth(birthCombined);c.dateNaissance=c.dateNaissance||sp.dateNaissance;c.lieuNaissance=c.lieuNaissance||sp.lieuNaissance}
  c.dateNaissance=c.dateNaissance||candidateExcelLooseDate(row,["date naissance","date de naissance","naissance","né le","ne le","date né","date ne"]);
  c.lieuNaissance=c.lieuNaissance||candidateExcelLooseText(row,["lieu naissance","lieu de naissance","commune naissance","wilaya naissance","né à","ne a","lieu né","lieu ne"]);
  c.groupeSanguin=c.groupeSanguin||candidateExcelLooseText(row,["groupe sanguin","group sanguin","gs","blood group","blood type"]);
  const addrCombined=candidateExcelLooseText(row,["adresse complete","adresse complète","adresse commune wilaya","adresse et wilaya","adresse/wilaya","lieu residence","lieu résidence","domicile","adresse personnelle"]);
  if(addrCombined){const sp=candidateExcelSplitAddress(addrCombined);c.adresse=c.adresse||sp.adresse;c.commune=c.commune||sp.commune;c.wilaya=c.wilaya||sp.wilaya}
  c.adresse=c.adresse||candidateExcelLooseText(row,["adresse","adresse personnelle","domicile","residence","résidence"]);
  c.commune=c.commune||candidateExcelLooseText(row,["commune","commune residence","commune résidence","ville"]);
  c.wilaya=c.wilaya||candidateExcelLooseText(row,["wilaya","wilaya residence","wilaya résidence","province"]);
  c.posteSouhaite=c.posteSouhaite||candidatePosteCleanValue(candidateExcelLooseText(row,["poste","poste souhaite","poste souhaité","poste occupe","poste occupé","fonction","fonction actuelle","metier","métier","emploi","emploi occupe","emploi occupé","profession","qualification","grade"]));
  c.dateRecrutement=c.dateRecrutement||candidateExcelLooseDate(row,["date entree","date entrée","date d'entree","date d’entrée","date recrutement","date de recrutement","date embauche","date d'embauche","date integration","date intégration","date installation","date prise de service","date debut","date début","debut contrat","début contrat"]);
  c.dateEntree=c.dateEntree||c.dateRecrutement;
  markCandidateNinWarning(c);
  markCandidateAgeWarning(c);
  c.source="Import Excel libre";
  c.importFreeMode=true;
  return c;
}
function candidateExcelMapRow(row,index,mode,options){
  const reserve=mode!=="new";
  const opt=options||{};
  const c=candidateBlankDraft({reserveDirect:reserve,markImportedSections:reserve});
  c.source="Import Excel";
  c.importedAt=new Date().toISOString();
  c.importRow=index+2;
  c.nom=candidateExcelText(row,["nom","nom candidat","last name","lastname","family name","اللقب"]);
  c.prenom=candidateExcelText(row,["prenom","prénom","prenom candidat","prénom candidat","first name","firstname","given name","الاسم"]);
  c.dateNaissance=excelDateValue(excelCell(row,["date naissance","date de naissance","naissance","date naissance candidat","birth date","date birth"]));
  c.lieuNaissance=candidateExcelText(row,["lieu naissance","lieu de naissance","lieu","birth place","place of birth"]);
  c.nomPere=candidateExcelText(row,["nom pere","nom père","pere","père","nom du pere","nom du père","father","father name"]);
  c.nomMere=candidateExcelText(row,["nom mere","nom mère","mere","mère","nom de la mere","nom de la mère","mother","mother name"]);
  c.nin=candidateExcelText(row,["nin","nni","numero nin","numéro nin","numero identification","numéro identification","identifiant national","cin"]);
  c.sexe=candidateExcelText(row,["sexe","genre","gender"])||"M";
  c.situation=candidateExcelText(row,["situation","situation familiale","etat civil","état civil"])||"Célibataire";
  c.groupeSanguin=candidateExcelText(row,["groupe sanguin","group sanguin","gs","blood group","blood type"]);
  c.telephone=candidateExcelText(row,["telephone","téléphone","tel","mobile","gsm","phone"]);
  c.email=candidateExcelText(row,["email","mail","courriel"]);
  c.adresse=candidateExcelText(row,["adresse","address"]);
  c.commune=candidateExcelText(row,["commune","municipality"]);
  c.wilaya=candidateExcelText(row,["wilaya","province"]);
  c.posteSouhaite=candidatePosteCleanValue(candidateExcelText(row,["poste","poste souhaite","poste souhaité","fonction","metier","métier","emploi","job"]));
  c.dateRecrutement=excelDateValue(excelCell(row,["date entree","date entrée","date d'entree","date d’entrée","date recrutement","date de recrutement","date embauche","date d'embauche","date integration","date intégration","date installation","date prise de service","date debut","date début","debut contrat","début contrat"]));
  c.dateEntree=c.dateRecrutement;
  c.societe=canonicalSocieteName(candidateExcelText(row,["societe","société","entreprise","company"])||currentStructureSocieteFilter()||mySoc()||"",currentAllowedSocietes());
  c.salairePrevu=candidateExcelMoney(row,["salaire","salaire prevu","salaire prévu","salaire net","net a payer","net à payer"]);
  c.avisDecision=candidateExcelText(row,["avis","decision","décision","avis decision","avis décision"])||(reserve?"Favorable":"");
  c.avisDate=excelDateValue(excelCell(row,["date avis","date decision","date décision"]))||today();
  c.avisRecruteur=candidateExcelText(row,["recruteur","avis recruteur"]);
  c.avisCommentaire=candidateExcelText(row,["commentaire","observation","observations","notes"]);
  c.taille=candidateExcelText(row,["taille","taille cm","taille (cm)"]);
  c.pointure=candidateExcelText(row,["pointure"]);
  c.tailleChemise=candidateExcelText(row,["taille chemise","chemise"])||"M";
  c.exServices=excelYesNo(excelCell(row,["ex services","ex-services","ancien militaire","ancien services"]))==="oui"?"Oui":"Non";
  c.exServicesPrecision=candidateExcelText(row,["precision ex services","précision ex-services","arme"]);
  c.sport=excelYesNo(excelCell(row,["sport","sportif"]))==="oui"?"Oui":"Non";
  c.sportPrecision=candidateExcelText(row,["sport precision","sport précision","discipline"]);
  c.contactUrgenceNom=candidateExcelText(row,["contact urgence","nom contact urgence","urgence nom"]);
  c.contactUrgenceTel=candidateExcelText(row,["telephone urgence","téléphone urgence","tel urgence","urgence tel"]);
  c.contactUrgenceLien=candidateExcelText(row,["lien urgence","relation urgence"]);
  const langues=candidateExcelText(row,["langues","langues parlees","langues parlées"]);
  if(langues)c.langues=langues.split(/[;,/]+/).map(x=>x.trim()).filter(Boolean);
  c.habilitations={...c.habilitations,serviceNational:excelYesNo(excelCell(row,["service national","service militaire"])),enqueteHabilitation:excelYesNo(excelCell(row,["enquete habilitation","enquête habilitation","habilitation"]))};
  c.verifActeNaissance=excelYesNo(excelCell(row,["acte naissance","acte de naissance"]))==="oui";
  c.verifCertifResidence=excelYesNo(excelCell(row,["certificat residence","certificat résidence","residence"]))==="oui";
  c.verifCasierJudiciaire=excelYesNo(excelCell(row,["casier judiciaire","casier"]))==="oui";
  c.verifAptitudeMedicale=excelYesNo(excelCell(row,["aptitude medicale","aptitude médicale","medical"]))==="oui";
  c.verifBulletinANEM=excelYesNo(excelCell(row,["bulletin anem","anem"]))==="oui";
  c.verifChequeBarre=excelYesNo(excelCell(row,["cheque barre","chèque barré","cheque"]))==="oui";
  c.verifPieceIdentite=excelYesNo(excelCell(row,["piece identite","pièce identité","piece d'identite","carte identite"]))==="oui";
  c.verifFicheFamiliale=excelYesNo(excelCell(row,["fiche familiale"]))==="oui";
  c.verifFicheIndividuelle=excelYesNo(excelCell(row,["fiche individuelle"]))==="oui";
  if(String(c.nin||"").trim()==="1234567890")c.nin="";
  if(String(c.telephone||"").replace(/\s+/g,"")==="0550000000")c.telephone="";
  if(String(c.email||"").trim().toLowerCase()==="ahmed.dupont@example.com")c.email="";
  return opt.free?candidateExcelSmartEnhance(c,row):c;
}
function candidateImportExistingKeys(){
  const keys=new Set();
  (db.candidats||[]).forEach(c=>{const k=candidateDedupeKey(c)||candidateImportFallbackKey(c);if(k)keys.add(k)});
  (db.agents||[]).forEach(a=>{const k=candidateDedupeKey(a)||candidateImportFallbackKey(a);if(k)keys.add(k)});
  return keys;
}
function candidateImportFallbackKey(c){
  const norm=v=>String(v||"").trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/\s+/g," ");
  const name=norm(c.nom||c.last_name)+"|"+norm(c.prenom||c.first_name);
  if(name==="|")return "";
  const birth=norm(c.dateNaissance||c.birth_date);
  const phone=norm(c.telephone||c.phone);
  if(birth)return "name-birth|"+norm(c.societe||c.society)+"|"+name+"|"+birth;
  if(phone)return "name-phone|"+norm(c.societe||c.society)+"|"+name+"|"+phone;
  return "";
}
function candidateImportKeyLabel(key){
  key=String(key||"");
  if(key.startsWith("nin|"))return "même NIN";
  if(key.startsWith("birth-phone|"))return "même naissance + téléphone";
  if(key.startsWith("identity|"))return "même identité complète";
  if(key.startsWith("name-birth|"))return "même nom/prénom + date de naissance";
  if(key.startsWith("name-phone|"))return "même nom/prénom + téléphone";
  return "identité similaire";
}
function candidateExcelTemplateValueWarnings(c){
  const warnings=[];
  const norm=v=>String(v||"").trim().toLowerCase();
  if(norm(c.nom)==="dupont"&&norm(c.prenom)==="ahmed")warnings.push("Ligne exemple importée si non supprimée");
  return warnings;
}
function candidateAgeWarning(c){
  const age=c&&c.dateNaissance?candidatAgeAtSave(c.dateNaissance):null;
  return age!==null&&age<20;
}
function candidateHasAgeAlert(c){
  return !!(c&&(c.ageAlert||c.importAgeWarning||candidateAgeWarning(c)));
}
function candidateNinWarning(c){return false;}
function candidateHasNinAlert(c){
  return !!(c&&(c.ninAlert||c.importNinWarning||candidateNinWarning(c)));
}
function markCandidateNinWarning(c,row){
  if(!c||!candidateNinWarning(c))return c;
  c.ninAlert=true;
  c.ninAlertType="invalid_nin";
  c.ninAlertAt=c.ninAlertAt||new Date().toISOString();
  c.ninAlertValue=String(c.nin||"").trim();
  c.ninAlertMessage="Candidat importé avec NIN non conforme";
  c.importNinWarning=true;
  if(row)c.importNinWarningRow=row;
  const note=`ALERTE NIN : candidat importé avec un NIN non conforme (${c.ninAlertValue}).`;
  if(!String(c.notes||"").includes("ALERTE NIN"))c.notes=(c.notes?c.notes+"\n":"")+note;
  return c;
}
function markCandidateAgeWarning(c,row){
  if(!c||!candidateAgeWarning(c))return c;
  const age=candidatAgeAtSave(c.dateNaissance);
  c.ageAlert=true;
  c.ageAlertType="under_20";
  c.ageAlertAt=c.ageAlertAt||new Date().toISOString();
  c.ageAlertAge=age;
  c.ageAlertMessage="Candidat importé avec âge inférieur à 20 ans";
  c.importAgeWarning=true;
  if(row)c.importAgeWarningRow=row;
  const note="ALERTE AGE : candidat importé avec moins de 20 ans"+(age!==null?` (${age} ans)`:"")+".";
  if(!String(c.notes||"").includes("ALERTE AGE"))c.notes=(c.notes?c.notes+"\n":"")+note;
  return c;
}
function candidateExcelRowHasData(row){
  return Object.values(row||{}).some(v=>String(v??"").trim()!=="");
}
function candidateImportLabel(item){
  const c=item&&item.c?item.c:item;
  const name=String(((c&&c.nom)||"")+" "+((c&&c.prenom)||"")).trim()||"Candidat sans nom";
  return `${item&&item.row?`Ligne ${item.row} - `:""}${name}`;
}
async function readCandidateExcelFile(file,options){
  if(!await sgdiEnsureXLSX()){toast("Lecteur Excel indisponible","error");return}
  const opt=options||{};
  const reader=new FileReader();
  reader.onload=e=>{
    try{
      const wb=XLSX.read(new Uint8Array(e.target.result),{type:"array",cellDates:false});
      const ws=wb.Sheets[wb.SheetNames[0]];
      const rows=XLSX.utils.sheet_to_json(ws,{defval:"",raw:true}).filter(candidateExcelRowHasData);
      if(!rows.length){toast("Fichier Excel vide","error");return}
      previewCandidateExcelImport(rows,file.name,opt);
    }catch(err){console.error(err);toast("Import Excel impossible: "+err.message,"error")}
  };
  reader.readAsArrayBuffer(file);
}
function previewCandidateExcelImport(rows,fileName,options){
  const opt=options||{};
  const existing=candidateImportExistingKeys();
  const seen=new Set();
  const mapped=rows.map((row,i)=>{
    const c=candidateExcelMapRow(row,i,opt.targetMode||"reserve",opt);
    markCandidateNinWarning(c,i+2);
    markCandidateAgeWarning(c,i+2);
    const errors=candidateIdentityMissing(c);
    const warnings=candidateExcelTemplateValueWarnings(c);
    if(candidateHasNinAlert(c))warnings.push("Alerte NIN : format non conforme");
    if(candidateHasAgeAlert(c))warnings.push("Alerte âge : moins de 20 ans");
    const key=candidateDedupeKey(c)||candidateImportFallbackKey(c);
    const duplicate=!!key&&(existing.has(key)||seen.has(key));
    const duplicateReason=duplicate?`${existing.has(key)?"Déjà existant en base":"Répété dans le fichier"} (${candidateImportKeyLabel(key)})`:"";
    if(duplicate)warnings.push(duplicateReason);
    if(key)seen.add(key);
    return {row:i+2,c,key,errors,warnings,duplicate,duplicateReason};
  });
  window._candidateExcelImport={rows,mapped,fileName};
  const valid=mapped.filter(x=>!x.errors.length).length;
  const warningCount=mapped.filter(x=>x.warnings.length).length;
  const ninAlerts=mapped.filter(x=>candidateHasNinAlert(x.c)).length;
  const ageAlerts=mapped.filter(x=>candidateHasAgeAlert(x.c)).length;
  const err=mapped.filter(x=>x.errors.length).length;
  const sample=mapped.slice(0,25).map(x=>`<tr><td class="font-mono text-xs">${x.row}</td><td class="font-semibold">${escapeHTML((x.c.nom||"")+" "+(x.c.prenom||""))}</td><td>${safe(x.c.dateNaissance)}</td><td>${safe(candidatePosteLabel(x.c))}</td><td>${safe(x.c.societe)}</td><td>${x.errors.length?`<span class="pill pill-red">${escapeHTML(x.errors.join(", "))}</span>`:x.warnings.length?`<span class="pill pill-amber">${escapeHTML(x.warnings.join(" · "))}</span>`:`<span class="pill pill-green">Prêt backend</span>`}</td></tr>`).join("");
  openModal(`<h3 class="font-bold text-lg mb-1">${opt.free?"Import Excel libre":"Import Excel candidats"}</h3><p class="text-sm text-slate-500 mb-4">${escapeHTML(fileName||"Fichier Excel")} · ${rows.length} ligne(s)${opt.free?" · format non conforme accepté":""}</p>
    <div class="grid grid-4 gap-3 mb-4">
      <div class="card p-3"><div class="text-xs uppercase text-slate-500 font-bold">Prêts</div><div class="text-2xl font-black text-emerald-600">${valid}</div></div>
      <div class="card p-3"><div class="text-xs uppercase text-slate-500 font-bold">Avertissements</div><div class="text-2xl font-black text-amber-600">${warningCount}</div></div>
      <div class="card p-3"><div class="text-xs uppercase text-slate-500 font-bold">Alertes NIN</div><div class="text-2xl font-black text-red-600">${ninAlerts}</div></div>
      <div class="card p-3"><div class="text-xs uppercase text-slate-500 font-bold">Alertes âge</div><div class="text-2xl font-black text-red-600">${ageAlerts}</div></div>
      ${err?`<div class="card p-3"><div class="text-xs uppercase text-slate-500 font-bold">Erreurs</div><div class="text-2xl font-black text-red-600">${err}</div></div>`:""}
    </div>
    <div class="card overflow-hidden mb-4" style="max-height:50vh;overflow:auto"><table><thead><tr><th>Ligne</th><th>Candidat</th><th>Naissance</th><th>Poste</th><th>Société</th><th>Statut</th></tr></thead><tbody>${sample||`<tr><td colspan="6" class="text-center p-4 text-slate-500">Aucune ligne lisible.</td></tr>`}</tbody></table></div>
    <div class="text-xs text-slate-500 mb-4">${opt.free?"Mode libre : SGDI tente de séparer automatiquement nom/prénom, date/lieu de naissance et adresse/commune/wilaya. Les champs vides sont acceptés. ":""}Les doublons sont affichés en avertissement mais seront copiés dans le système. Seules les lignes sans nom/prénom sont refusées.</div>
    <div class="flex justify-end gap-2 flex-wrap"><button class="btn btn-ghost" onclick="closeModal()">Annuler</button><button class="btn btn-primary" ${valid?"":"disabled"} onclick="confirmCandidateExcelImport(this)">Enregistrer dans le backend</button></div>`);
}
async function confirmCandidateExcelImport(btn){
  const batch=window._candidateExcelImport;
  if(!batch||!Array.isArray(batch.mapped)){toast("Aucun import en attente","error");return}
  const rowsToImport=batch.mapped.filter(x=>!x.errors.length);
  rowsToImport.forEach(x=>{markCandidateNinWarning(x.c,x.row);markCandidateAgeWarning(x.c,x.row)});
  const invalidNin=rowsToImport.filter(x=>candidateHasNinAlert(x.c));
  const underAge=rowsToImport.filter(x=>candidateHasAgeAlert(x.c));
  const items=rowsToImport.map(x=>({...x.c,importRow:x.row,importAllowDuplicate:!!x.duplicate,importDuplicateReason:x.duplicateReason||"",importNinWarning:candidateHasNinAlert(x.c),importAgeWarning:candidateHasAgeAlert(x.c)}));
  if(!items.length){toast("Aucune ligne valide à importer","error");return}
  if(btn)btn.disabled=true;
  closeModal();
  sgdiShowImportProgress(0,items.length,"Import candidats en cours…");
  sgdiRequireServerWrite();
  if(!Array.isArray(db.candidats))db.candidats=[];
  let ok=0;
  const importErrors=[];
  const BATCH=10;
  try{
    for(let i=0;i<items.length;i+=BATCH){
      sgdiShowImportProgress(i,items.length,"Import candidats en cours…");
      const batch=items.slice(i,i+BATCH);
      const results=await Promise.allSettled(batch.map(c=>persistCandidateToPostgres(c,{allowCreate:true})));
      results.forEach((r,idx)=>{
        const c=batch[idx];
        if(r.status==="fulfilled"){
          if(!db.candidats.some(x=>String(x.id)===String(c.id)||String(x.backendId||"")===String(c.backendId||"")))db.candidats.push(c);
          ok++;
        }else{
          importErrors.push(`Ligne ${c.importRow||"?"} ${candidateImportLabel(c)} : ${r.reason?.message||r.reason}`);
        }
      });
    }
    sgdiShowImportProgress(items.length,items.length,"Import candidats en cours…");
    await sgdiPullState({silent:true,render:false,force:true,light:true});
    const resultLabel=`${ok} CANDIDAT(S) IMPORTÉ(S)${importErrors.length?` · ${importErrors.length} ÉCHEC(S)`:""}${invalidNin.length?` · ${invalidNin.length} ALERTE(S) NIN`:""}${underAge.length?` · ${underAge.length} ALERTE(S) AGE`:""}`;
    sgdiShowImportResult(ok,importErrors.length,importErrors,resultLabel);
    navigate("reserve");
  }catch(e){
    sgdiRemoveImportOverlay();
    if(btn)btn.disabled=false;
    toast("Import backend refusé : "+(e.message||e),"error");
  }
}
