function directContractSiteFromEmployee(a){
  const aff=a?.affectationCourante||{};
  const id=aff.siteId||a?.siteId||"";
  const name=String(aff.siteName||a?.site||"").trim().toLowerCase();
  return (db.sites||[]).find(s=>(id&&String(s.id)===String(id))||(id&&String(s.backendId||"")===String(id))||(name&&String(s.nom||s.intitule||"").trim().toLowerCase()===name))||null;
}
function contractWorkflowStatusLabel(status,signature){
  if(status==="valide_rh")return "VALIDÉ RH";
  if(signature)return "SIGNÉ EMPLOYÉ";
  return "BROUILLON";
}
function normalizeContractDurationValue(value){
  const v=String(value||"").trim();
  if(!v)return "";
  if(DUREES_CONTRAT.some(d=>d.value===v))return v;
  const byLabel=DUREES_CONTRAT.find(d=>d.label.toLowerCase()===v.toLowerCase());
  if(byLabel)return byLabel.value;
  const days=v.match(/^(\d+)\s*j/i);
  if(days)return parseInt(days[1],10)+"d";
  const months=v.match(/^(\d+)\s*m/i);
  if(months)return parseInt(months[1],10)+"m";
  return v;
}
