function newContractClientOptions(selectedClient){
  const selected=String(selectedClient||"").trim().toLowerCase();
  const soc=typeof effectifSocieteFilter==="function"?effectifSocieteFilter():(typeof mySoc==="function"?mySoc():"");
  const seen=new Set();
  const sites=(db.sites||[]).filter(s=>s&&s.actif!==false&&(!soc||siteMatchesSociete(s,soc))).sort((a,b)=>String(a.nom||a.intitule||"").localeCompare(String(b.nom||b.intitule||""),"fr"));
  const options=sites.map(s=>{
    const siteName=String(s.nom||s.intitule||"").trim();
    const client=String(s.client||siteName||"").trim();
    if(!client)return "";
    const key=(siteName+"|"+client).toLowerCase();
    if(seen.has(key))return "";
    seen.add(key);
    const label=siteName&&siteName!==client?`${siteName} - ${client}`:client;
    const isSelected=selected&&(selected===client.toLowerCase()||selected===siteName.toLowerCase());
    return `<option value="${escapeHTML(client)}" data-site="${escapeHTML(siteName)}" data-adresse="${escapeHTML(s.adresse||"")}" data-wilaya="${escapeHTML(s.wilaya||"")}" data-commune="${escapeHTML(s.commune||"")}" ${isSelected?"selected":""}>${escapeHTML(label)}</option>`;
  }).filter(Boolean).join("");
  const custom=selected&&!options.includes("selected")?`<option value="__autre__" selected>Autre</option>`:"";
  return `<option value="">— Choisir site / client —</option>${custom}${options}<option value="__autre__">Autre</option>`;
}
function newContractClientCustomField(selectedClient){
  const selected=String(selectedClient||"").trim();
  return `<div data-new-contract-client-other class="hidden"><label class="label">Autre client</label><input class="input" name="clientAutre" value="${escapeHTML(selected)}" placeholder="Saisir le client"/></div>`;
}
function newContractPosteOptions(selectedPoste){
  const selected=String(selectedPoste||"").trim();
  const values=[...new Set([
    selected,
    ...POSTES,
    ...(db.agents||[]).flatMap(a=>[a?.fonction,a?.position,a?.posteContrat,a?.affectationCourante?.poste])
  ].map(v=>String(v||"").trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,"fr"));
  return `<option value="">— Choisir fonction —</option>${values.map(p=>`<option value="${escapeHTML(p)}" ${p===selected?"selected":""}>${escapeHTML(p)}</option>`).join("")}`;
}
