function employeeNewContractDraftFromForm(form){
  const fd=new FormData(form);
  const a=findEmployeeByRef(fd.get("agentId"));
  const dateDebut=String(fd.get("dateDebut")||today());
  const dureeContrat=normalizeContractDurationValue(fd.get("dureeContrat"))||"";
  const dateFin=String(fd.get("dateFin")||contractEndDate(dateDebut,dureeContrat));
  const salaireNet=parseMoneyInput(fd.get("salaireNet"))||0;
  const reference=String(fd.get("reference")||newContractDecisionReference(a,dateDebut));
  return {
    a,
    reference,
    title:"CONTRAT DE TRAVAIL",
    dateDecision:String(fd.get("dateDecision")||today()),
    typeContrat:cleanContractType(fd.get("typeContrat"))||"CDD",
    poste:String(fd.get("poste")||"AGENT DE PREVENTION ET DE SECURITE").trim(),
    dateDebut,
    dureeContrat,
    dateFin,
    periodeEssai:String(fd.get("periodeEssai")||"3m").trim(),
    numeroPieceIdentite:String(fd.get("numeroPieceIdentite")||"").trim(),
    nin:String(fd.get("nin")||a?.nin||"").trim(),
    adresseSite:String(fd.get("adresseSite")||"").trim(),
    wilaya:String(fd.get("wilaya")||"").trim(),
    commune:String(fd.get("commune")||"").trim(),
    client:String(fd.get("client")==="__autre__"?fd.get("clientAutre")||"":fd.get("client")||"").trim(),
    salaireNet,
    salaireLettres:String(fd.get("salaireLettres")||moneyToFrenchWords(fd.get("salaireNet"))).trim(),
    missions:String(fd.get("missions")||"").trim(),
    articleOverrides:employeeNewContractArticleOverridesFromForm(form),
    observation:String(fd.get("observation")||"").trim()
  };
}
function employeeNewContractArticleOverridesFromForm(form){
  const overrides={};
  if(!form)return overrides;
  form.querySelectorAll("[data-contract-article-text]").forEach(el=>{
    const n=String(el.dataset.article||"").trim();
    const v=String(el.value||"").trim();
    const def=String(el.dataset.defaultText||"").trim();
    if(n&&v&&v!==def)overrides[n]=v;
  });
  return overrides;
}
function contractInlineHTML(text){
  return escapeHTML(text).replace(/\*\*(.+?)\*\*/g,"<b>$1</b>");
}
function contractTextToHTML(text){
  return String(text||"").split(/\n{2,}/).map(block=>{
    const lines=block.split("\n").map(x=>x.trim()).filter(Boolean);
    if(!lines.length)return "";
    if(lines.every(l=>l.startsWith("- ")))return `<ul>${lines.map(l=>`<li>${contractInlineHTML(l.slice(2))}</li>`).join("")}</ul>`;
    return `<p>${contractInlineHTML(lines.join("\n")).replace(/\n/g,"<br>")}</p>`;
  }).join("");
}
function contractBoldValue(v){
  return `**${String(v||"—")}**`;
}
function newContractArticleDefinitions(a,d){
  const full=contractBoldValue(((a?.nom||"")+" "+(a?.prenom||"")).trim().toUpperCase()||"____________________________");
  const fonction=contractBoldValue(d.poste||"AGENT DE PREVENTION ET DE SECURITE");
  const duree=contractBoldValue(contratDureeLabel(d.dureeContrat)||"—");
  const periodeEssai=contractBoldValue(contratDureeLabel(d.periodeEssai)||"03 Mois");
  const client=contractBoldValue(d.client||"—");
  const wilaya=contractBoldValue(d.wilaya||"—");
  const commune=contractBoldValue(d.commune||"—");
  const adresseSite=contractBoldValue(d.adresseSite||"—");
  const salaire=contractBoldValue(money(d.salaireNet||0));
  const salaireLettres=contractBoldValue(d.salaireLettres||"______________________________");
  const missions=String(d.missions||"").trim();
  const missionsText=missions?contractBoldValue(missions):"";
  const missionItems=[
    "Surveiller et contrôler les accès (entrées et sorties de personnes, véhicules et marchandises).",
    "Effectuer des rondes de sécurité selon les consignes établies.",
    "Prévenir les incidents, anomalies, intrusions, actes de malveillance, incendies ou accidents.",
    "Rendre compte immédiatement à sa hiérarchie de tout événement anormal.",
    "Tenir à jour les rapports journaliers, registres et fiches de poste.",
    "Appliquer strictement les consignes du site, les procédures internes et les instructions de la Direction.",
    "Porter et entretenir correctement son uniforme et ses équipements de travail.",
    "Garantir une attitude professionnelle, courtoise et discrète en toute circonstance.",
    "Protéger la confidentialité des informations et documents du site.",
    "Participer aux formations internes et exercices de sécurité organisés par la société."
  ].map(x=>"- "+x).join("\n");
  return [
    {n:"1",title:"Article 1 - Objet du contrat",text:`Le présent contrat a pour objet l'engagement de Monsieur ${full} en qualité ${fonction} (APS).\n\nLe salarié exercera ses fonctions sous la responsabilité du Chef de Poste, du Chef de Groupe ou du Superviseur désigné par la Direction d'IRON GLOBAL SÉCURITÉ.\n\nL'intéressé exercera ses fonctions sous la responsabilité directe de la Direction Générale et du Responsable d'exploitation/opérations.`},
    {n:"2",title:"Article 2 : Cas de recours",text:`Conformément à l'article 12 de la loi n° 90-11 du 21 avril 1990, ce contrat à durée déterminée est conclu dans le cadre suivant :\n\n« Lorsque le travailleur est recruté pour l'exécution d'un contrat lié à des travaux ou prestations non renouvelables. »\n\nLe recours à ce CDD est également motivé par un surcroît temporaire d'activité.`},
    {n:"3",title:"Article 3 : Motif",text:`Ce contrat est établi afin de répondre à des besoins ponctuels, non récurrents, en lien avec l'exécution de missions contractuelles confiées par le client : ${client}.`},
    {n:"4",title:"Article 4 : Durée du contrat",text:`Le contrat est conclu pour une durée déterminée ${duree}, prenant effet à compter du ${contractBoldValue(formatDate(d.dateDebut))} et expirant le ${contractBoldValue(formatDate(d.dateFin))} sans préavis ni indemnité aucune.`},
    {n:"5",title:"Article 5 : Poste et qualification",text:`L'employé est recruté en qualité de ${fonction}, sous l'autorité fonctionnelle du responsable de l'entrepôt et du hiérarchique responsable des opérations/chef de groupe/chef de site/coordinateur.\n\nIl pourra être amené, temporairement ou ponctuellement, à accomplir d'autres tâches compatibles avec ses qualifications et ses aptitudes professionnelles.`},
    {n:"6",title:"Article 6 : Missions et attributions",text:`${full} a pour mission principale d'assurer la sécurité des personnes, des biens et des installations sur le site.${missionsText?`\n\n${missionsText}`:""}\n\nÀ ce titre, il est notamment chargé de :\n\n${missionItems}`},
    {n:"7",title:"Article 7 : Lieu de travail",text:`Le poste est basé dans la wilaya ${wilaya}, commune de ${commune}, à l'adresse ${adresseSite}, au profit du client ${client}.\n\nL'employé peut être affecté temporairement, en fonction des besoins de service, sur d'autres sites en Algérie où les clients de l'employeur sont implantés, à condition que ces affectations correspondent à son profil et à ses qualifications.\n\nLes déplacements professionnels sont considérés comme partie intégrante des fonctions confiées au salarié.`},
    {n:"8",title:"Article 8 : Période d'essai",text:`Une période d'essai de ${periodeEssai} est fixée à compter de la date de début du contrat. Pendant cette période, chacune des parties peut y mettre fin sans indemnité ni préavis.\n\nLa période d'essai peut être prolongée une fois, automatiquement, pour une durée égale, sauf si elle est jugée satisfaisante par l'employeur, auquel cas une décision écrite de confirmation sera notifiée à l'employé. Conformément à la Loi n° 90-11 du 21 avril 1990.\n\nAvant tout départ, l'employé est tenu de procéder à une passation de consignes, confirmée par un procès-verbal signé et validé par la direction générale.`},
    {n:"9",title:"Article 9 : Répartition du temps de travail",text:`Le temps de travail est organisé conformément à l'ordonnance n° 97-03, en fonction des exigences du poste, du lieu de travail, et des obligations contractuelles de l'employeur. La répartition est définie à la seule initiative de l'employeur.\n\nL'employé peut travailler soit en surface, soit en rotation.`},
    {n:"10",title:"Article 10 : Rémunération",text:`Le salarié percevra un salaire net en lettre de : ${salaireLettres}\n\nEn chiffre (${salaire}/NET/MOIS).\n\nLe salaire est soumis aux retenues légales applicables (CNAS, IRG, etc.), conformément à la législation du travail en vigueur.\n\nLes salaires seront versés entre le 10 et le 15 du mois suivant celui travaillé, sauf cas de force majeure.\n\nLe versement est effectué uniquement par virement bancaire ou postal, après remise d'un relevé d'identité bancaire ou postal. Le paiement en espèces est strictement interdit.\n\nUne fiche de paie sera mise à la disposition de l'employé, imprimée et classée dans le dossier de l'intéressé, elle ne peut être envoyé par courrier recommandé la demande écrite de ce dernier.`},
    {n:"11",title:"Article 11 : Droits de l'employé",text:"L'employé bénéficie de l'ensemble des droits prévus par la législation algérienne, notamment : rémunération pour le travail accompli ; affiliation à la sécurité sociale et à la retraite ; droit au congé annuel ; droit à l'hygiène, la sécurité et à la médecine du travail ; respect de la dignité et de l'intégrité physique et morale."},
    {n:"12",title:"Article 12 : Équipements",text:"L'entreprise fournit à l'employé les équipements nécessaires à ses missions. La remise et la restitution de ces équipements doivent faire l'objet d'une passation de consignes.\n\nEn cas de perte ou détérioration due à une négligence ou autres, l'employé s'engage à rembourser les coûts correspondants dans leur intégralité."},
    {n:"13",title:"Article 13 : Responsabilité",text:"L'employé s'engage à respecter les procédures internes et à signaler tout incident dans les délais. Il s'interdit toute participation à des conflits internes ou externes.\n\nIl lui est interdit, pendant 24 mois après la fin du contrat, de se faire recruter directement ou indirectement par le client, ses sous-traitants, partenaires ou clients finaux.\n\nL'agent est responsable du respect des consignes de sécurité et du matériel confié. En cas de négligence, vol, perte, sabotage ou détérioration, sa responsabilité pourra être engagée.\n\nLe port de l'uniforme constitue un élément obligatoire et indissociable de la fonction d'agent de sécurité/Chef de groupe au sein d'IRON GLOBAL SÉCURITÉ. Il représente l'image, la discipline et la crédibilité de l'entreprise auprès des clients et du public.\n\nL'employé doit porter l'uniforme complet et réglementaire fourni par l'entreprise pendant toute la durée de son service. L'uniforme doit être propre, bien entretenu, repassé et porté correctement.\n\nÀ la fin du contrat de travail, l'employé doit restituer l'uniforme complet et tout équipement confié en bon état. Tout élément non restitué ou endommagé sera facturé ou retenu sur le solde de tout compte."},
    {n:"14",title:"Article 14 : Confidentialité et secret professionnel",text:"L'employé s'engage à observer la plus stricte confidentialité sur toutes les informations, documents, données, procédés, méthodes, fichiers et activités dont il pourrait avoir connaissance dans le cadre de ses fonctions.\n\nIl est formellement interdit à l'employé, sans autorisation écrite préalable de la Direction Générale, de diffuser, publier, partager ou commenter sur les réseaux sociaux toute information, image, vidéo, enregistrement audio, avis ou contenu relatif à l'entreprise, à son personnel, à ses clients, à ses sites d'intervention ou à ses activités.\n\nToute infraction à ces dispositions constitue une faute professionnelle grave pouvant entraîner des sanctions disciplinaires, voire la rupture du contrat de travail. Cette obligation perdure même après la rupture du contrat."},
    {n:"15",title:"Article 15 : Clause de non-concurrence",text:"Le salarié s'engage, pendant la durée du contrat et pendant une période de vingt-quatre (24) mois après sa rupture, à ne pas travailler pour une entreprise concurrente ou collaborer avec tout client, partenaire ou personnel d'IRON GLOBAL SÉCURITÉ sans autorisation écrite de la Direction Générale.\n\nToute violation de cette clause entraînera des poursuites et le versement de dommages et intérêts à la société."},
    {n:"16",title:"Article 16 : Solde de tout compte",text:"Le solde de tout compte (STC) est établi après constat de la fin de contrat, sous réserve de la restitution de tout matériel ou document appartenant à l'entreprise et d'une passation de consignes complète.\n\nLe paiement du STC interviendra dans un délai de 45 jours suivant la fin effective de la relation de travail."},
    {n:"17",title:"Article 17 - Rupture du contrat",text:"La rupture du présent contrat interviendra à l'expiration de la période convenue, ou selon les dispositions des articles 66 à 73 de la Loi 90-11 relative aux relations de travail. En cas de faute grave, le contrat pourra être résilié sans préavis ni indemnité."},
    {n:"18",title:"Article 18 : Préavis",text:"En cas de rupture anticipée, les préavis suivants doivent être respectés : 30 jours entre la fin de la période d'essai et le 6e mois d'activité inclus ; 60 jours à partir du 7e mois d'activité. Tout manquement à ces délais sera considéré comme un abandon de poste, aux torts exclusifs de l'employé."},
    {n:"19",title:"Article 19 : Litiges",text:"Tout différend relatif à l'exécution du présent contrat sera d'abord soumis à une tentative de règlement amiable. En cas d'échec, le litige sera porté devant le Tribunal de Bir Mourad Raïs."},
    {n:"20",title:"Article 20 : Protection des Données à Caractère Personnel loi n° 18-07",text:"Conformément à la loi n° 18-07 relative à la protection des données à caractère personnel en Algérie, l'Employeur s'engage à traiter les données personnelles de l'Employé avec la plus grande confidentialité et à respecter strictement les dispositions légales en vigueur.\n\nL'Employé est informé qu'il dispose d'un droit d'accès, de rectification, et de suppression des données le concernant, ainsi que d'un droit d'opposition au traitement de ces données, dans les conditions prévues par la loi."},
    {n:"21",title:"Article 21 : Prévention et dépistage de la consommation de stupéfiants",text:"L'employé est tenu de s'abstenir de toute consommation de substances classées comme stupéfiants ou psychotropes. L'employeur se réserve le droit d'exiger, lors du recrutement ou en cours de relation de travail, un test de dépistage effectué par un organisme habilité.\n\nTout refus injustifié de se soumettre aux tests, ou tout résultat positif avéré, pourra entraîner des mesures disciplinaires conformément à la réglementation en vigueur et au règlement intérieur de l'entreprise."},
    {n:"22",title:"Article 22 : Approbation",text:"L'employé soussigné, déclare avoir lu, compris et accepter, sans réserve, les termes de son contrat de travail ainsi que l'ensemble des dispositions du Règlement Intérieur.\n\nLe présent contrat est établi en deux exemplaires."}
  ];
}
function newContractArticlesHTML(a,d){
  const overrides=d.articleOverrides||{};
  return newContractArticleDefinitions(a,d).map(def=>{
    const custom=String(overrides[def.n]||"").trim();
    const text=custom||def.text;
    return `<section class="aps-article"><h3>${escapeHTML(def.title)}</h3>${contractTextToHTML(text)}</section>`;
  }).join("");
}
function apsContractDocumentHTML(a,d){
  const nom=escapeHTML(String(a?.nom||"").toUpperCase());
  const prenom=escapeHTML(String(a?.prenom||"").toUpperCase());
  const full=escapeHTML(((a?.nom||"")+" "+(a?.prenom||"")).trim().toUpperCase()||"____________________________");
  const soc=escapeHTML(a?.societe||"IRON GLOBAL SÉCURITÉ");
  const adresse=escapeHTML(a?.adresse||"_____________________________");
  const birth=`${formatDate(a?.dateNaissance)} à ${escapeHTML(a?.lieuNaissance||"__________")}`;
  const pieceIdentite=escapeHTML(d.numeroPieceIdentite||a?.numeroPieceIdentite||a?.pieceIdentiteNumero||"_____________");
  const nin=escapeHTML(d.nin||a?.nin||"_____________");
  const cnas=escapeHTML(a?.numeroCnas||"");
  const salaire=money(d.salaireNet||0);
  const salaireLettres=escapeHTML(d.salaireLettres||"______________________________");
  const fonction=escapeHTML(d.poste||"AGENT DE PREVENTION ET DE SECURITE");
  const duree=escapeHTML(contratDureeLabel(d.dureeContrat)||"—");
  const periodeEssai=escapeHTML(contratDureeLabel(d.periodeEssai)||"03 Mois");
  const adresseSite=escapeHTML(d.adresseSite||"—");
  const wilaya=escapeHTML(d.wilaya||"—");
  const commune=escapeHTML(d.commune||"—");
  const client=escapeHTML(d.client||"—");
  const articlesHTML=newContractArticlesHTML(a,d);
  return `<!doctype html><html><head><meta charset="utf-8"><title>${escapeHTML(d.reference||"CONTRAT APS")}</title><style>
    @page{size:A4 portrait;margin:10mm}*{box-sizing:border-box}html,body{margin:0;background:#fff;color:#111;font-family:Arial,Helvetica,sans-serif}.aps-contract{width:190mm;margin:0 auto;padding:4mm 6mm 8mm;font-size:10.8px;line-height:1.26}.aps-top{display:grid;grid-template-columns:30mm 1fr 36mm;align-items:center;border-bottom:2px solid #043970;padding-bottom:3mm;margin-bottom:5mm}.aps-logo{width:25mm;height:25mm;object-fit:contain}.aps-title{text-align:center}.aps-title h1{margin:0;font-size:19px;color:#043970;letter-spacing:.3px}.aps-title div{font-size:10px;color:#334155;font-weight:800;text-transform:uppercase}.aps-ref{text-align:right;font-size:9px;line-height:1.45}.aps-parties{display:grid;grid-template-columns:1fr 1fr;gap:6mm;border-top:1.5px solid #f2b705;border-bottom:1.5px solid #f2b705;padding:4mm 0;margin-bottom:4mm}.aps-party h2{font-size:12px;margin:0 0 2mm;color:#043970;text-transform:uppercase}.aps-party p{margin:0 0 1.4mm}.aps-center{text-align:center;font-size:13px;font-weight:900;margin:5mm 0;text-transform:uppercase}.aps-article{break-inside:avoid;margin:0 0 3mm;text-align:justify}.aps-article h3{font-size:11.5px;margin:0 0 1.2mm;color:#043970;text-transform:uppercase}.aps-article p{margin:0 0 1.5mm}.aps-article ul{margin:1mm 0 1.5mm 5mm;padding-left:4mm}.aps-article li{margin:.6mm 0}.aps-sign{display:grid;grid-template-columns:1fr 1fr;gap:24mm;margin-top:10mm}.aps-sign div{height:25mm;border-top:1px solid #111;text-align:center;padding-top:2mm;font-weight:900}.aps-footer{border-top:1.5px solid #f2b705;margin-top:7mm;padding-top:1.5mm;text-align:center;font-size:8.5px;color:#334155}@media print{.no-print{display:none!important}.aps-contract{width:auto;margin:0;padding:0;font-size:10.4px}.aps-article{break-inside:avoid}.aps-top{margin-top:0}}
  </style></head><body><main class="aps-contract">
    <header class="aps-top"><img class="aps-logo" src="${SGDI_IRON_LOGO_SRC}" alt="IRON GLOBAL SÉCURITÉ"><div class="aps-title"><h1>CONTRAT DE TRAVAIL</h1><div><b>${escapeHTML(d.typeContrat||"CDD")}</b> · Agent de Prévention et de Sécurité</div></div><div class="aps-ref"><b>Réf.</b> <b>${escapeHTML(d.reference||"")}</b><br><b>Date</b> <b>${formatDate(d.dateDecision||today())}</b></div></header>
    <section class="aps-parties">
      <div class="aps-party"><h2>Entre :</h2><p><b>${soc}</b></p><p>Adresse: Avenue Ahmed Sayeh Lot N°76 B Les Sources Bir Mourad Rais</p><p>Représentée par M. MERAH Athmane, agissant en qualité de gérant.</p><p>Ci-après désigné « Employeur »</p><p>D'une part,</p></div>
      <div class="aps-party"><h2>Et,</h2><p>Nom : <b>${nom}</b></p><p>Prénom : <b>${prenom}</b></p><p>Date et lieu de naissance : <b>${birth}</b></p><p>Adresse 1 : <b>${adresse}</b></p><p>N° pièce d'identité : <b>${pieceIdentite}</b></p><p>N° identité National : <b>${nin}</b>${cnas?`</p><p>N° CNAS : <b>${cnas}</b>`:""}</p><p>Ci-après désigné « Employé »</p><p>D'autre part,</p></div>
    </section>
    <div class="aps-center">Il a été convenu et arrêté ce qui suit</div>
    ${articlesHTML}
    <p style="margin-top:8mm">Fait à Alger le, <b>${formatDate(d.dateDecision||today())}</b></p>
    <div class="aps-sign"><div id="aps-employee-sign-box">L'employé<div id="aps-employee-signature-output" style="height:24mm;margin:1.5mm 0"></div><div>(${full})</div></div><div>La Direction des Ressources Humaines</div></div>
    <footer class="aps-footer">Adresse : N° 76, boulevard Ahmed Sayeh, Cité les Sources, Bir Mourad Rais Alger · Contact : STD : +213 770 112 034</footer>
  </main></body></html>`;
}
function employeeContractReviewControlsHTML(){
  return `<section class="no-print" style="position:sticky;top:0;z-index:50;background:#fff;border-bottom:1px solid #dbe3ef;box-shadow:0 8px 24px rgba(15,23,42,.12);padding:12px 18px;font-family:Arial,Helvetica,sans-serif">
    <div style="max-width:980px;margin:0 auto;display:grid;gap:10px">
      <label style="display:flex;gap:10px;align-items:flex-start;font-size:13px;color:#0f172a;line-height:1.4"><input id="aps-accept-contract" type="checkbox" style="width:18px;height:18px;margin-top:1px"> <span>Je déclare sur mon honneur avoir lu et compris l'ensemble des articles du contrat et m'engage à le respecter scrupuleusement.</span></label>
      <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
        <button id="aps-sign-contract" disabled style="border:0;border-radius:8px;background:#043970;color:#fff;padding:9px 14px;font-weight:800;cursor:pointer;opacity:.45">Signer contrat</button>
        <button id="aps-validate-contract" disabled style="border:0;border-radius:8px;background:#043970;color:#fff;padding:9px 14px;font-weight:800;cursor:pointer;opacity:.45">Valider contrat</button>
        <button id="aps-print-contract" disabled style="border:0;border-radius:8px;background:#047857;color:#fff;padding:9px 14px;font-weight:800;cursor:pointer;opacity:.45">Imprimer le contrat</button>
        <button id="aps-close-contract" type="button" style="border:1px solid #cbd5e1;border-radius:8px;background:#fff;color:#0f172a;padding:9px 14px;font-weight:800;cursor:pointer">Fermer</button>
        <span id="aps-contract-state" style="font-size:12px;color:#64748b">Lecture du contrat en attente.</span>
      </div>
      <div id="aps-signature-panel" hidden style="border:1px solid #cbd5e1;border-radius:10px;padding:14px;background:#f8fafc">
        <div style="font-weight:900;color:#043970;margin-bottom:6px">Signature de l'employé</div>
        <canvas id="aps-signature-canvas" style="width:100%;height:240px;background:#fff;border:1px dashed #94a3b8;border-radius:8px;touch-action:none;display:block"></canvas>
        <div style="display:flex;gap:8px;align-items:center;margin-top:8px;flex-wrap:wrap"><button id="aps-clear-signature" type="button" style="border:1px solid #cbd5e1;border-radius:8px;background:#fff;padding:7px 11px;font-weight:700">Effacer signature</button><button id="aps-confirm-signature" type="button" disabled style="border:0;border-radius:8px;background:#047857;color:#fff;padding:8px 13px;font-weight:800;cursor:pointer;opacity:.45">Valider signature</button><span id="aps-signature-state" style="font-size:12px;color:#64748b">Signez avec le doigt, stylet ou souris.</span></div>
      </div>
    </div>
  </section>`;
}
function employeeContractReviewScript(){
  return `<script>
  (function(){
    const accept=document.getElementById("aps-accept-contract");
    const signBtn=document.getElementById("aps-sign-contract");
    const validate=document.getElementById("aps-validate-contract");
    const printBtn=document.getElementById("aps-print-contract");
    const closeBtn=document.getElementById("aps-close-contract");
    const state=document.getElementById("aps-contract-state");
    const panel=document.getElementById("aps-signature-panel");
    const canvas=document.getElementById("aps-signature-canvas");
    const clear=document.getElementById("aps-clear-signature");
    const confirmSignature=document.getElementById("aps-confirm-signature");
    const signState=document.getElementById("aps-signature-state");
    const output=document.getElementById("aps-employee-signature-output");
    const ctx=canvas.getContext("2d");
    let drawing=false,last=null,signed=false,signatureValidated=false,archived=false;
    function setBtn(btn,on){if(!btn)return;btn.disabled=!on;btn.style.opacity=on?"1":".45";}
    function statusBox(text,ok){
      let box=document.getElementById("aps-contract-status-box");
      if(!box){box=document.createElement("div");box.id="aps-contract-status-box";box.className="no-print";box.style.cssText="position:fixed;inset:0;z-index:9999;background:rgba(15,23,42,.38);display:flex;align-items:center;justify-content:center;font-family:Arial,Helvetica,sans-serif";box.innerHTML='<div id="aps-contract-status-inner" style="background:#fff;border-radius:14px;box-shadow:0 24px 80px rgba(15,23,42,.28);padding:28px 34px;min-width:320px;text-align:center;font-size:18px;font-weight:900;color:#043970"></div>';document.body.appendChild(box);}
      const inner=document.getElementById("aps-contract-status-inner");
      if(inner){inner.textContent=text;inner.style.color=ok?"#047857":"#043970";}
      box.style.display="flex";
      if(ok)setTimeout(()=>{box.style.display="none"},1400);
    }
    function sizeCanvas(){
      const r=canvas.getBoundingClientRect(), ratio=Math.max(window.devicePixelRatio||1,1);
      canvas.width=Math.max(1,Math.floor(r.width*ratio));canvas.height=Math.max(1,Math.floor(r.height*ratio));
      ctx.setTransform(ratio,0,0,ratio,0,0);ctx.lineWidth=2.8;ctx.lineCap="round";ctx.lineJoin="round";ctx.strokeStyle="#0f172a";ctx.fillStyle="#fff";ctx.fillRect(0,0,r.width,r.height);
    }
    function point(e){const r=canvas.getBoundingClientRect();return{x:e.clientX-r.left,y:e.clientY-r.top};}
    function finishSignature(){
      signed=true;
      const data=canvas.toDataURL("image/png");
      if(output)output.innerHTML='<img src="'+data+'" style="max-width:60mm;max-height:23mm;object-fit:contain;display:block;margin:0 auto">';
      setBtn(confirmSignature,true);
      setBtn(validate,false);
      setBtn(printBtn,false);
      state.textContent="Signature saisie. Cliquez sur Valider signature.";
      signState.textContent="Signature enregistrée.";
      signState.style.color="#047857";
    }
    accept.addEventListener("change",()=>{setBtn(signBtn,accept.checked);setBtn(validate,false);state.textContent=accept.checked?"Cliquez sur Signer contrat.":"Lecture du contrat en attente.";});
    signBtn.addEventListener("click",()=>{panel.hidden=false;accept.disabled=true;setBtn(signBtn,false);state.textContent="Signez dans l'espace de signature.";setTimeout(sizeCanvas,50);});
    confirmSignature.addEventListener("click",()=>{
      if(!signed)return;
      signatureValidated=true;
      setBtn(confirmSignature,false);
      setBtn(validate,true);
      state.textContent="Signature validée. Cliquez sur Valider contrat pour enregistrer.";
      signState.textContent="Signature validée.";
      signState.style.color="#047857";
    });
    validate.addEventListener("click",async()=>{
      if(!signatureValidated){state.textContent="Validez d'abord la signature.";state.style.color="#dc2626";return;}
      setBtn(validate,false);state.textContent="Contrat en cours d'enregistrement...";state.style.color="#64748b";statusBox("Contrat en cours d'enregistrement");
      let ok=false;try{if(window.opener&&window.opener.saveAndArchiveEmployeeContractFromWindow)ok=await window.opener.saveAndArchiveEmployeeContractFromWindow(window,window.SGDI_ARCHIVE_META||{});}catch(e){console.error(e)}
      if(!ok){setBtn(validate,true);state.textContent="Enregistrement impossible. Vérifiez la session serveur puis réessayez.";state.style.color="#dc2626";const box=document.getElementById("aps-contract-status-box");if(box)box.style.display="none";return;}
      archived=true;setBtn(printBtn,true);state.textContent="Contrat enregistré. Vous pouvez imprimer.";state.style.color="#047857";statusBox("Contrat enregistré",true);
    });
    canvas.addEventListener("pointerdown",e=>{drawing=true;last=point(e);canvas.setPointerCapture(e.pointerId);});
    canvas.addEventListener("pointermove",e=>{if(!drawing||!last)return;const p=point(e);ctx.beginPath();ctx.moveTo(last.x,last.y);ctx.lineTo(p.x,p.y);ctx.stroke();last=p;});
    canvas.addEventListener("pointerup",e=>{if(drawing){drawing=false;last=null;finishSignature();}try{canvas.releasePointerCapture(e.pointerId)}catch(_e){}});
    canvas.addEventListener("pointerleave",()=>{if(drawing){drawing=false;last=null;finishSignature();}});
    clear.addEventListener("click",()=>{sizeCanvas();signed=false;signatureValidated=false;archived=false;if(output)output.innerHTML="";setBtn(confirmSignature,false);setBtn(validate,false);setBtn(printBtn,false);signState.textContent="Signez avec le doigt, stylet ou souris.";signState.style.color="#64748b";state.textContent="Signature effacée. Signez à nouveau puis validez la signature.";state.style.color="#64748b";});
    printBtn.addEventListener("click",()=>{if(!signed||!archived)return;window.print();state.textContent="Impression du contrat lancée.";state.style.color="#047857";});
    if(closeBtn)closeBtn.addEventListener("click",()=>window.close());
    setBtn(signBtn,false);setBtn(confirmSignature,false);setBtn(validate,false);setBtn(printBtn,false);
  })();
  </script>`;
}
