  const html=apsContractDocumentHTML(a,draft)
    .replace("<body>","<body><script>window.SGDI_ARCHIVE_META="+JSON.stringify(archiveMeta).replace(/<\//g,"<\\/")+";<\/script>"+employeeContractReviewControlsHTML())
