function toggleNewContractArticlesEditor(button){
  const form=button?.form||document.getElementById("employee-new-contract-form");if(!form)return;
  const host=document.getElementById("new-contract-articles-editor");if(!host)return;
  if(host.dataset.loaded==="1"){
    host.classList.toggle("hidden");
    button.textContent=host.classList.contains("hidden")?"Modifier les articles du contrat":"Masquer les articles";
    return;
  }
  const draft=employeeNewContractDraftFromForm(form);
  if(!draft.a){toast("Employé introuvable","error");return}
  const defs=newContractArticleDefinitions(draft.a,draft);
  host.innerHTML=`<div class="section-banner banner-amber mb-3">Articles personnalisables du contrat</div>
    <div class="text-xs text-slate-500 mb-3">Les modifications concernent uniquement ce contrat. Un article laissé inchangé garde le texte standard.</div>
    <div class="grid grid-cols-1 gap-3">${defs.map(def=>`<details class="card p-3" data-contract-article-box="${escapeHTML(def.n)}"><summary class="font-bold cursor-pointer">${escapeHTML(def.title)}</summary>
      <textarea class="textarea mt-3" rows="7" name="article_${escapeHTML(def.n)}" data-contract-article-text data-article="${escapeHTML(def.n)}" data-default-text="${escapeHTML(def.text)}">${escapeHTML(def.text)}</textarea>
      <div class="flex justify-end gap-2 mt-2"><button type="button" class="btn btn-ghost text-xs" onclick="resetNewContractArticle('${escapeHTML(def.n)}')">Réinitialiser l'article</button></div>
    </details>`).join("")}</div>`;
  host.dataset.loaded="1";
  host.classList.remove("hidden");
  button.textContent="Masquer les articles";
}
