function filterSuspensionEmployeeOptions(q){
  const needle=String(q||"").trim().toLowerCase();
  const select=document.getElementById("suspension-agent-select");if(!select)return;
  const current=select.value;
  const list=rhEffectifActionTargets().filter(a=>{
    const text=[a.matricule,a.nom,a.prenom,a.societe,a.fonction,a.affectationCourante?.siteName].filter(Boolean).join(" ").toLowerCase();
    return !needle||text.includes(needle);
  });
  select.innerHTML=list.map(a=>{
    const label=[a.matricule||"",((a.nom||"")+" "+(a.prenom||"")).trim(),a.societe||""].filter(Boolean).join(" - ");
    return `<option value="${escapeHTML(a.id)}">${escapeHTML(label)}</option>`;
  }).join("")||`<option value="">Aucun employé trouvé</option>`;
  if(list.some(a=>String(a.id)===String(current)))select.value=current;
  else if(list[0])select.value=list[0].id;
  updateSuspensionEndDate();
}
function updateSuspensionEndDate(){
  const f=document.getElementById("employee-suspension-form");if(!f)return;
  const start=f.dateDebut.value||today();
  const days=parseInt(f.duree.value||"15",10)||15;
  const end=addDays(start,days);
  f.dateFin.value=end;
  if(f.reference)f.reference.value=suspensionDecisionReference(findEmployeeByRef(f.agentId.value),start);
  updateSuspensionConvocationState();
  const alert=f.querySelector("#suspension-alert-date");
  if(alert)alert.textContent="Alerte programmée le "+formatDate(addDays(end,-2))+" (48 heures avant la fin).";
}
function updateSuspensionConvocationState(){
  const f=document.getElementById("employee-suspension-form");if(!f)return;
  const checked=!!f.aConvoquer?.checked;
  if(f.dateConvocation){
    f.dateConvocation.disabled=!checked;
    f.dateConvocation.classList.toggle("bg-slate-50",!checked);
    if(checked&&!f.dateConvocation.value)f.dateConvocation.value=f.dateFin?.value||addDays(f.dateDebut?.value||today(),parseInt(f.duree?.value||"15",10)||15);
    if(!checked)f.dateConvocation.value="";
  }
}
function suspensionDecisionReference(a,dateDebut){
  const code=String(a?.matricule||"EMP").replace(/[^a-z0-9]/gi,"").toUpperCase()||"EMP";
  return "DEC-SUSP-"+code+"-"+String(dateDebut||today()).replaceAll("-","");
}
function employeeSuspensionDraftFromForm(form){
  const fd=new FormData(form);
  const a=findEmployeeByRef(fd.get("agentId"));
  const du=String(fd.get("dateDebut")||today());
  const duree=parseInt(fd.get("duree")||"15",10)||15;
  const au=String(fd.get("dateFin")||addDays(du,duree));
  const ref=String(fd.get("reference")||suspensionDecisionReference(a,du));
  const aConvoquer=fd.get("aConvoquer")==="on";
  const motifs=fd.getAll("motifsSuspension").map(x=>String(x||"").trim()).filter(Boolean);
  return {a,ref,du,duree,au,aConvoquer,dateConvocation:aConvoquer?String(fd.get("dateConvocation")||""):"",motifs,motif:motifs.join(" / ")};
}
