async function persistEmployeeRhDecision(a,event,options={}){
  a.gestionEvents=a.gestionEvents||[];
  a.gestionEvents.push({...event,createdAt:new Date().toISOString(),createdBy:session?.username||"DRH",source:"rh-effectif"});
  if(options.status)a.statut=options.status;
  if(options.dateSortie)a.dateSortie=options.dateSortie;
  a.updatedAt=today();
  const saved=a.backendId?await SGDI.employees.update(a.backendId,employeeApiPayload(a)):await SGDI.employees.create(employeeApiPayload(a));
  Object.assign(a,employeeFromApi(saved),a,{backendId:saved?.id||a.backendId});
}
function employeeStatusActiveEvents(a){
  const st=String(a?.statut||"").toLowerCase();
  const wanted=st==="suspendu"?"Suspension":st==="absent"?"Absence":st==="sortant"?"Fin de contrat":"";
  const evs=(a?.gestionEvents||[]).slice().sort((x,y)=>String(y.createdAt||y.du||"").localeCompare(String(x.createdAt||x.du||"")));
  return wanted?evs.filter(e=>e.type===wanted||e.statut==="en_cours"):evs.slice(0,5);
}
function openEmployeeStatusDetailModal(agentId){
  const a=findEmployeeByRef(agentId);if(!a){toast("Employé introuvable","error");return}
  const evs=employeeStatusActiveEvents(a);
  openModal(`<h3 class="font-bold text-lg mb-3">DETAIL DU STATUT</h3>
    <div class="card p-3 mb-3" style="background:#f8fafc">
      <div class="font-black uppercase">${escapeHTML(((a.nom||"")+" "+(a.prenom||"")).trim())}</div>
      <div class="text-xs text-slate-500">${escapeHTML(a.matricule||"")} · ${escapeHTML(a.societe||"")} · Statut : <b>${escapeHTML(String(a.statut||"—").toUpperCase())}</b></div>
    </div>
    <div class="overflow-auto"><table><thead><tr><th>Type</th><th>Du</th><th>Au</th><th>Motif</th><th>Observation</th><th>Réf.</th></tr></thead><tbody>
      ${evs.length?evs.map(e=>`<tr><td><span class="pill ${gestionPillClass(e.type)}">${escapeHTML(e.type||"—")}</span></td><td class="text-xs">${formatDate(e.du||e.date)}</td><td class="text-xs">${formatDate(e.au||e.dateFin)}</td><td class="text-xs">${escapeHTML(e.motif||"")}</td><td class="text-xs">${escapeHTML(e.observation||e.details||"")}</td><td class="font-mono text-xs">${escapeHTML(e.reference||"—")}</td></tr>`).join(""):`<tr><td colspan="6" class="text-center text-slate-500 p-4">Aucun détail enregistré pour ce statut.</td></tr>`}
    </tbody></table></div>
    <div class="flex justify-end mt-4"><button type="button" class="btn btn-primary" onclick="closeModal()">Fermer</button></div>`);
}
function integrationDraftFromForm(form){
  const fd=new FormData(form);
  const a=findEmployeeByRef(fd.get("agentId"));
  const dateDecision=String(fd.get("dateDecision")||today());
  const motif=String(fd.get("motif")||"").trim();
  const observation=String(fd.get("observation")||"").trim();
  const reference=String(fd.get("reference")||rhDecisionReference("INT",a,dateDecision));
  return {a,title:"DECISION D'INTEGRATION / REINTEGRATION",reference,dateDecision,dateEffet:dateDecision,motif,details:observation,motifTitle:"Motif",intro:"La Direction des Ressources Humaines confirme l'intégration ou la réintégration de l'employé(e) concerné(e) selon les éléments ci-dessous.",closing:"La présente décision met à jour la situation administrative de l'employé(e).",observation};
}
function updateIntegrationReference(){
  const f=document.getElementById("employee-integration-form");if(!f)return;
  if(f.reference)f.reference.value=rhDecisionReference("INT",findEmployeeByRef(f.agentId.value),f.dateDecision.value||today());
}
function canUserReactiverSortant(){
  const u=(db.users||[]).find(x=>x.username===session?.username);
  return !!(u&&u.peutReactiverSortant);
}
function openEmployeeIntegrationModal(agentId){
  if(!canUseEmployeeActionWorkflows()){toast("Intégration non autorisée depuis ce module","error");return}
  const _check=findEmployeeByRef(agentId);
  if(_check&&String(_check.statut||"").toLowerCase()==="sortant"&&!canUserReactiverSortant()){
    toast("Réactivation d'un employé SORTANT non autorisée. Habilitation requise (Administration → Utilisateurs).","error");return;
  }
  const selected=findEmployeeByRef(agentId)||rhEffectifActionTargets()[0];if(!selected){toast("Aucun employé disponible","error");return}
  openModal(`<div class="flex items-start justify-between gap-3 mb-3 flex-wrap"><h3 class="font-bold text-lg">REINTEGRER</h3><div style="min-width:240px"><label class="label">Référence décision</label><input class="input bg-slate-50" name="reference" form="employee-integration-form" value="${escapeHTML(rhDecisionReference("INT",selected,today()))}" readonly/></div></div>
    <form id="employee-integration-form" onsubmit="event.preventDefault();confirmEmployeeIntegration(this)">
      <div class="grid grid-cols-1 md:grid-cols-2 gap-3">
        <div class="md:col-span-2"><label class="label">Employé</label><select class="select" name="agentId" required onchange="updateIntegrationReference()">${rhDecisionEmployeeOptions(selected.id)}</select></div>
        <div><label class="label">Date</label><input class="input" type="date" name="dateDecision" value="${today()}" onchange="updateIntegrationReference()" required/></div>
        <div><label class="label">Nouveau statut</label><input class="input bg-slate-50" value="ACTIF" readonly/></div>
        <div class="md:col-span-2"><label class="label">Motif *</label><input class="input" name="motif" required placeholder="Motif de l'intégration / réintégration"/></div>
        <div class="md:col-span-2"><label class="label">Observation</label><textarea class="textarea" name="observation" rows="4"></textarea></div>
      </div>
      <div class="flex justify-end gap-2 mt-4"><button type="button" class="btn btn-ghost" onclick="closeModal()">Annuler</button><button type="button" class="btn btn-secondary" onclick="printRhDecisionWindow(integrationDraftFromForm(this.form).a,integrationDraftFromForm(this.form))">Éditer / Imprimer</button><button class="btn btn-success">Confirmer et imprimer</button></div>
    </form>`);
}
async function confirmEmployeeIntegration(form){
  const draft=integrationDraftFromForm(form);
  const a=draft.a;if(!a){toast("Employé introuvable","error");return}
  if(!draft.motif){toast("Motif obligatoire","error");return}
  const printWindow=window.open("","_blank","width=900,height=700");
  if(printWindow)printWindow.document.write(`<!doctype html><html><head><meta charset="utf-8"><title>Préparation intégration</title></head><body style="font-family:Arial;padding:24px">Préparation de la décision...</body></html>`);
  try{
    (a.gestionEvents||[]).forEach(e=>{if(e.statut==="en_cours"&&(e.type==="Suspension"||e.type==="Absence"||e.type==="Fin de contrat"))e.statut="termine"});
    if(String(a.statut||"").toLowerCase()==="sortant"){
      a.dateSortie=null;a.finRelationAt=null;a.finRelationDotationReversee=null;
      a.stcCongeReliquat=null;a.stcDeductionReforme=null;
      a.finRelationMed1SentAt=null;a.finRelationMed2SentAt=null;a.finRelationGendarmerieSentAt=null;
      a.finRelationReversementAt=null;a.finRelationReversementDate=null;
    }
    await persistEmployeeRhDecision(a,{type:"Intégration",du:draft.dateDecision,au:draft.dateDecision,motif:draft.motif,observation:draft.observation,details:draft.observation,reference:draft.reference,statut:"termine"},{status:"actif"});
  }catch(e){if(printWindow)printWindow.close();toast("Intégration non enregistrée : "+(e.message||e),"error");return}
  if(!(await saveDBAndWaitToast("Intégration non confirmée"))){if(printWindow)printWindow.close();return}
  if(printWindow)printRhDecisionWindow(a,{...draft,a},printWindow);else toast("Intégration enregistrée, mais l'impression a été bloquée","warn");
  closeModal();toast("Employé remis en statut actif","success");renderView();
}
function updateMiseEnDemeureReference(){
  const f=document.getElementById("employee-mise-form");if(!f)return;
  if(f.reference)f.reference.value=rhDecisionReference("MED",findEmployeeByRef(f.agentId.value),f.dateDecision.value||today());
}
function miseEnDemeureDraftFromForm(form){
  const fd=new FormData(form);
  const a=findEmployeeByRef(fd.get("agentId"));
  const dateDecision=String(fd.get("dateDecision")||today());
  const dateLimite=String(fd.get("dateLimite")||"");
  const motif=String(fd.get("motif")||"").trim();
  const details=String(fd.get("details")||"").trim();
  const reference=String(fd.get("reference")||rhDecisionReference("MED",a,dateDecision));
  return {a,title:"MISE EN DEMEURE",reference,dateDecision,dateEffet:dateDecision,dateLimite,motif,details,motifTitle:"Objet de la mise en demeure",intro:"La Direction des Ressources Humaines met officiellement en demeure l'employé(e) concerné(e) pour les faits indiqués ci-dessous.",closing:"L'intéressé(e) est tenu(e) de régulariser sa situation dans les délais indiqués. A défaut, des mesures disciplinaires pourront être engagées."};
}
function openEmployeeMiseEnDemeureModal(agentId){
  if(!canUseEmployeeActionWorkflows()){toast("Mise en demeure non autorisée depuis ce module","error");return}
  const selected=findEmployeeByRef(agentId)||rhEffectifActionTargets()[0];if(!selected){toast("Aucun employé disponible","error");return}
  openModal(`<div class="flex items-start justify-between gap-3 mb-3 flex-wrap"><h3 class="font-bold text-lg">MISE EN DEMEURE</h3><div style="min-width:240px"><label class="label">Référence décision</label><input class="input bg-slate-50" name="reference" form="employee-mise-form" value="${escapeHTML(rhDecisionReference("MED",selected,today()))}" readonly/></div></div>
    <form id="employee-mise-form" onsubmit="event.preventDefault();confirmEmployeeMiseEnDemeure(this)">
      <div class="grid grid-cols-1 md:grid-cols-2 gap-3">
        <div class="md:col-span-2"><label class="label">Recherche employé</label><input class="input" placeholder="Nom, prénom ou code..." oninput="filterRhDecisionEmployeeOptions(this.value,'mise-agent-select','updateMiseEnDemeureReference')"/></div>
        <div class="md:col-span-2"><label class="label">Liste des employés</label><select id="mise-agent-select" class="select" name="agentId" required onchange="updateMiseEnDemeureReference()">${rhDecisionEmployeeOptions(selected.id)}</select></div>
        <div><label class="label">Date de décision</label><input class="input" type="date" name="dateDecision" value="${today()}" onchange="updateMiseEnDemeureReference()" required/></div>
        <div><label class="label">Date limite de régularisation</label><input class="input" type="date" name="dateLimite" value="${addDays(today(),2)}"/></div>
        <div class="md:col-span-2"><label class="label">Objet / motif *</label><textarea class="textarea" name="motif" rows="3" required placeholder="Motif de la mise en demeure..."></textarea></div>
        <div class="md:col-span-2"><label class="label">Détails complémentaires</label><textarea class="textarea" name="details" rows="3"></textarea></div>
      </div>
      <div class="flex justify-end gap-2 mt-4"><button type="button" class="btn btn-ghost" onclick="closeModal()">Annuler</button><button type="button" class="btn btn-secondary" onclick="printRhDecisionWindow(miseEnDemeureDraftFromForm(this.form).a,miseEnDemeureDraftFromForm(this.form))">Éditer / Imprimer</button><button class="btn btn-primary">Confirmer et imprimer</button></div>
    </form>`);
}
async function confirmEmployeeMiseEnDemeure(form){
  const draft=miseEnDemeureDraftFromForm(form);
  const a=draft.a;if(!a){toast("Employé introuvable","error");return}
  if(!draft.motif){toast("Motif obligatoire","error");return}
  const printWindow=window.open("","_blank","width=900,height=700");
  if(printWindow)printWindow.document.write(`<!doctype html><html><head><meta charset="utf-8"><title>Préparation mise en demeure</title></head><body style="font-family:Arial;padding:24px">Préparation de la mise en demeure...</body></html>`);
  try{await persistEmployeeRhDecision(a,{type:"Mise en demeure",du:draft.dateDecision,au:draft.dateLimite,motif:draft.motif,details:draft.details,reference:draft.reference,statut:"en_cours"});}
  catch(e){if(printWindow)printWindow.close();toast("Mise en demeure non enregistrée : "+(e.message||e),"error");return}
  if(!(await saveDBAndWaitToast("Mise en demeure non confirmée"))){if(printWindow)printWindow.close();return}
  if(printWindow)printRhDecisionWindow(a,{...draft,a},printWindow);else toast("Mise en demeure enregistrée, mais l'impression a été bloquée","warn");
  closeModal();toast("Mise en demeure enregistrée","success");renderView();
}
function updateFinRelationReference(){
  const f=document.getElementById("employee-fin-form");if(!f)return;
  if(f.reference)f.reference.value=rhDecisionReference("FIN-REL",findEmployeeByRef(f.agentId.value),f.dateEffet.value||today());
}
function employeeTrialExpired(a,dateRef){
  if(!a?.dateFinEssai)return false;
  return daysBetween(String(dateRef||today()).slice(0,10),a.dateFinEssai)<0;
}
function finRelationEmployeeSummaryHTML(a){
  const trialExpired=employeeTrialExpired(a);
  const trialState=!a?.dateFinEssai?"Période d'essai non renseignée":trialExpired?"Période d'essai dépassée":"Période d'essai en cours";
  const trialClass=!a?.dateFinEssai?"pill-gray":trialExpired?"pill-red":"pill-green";
  return `<div class="md:col-span-2 rounded-lg p-4" style="border:1px solid #dbe5f2;background:#f8fafc">
    <div class="flex items-start justify-between gap-3 flex-wrap">
      <div><div class="text-[10px] uppercase font-black text-slate-500 tracking-widest">Employé concerné</div><div class="text-lg font-black uppercase">${escapeHTML(((a.nom||"")+" "+(a.prenom||"")).trim()||"—")}</div><div class="font-mono text-sm font-bold text-slate-600">${escapeHTML(a.matricule||"—")} · ${escapeHTML(a.societe||"—")}</div></div>
      <span class="pill ${trialClass}">${escapeHTML(trialState)}</span>
    </div>
    <div class="grid grid-cols-1 md:grid-cols-3 gap-3 mt-4 text-sm">
      <div><div class="text-[10px] uppercase font-black text-slate-500">Début contrat</div><div class="font-bold">${formatDate(a.dateDebutContrat||a.dateRecrutement)}</div></div>
      <div><div class="text-[10px] uppercase font-black text-slate-500">Fin période d'essai</div><div class="font-bold">${formatDate(a.dateFinEssai)}</div></div>
      <div><div class="text-[10px] uppercase font-black text-slate-500">Fin contrat</div><div class="font-bold">${employeePositionContractEndPillHTML(a)}</div></div>
    </div>
  </div>`;
}
function finRelationDraftFromForm(form){
  const fd=new FormData(form);
  const a=findEmployeeByRef(fd.get("agentId"));
  const dateDecision=String(fd.get("dateDecision")||today());
  const dateEffet=String(fd.get("dateEffet")||dateDecision);
  const motifs=[];
  const motifFinEssai=fd.get("motifFinEssai")==="on";
  if(motifFinEssai)motifs.push("Période d'essai non concluante");
  const motifLibre=String(fd.get("motifLibre")||"").trim();
  if(motifLibre)motifs.push(motifLibre);
  const motif=motifs.join(" / ");
  const details=String(fd.get("observation")||"").trim();
  const reference=String(fd.get("reference")||rhDecisionReference("FIN-REL",a,dateEffet));
  return {a,type:"fin_relation",noSignature:true,title:"DECISION DE FIN DE RELATION DE TRAVAIL",reference,dateDecision,dateEffet,motif,motifFinEssai,trialExpired:employeeTrialExpired(a,dateEffet),details,motifTitle:"Motif de la fin de relation",intro:"La Direction des Ressources Humaines notifie à l'employé(e) concerné(e) la fin de la relation de travail selon les éléments ci-dessous.",closing:"La présente décision sera portée au dossier administratif et prendra effet à la date indiquée."};
}
function showFinRelationFormMessage(form,message,type="error"){
  const box=(form||document).querySelector?.("[data-fin-relation-message]")||document.querySelector("[data-fin-relation-message]");
  if(!box){toast(message,type);return}
  box.style.display=message?"block":"none";
  box.style.borderColor=type==="error"?"#fecaca":"#bfdbfe";
  box.style.background=type==="error"?"#fef2f2":"#eff6ff";
  box.style.color=type==="error"?"#991b1b":"#1e3a8a";
  box.textContent=message||"";
}
function validateFinRelationDraft(draft,form){
  showFinRelationFormMessage(form,"");
  if(!draft.a){showFinRelationFormMessage(form,"Employé introuvable");return false}
  if(!draft.motif){showFinRelationFormMessage(form,"Motif obligatoire");return false}
  if(draft.motifFinEssai&&draft.trialExpired){
    showFinRelationFormMessage(form,"Impossible : la période d'essai est dépassée. Ce motif ne peut plus être utilisé.");
    return false;
  }
  return true;
}
function finRelationFormFromControl(control){
  return control?.form||document.getElementById("employee-fin-form");
}
function editFinRelationDraftFromControl(control){
  const form=finRelationFormFromControl(control);
  if(!form){toast("Formulaire fin de relation introuvable","error");return}
  const draft=finRelationDraftFromForm(form);
  if(!validateFinRelationDraft(draft,form))return;
  printRhDecisionWindow(draft.a,draft);
}
function confirmFinRelationFromControl(control){
  const form=finRelationFormFromControl(control);
  if(!form){toast("Formulaire fin de relation introuvable","error");return}
  confirmEmployeeFinRelation(form);
}
