async function confirmReaffectation(agentId){
  const a=db.agents.find(x=>x.id===agentId);const fd=new FormData(document.querySelector(".modal-bg form"));
  const liveAff=agentLiveAffectation(a);
  if(liveAff?.siteId){
    toast(`Employé déjà affecté au site ${liveAff.siteName||liveAff.siteId}. Affectation refusée.`,"error");
    return;
  }
  const siteId=fd.get("siteId");const site=db.sites.find(s=>s.id===siteId);
  if(!siteId||!site){toast("Choisissez un site actif","error");return}
  if(liveAff&&liveAff.siteId){a.affectationsHistorique=a.affectationsHistorique||[];a.affectationsHistorique.push({...liveAff,dateFin:fd.get("dateDebut"),motifChangement:fd.get("motifChangement")||""})}
  const groupe=fd.get("groupe")||"";
  a.affectationCourante={siteId,siteName:site?.nom,clientName:site?.client,poste:a.affectationCourante?.poste||a.fonction||"",horaire:"Mixte",groupe,dateDebut:fd.get("dateDebut")};
  const changedSites=siteSetEmployeeSingleGroup(site,agentId,groupe);
  addEmployeeCareerEvent(a,"Affectation",{
    date:fd.get("dateDebut")||today(),
    motif:`Affectation à ${site?.nom||"site non renseigné"}${groupe?` · Groupe ${groupe}`:""}`,
    source:"ops-affectation",
    sourceId:`affectation_${agentId}_${siteId}_${fd.get("dateDebut")||today()}`,
    details:{siteId,siteName:site?.nom||"",clientName:site?.client||"",groupe,poste:a.affectationCourante.poste||""}
  });
  try{
    if(a.backendId)Object.assign(a,employeeFromApi(await SGDI.employees.update(a.backendId,employeeApiPayload(a))),a,{backendId:a.backendId});
    for(const changedSite of changedSites)await persistSiteToPostgres(changedSite);
    const siteBackendId=site.backendId||sqlBackendId(site.id);
    if(a.backendId&&siteBackendId)await persistSqlAssignment(a.backendId,siteBackendId,groupe,fd.get("dateDebut")||today(),fd.get("motifChangement")||"Affectation OPS",a.affectationCourante?.poste||"");
  }catch(e){toast("Affectation non enregistrée : "+(e.message||e),"error");return}
  if(!(await saveDBAndWaitToast("Affectation non confirmée")))return;
  closeModal();toast("Affectation enregistrée","success");renderView();
}
