/* ---- MATÉRIEL & ÉQUIPEMENT ---- */
function stockFindArticleByAnyRef(ref){
  const value=String(ref||"").trim();
  if(!value)return null;
  return (db.stockArticles||[]).find(a=>
    String(a.id||"")===value||
    String(a.backendId||"")===value||
    String(a.code||"")===value||
    String(a.reference||"")===value||
    String(a.codeBarre||"")===value
  )||null;
}
function employeeLocalDotationSnapshots(agentId){
  const a=findEmployeeByRef(agentId);
  const source=[...(Array.isArray(a?.dotations)?a.dotations:[]),...(Array.isArray(a?.equipements)?a.equipements:[])];
  const seen=new Set();
  return source.filter(d=>{
    const st=String(d.statut||d.status||"attribue").toLowerCase();
    if(st&&optsActiveStatusIsReturned(st))return false;
    const key=String(d.backendId||d.equipmentBackendId||d.id||`${d.articleId||d.articleBackendId}-${d.date||d.dateDotation}-${d.quantite||d.qte}`);
    if(seen.has(key))return false;
    seen.add(key);
    return true;
  });
}
function optsActiveStatusIsReturned(status){
  return ["reverse","reversé","reversed","retourne","retourné","en_stock"].includes(String(status||"").toLowerCase());
}
function renderAgentMateriel(a,locked){
  const stockAttribs=(db.stockMouvements||[]).filter(m=>stockMvtIsOut(m.type)&&stockMovementBelongsToAgent(m,a)).slice().sort((x,y)=>(y.date||"").localeCompare(x.date||"")||(y.createdAt||"").localeCompare(x.createdAt||""));
  const allCats=[...new Set(stockAttribs.map(m=>{const art=stockFindArticleByAnyRef(m.articleId||m.articleBackendId);return art?art.categorie:"Stock"}).filter(Boolean))];
  const rows=agentDotationRows(a.id,{onlyActive:false});
  const totalValue=rows.reduce((s,r)=>s+(parseFloat(r.valeur)||0),0);
  const stockValue=totalValue;
  const canEdit=!locked||isAdmin();
  const ficheDotationBtn=isMaterielFicheContext()?`<button type="button" class="btn btn-primary text-xs" onclick="voirFicheDotation('${a.id}')">Voir fiche de dotation</button>`:"";
  return`<div class="grid grid-3 mb-3">
    <div class="bg-slate-50 p-3 rounded border border-slate-200"><div class="text-xs text-slate-500 uppercase">Articles attribués</div><div class="text-2xl font-bold mt-1">${rows.length}</div><div class="text-[11px] text-slate-500 mt-1">${rows.length} dotation(s)</div></div>
    <div class="bg-slate-50 p-3 rounded border border-slate-200"><div class="text-xs text-slate-500 uppercase">Catégories</div><div class="text-sm mt-1 flex flex-wrap gap-1">${allCats.map(c=>`<span class="pill pill-indigo">${escapeHTML(c)}</span>`).join("")||"—"}</div></div>
    <div class="bg-slate-50 p-3 rounded border border-slate-200"><div class="text-xs text-slate-500 uppercase">Valeur dotation</div><div class="text-2xl font-black mt-1">${money(totalValue)}</div><div class="text-[11px] text-slate-500 mt-1">Source PostgreSQL uniquement</div></div>
  </div>
  <div class="card p-3 mb-3">
    <div class="flex justify-between items-center mb-2 flex-wrap gap-2"><h4 class="font-bold text-sm">Détail de la dotation</h4><div class="flex gap-2 flex-wrap">${ficheDotationBtn}<a href="#/materiel/mouvements" class="text-xs text-amber-600 hover:underline">Voir mouvements →</a></div></div>
    <div class="overflow-x-auto"><table><thead><tr><th>Date dotation</th><th>Code</th><th>Article</th><th>Qté</th><th>Prix unitaire</th><th>Valeur exacte</th><th>Motif</th><th>N° bon</th><th>Date reversement</th><th>Motif reversement</th></tr></thead><tbody>${rows.length===0?`<tr><td colspan="10" class="text-center text-slate-500 p-3">Aucune dotation enregistrée.</td></tr>`:rows.map(r=>`<tr><td class="text-xs">${formatDate(r.date)}</td><td class="font-mono text-xs">${escapeHTML(r.code||"—")}</td><td>${r.articleId?`<a class="font-semibold hover:underline" href="#/materiel/article/${r.articleId}">${escapeHTML(r.article)}</a>`:`<span class="font-semibold">${escapeHTML(r.article||"—")}</span>`}<div class="text-[10px] text-slate-500">${escapeHTML(r.categorie||"—")}</div></td><td class="font-bold text-center">${qty(r.qte)} <span class="text-[10px] text-slate-400">${escapeHTML(r.unite||"")}</span></td><td class="text-right text-xs">${money(r.pu)}</td><td class="text-right font-bold">${money(r.valeur)}</td><td class="text-xs">${escapeHTML(r.motif||"—")}</td><td class="font-mono text-xs">${escapeHTML(r.bon||"—")}</td><td class="text-xs">${r.dateReversement||"—"}</td><td class="text-xs">${escapeHTML(r.motifReversement||"—")}</td></tr>`).join("")}</tbody></table></div>
  </div>`;
}
function agentDotationRows(agentId,opts){
  opts=opts||{};
  const ag=(db.agents||[]).find(x=>x.id===agentId);
  const legacy=[];
  const stockOut=(db.stockMouvements||[]).filter(m=>stockMvtIsOut(m.type)&&stockMovementBelongsToAgent(m,ag||agentId));
  const movementKeys=new Set(stockOut.map(m=>String(m.backendId||m.equipmentBackendId||m.id||"")).filter(Boolean));
  const rows=stockOut.map(m=>{
    const art=stockFindArticleByAnyRef(m.articleId||m.articleBackendId);
    const pu=parseFloat(m.prixUnitaire||art?.prixUnitaire)||0;
    const returned=(db.stockMouvements||[]).filter(r=>stockMvtIsIn(r.type)&&stockMvtIsRetourAgent(r.motif)&&r.retourAgentId===agentId&&r.articleId===m.articleId&&(!m.date||!r.date||r.date>=m.date));
    const returnedQty=returned.reduce((s,r)=>s+(parseFloat(r.quantite)||0),0);
    const initialQty=parseFloat(m.quantite)||0;
    const remaining=Math.max(0,initialQty-returnedQty);
    if(opts.onlyActive&&remaining<=0)return null;
    const q=opts.onlyActive?remaining:initialQty;
    const rep=m.repartitionTailles||{};
    const sizeDetail=dotationSizeSummary(m.taille,m.pointure);
    const detail=Object.keys(rep).length?Object.entries(rep).map(([k,v])=>`${k}: ${qty(v)}`).join(" / "):sizeDetail;
    return{date:m.date,code:art?.code||"—",article:art?.designation||"Article supprimé",categorie:art?.categorie||"Stock",articleId:m.articleId,qte:q,unite:art?.unite||"",pu,valeur:q*pu,motif:[stockMvtTypeLabel(m.type),m.motif,m.motifRenouvellement,m.motifRenouvellementPrecision].filter(Boolean).join(" · "),bon:m.numeroBon||"—",etat:m.etatArticle||"—",dateReversement:returned.map(r=>formatDate(r.date)).join(", "),motifReversement:returned.map(r=>[r.motif,qty(r.quantite)+(art?.unite?` ${art.unite}`:"")].filter(Boolean).join(" · ")).join(" / "),detail,barcodeValue:m.barcodeValue||m.codeBarreDotation||"",codeSerie:m.codeSerie||m.numeroSerie||"",modele:m.modele||art?.modele||""};
  }).filter(Boolean);
  const localRows=employeeLocalDotationSnapshots(agentId).filter(d=>{
    const key=String(d.backendId||d.equipmentBackendId||d.id||"");
    return !key||!movementKeys.has(key);
  }).map(d=>{
    const art=stockFindArticleByAnyRef(d.articleId||d.articleBackendId||d.code);
    const q=parseFloat(d.quantite||d.qte)||0;
    const pu=parseFloat(d.prixUnitaire||d.pu||art?.prixUnitaire)||0;
    const detail=Object.keys(d.repartitionTailles||{}).length?Object.entries(d.repartitionTailles).map(([k,v])=>`${k}: ${qty(v)}`).join(" / "):dotationSizeSummary(d.taille,d.pointure);
    return{date:d.date||d.dateDotation||d.createdAt||today(),code:d.codeSerie||d.code||art?.code||"—",article:d.designation||d.article||art?.designation||"Article",categorie:d.categorie||art?.categorie||"Stock",articleId:art?.id||d.articleId||"",qte:q,unite:d.unite||art?.unite||"",pu,valeur:q*pu,motif:d.motif||d.notes||"Dotation matériel",bon:d.numeroBon||d.bon||"—",etat:d.etatArticle||d.etat||"—",dateReversement:d.dateReversement||"",motifReversement:d.motifReversement||"",detail,barcodeValue:d.barcodeValue||"",codeSerie:d.codeSerie||"",modele:d.modele||art?.modele||""};
  });
  return legacy.concat(rows,localRows).sort((x,y)=>(y.date||"").localeCompare(x.date||""));
}
function sgdiQrSrc(value,size){
  const data=encodeURIComponent(String(value||"SGDI"));
  const s=size||140;
  return `https://api.qrserver.com/v1/create-qr-code/?size=${s}x${s}&margin=1&data=${data}`;
}
function sgdiQrHTML(value,size){
  return `<div class="sgdi-qr"><img src="${sgdiQrSrc(value,size||120)}" alt="QR ${escapeHTML(value||"")}" /><div class="sgdi-qr-text">${escapeHTML(value||"")}</div></div>`;
}
