/* ============ PRO STOCK MANAGEMENT ============ */
const STOCK_SOC_META={};
const STOCK_CATEGORIES={};
function stockDotationCategories(){return DOTATION_PERSONNEL_CATEGORIES.map(label=>({code:label,label,icon:"📦",color:"#043970"}))}
function stockGetCategoriesFor(soc){
  const base=(STOCK_CATEGORIES[soc]||[]).slice();
  const seen=new Set(base.map(c=>String(c.code||c.label||"").toLowerCase()));
  stockDotationCategories().forEach(c=>{if(!seen.has(c.code.toLowerCase()))base.push(c)});
  return base;
}
function stockMagasinsForCategorie(soc){
  return (db.magasins||[]).filter(m=>!soc||!m.societe||m.societe===soc).sort((a,b)=>(a.nom||"").localeCompare(b.nom||""));
}
function stockMagasinCategorieOptionsHTML(soc,selected){
  const mags=stockMagasinsForCategorie(soc);
  if(!mags.length)return `<option value="">Aucun magasin créé</option>`;
  return `<option value="">— Choisir un magasin —</option>${mags.map(m=>`<option value="${escapeHTML(m.id)}" ${String(selected||"")===String(m.id)||String(selected||"")===String(m.nom||"")?"selected":""}>${m.icon||"🏬"} ${escapeHTML(m.nom||"Magasin")}</option>`).join("")}`;
}
function stockSelectedMagasinSummaryHTML(value){
  const m=(db.magasins||[]).find(x=>String(x.id)===String(value||"")||String(x.nom||"")===String(value||""));
  if(!m)return `<span class="text-slate-400">Aucun magasin sélectionné</span>`;
  return `${m.icon||"🏬"} <b>${escapeHTML(m.nom||"Magasin")}</b>${m.societe?` · ${escapeHTML(m.societe)}`:""}`;
}
function stockGetCategorie(soc,code){
  const mag=(db.magasins||[]).find(m=>String(m.id)===String(code)||String(m.nom||"")===String(code));
  if(mag)return{code,label:mag.nom||"Magasin",icon:mag.icon||"🏬",color:mag.color||"#043970"};
  return stockGetCategoriesFor(soc).find(c=>c.code===code)||{code,label:code||"—",icon:"📦",color:"#64748b"}
}
function stockGetMouvements(articleId){
  const a=(db.stockArticles||[]).find(x=>String(x.id)===String(articleId)||String(x.backendId||"")===String(articleId));
  const refs=new Set([articleId,a?.id,a?.backendId].map(v=>String(v||"")).filter(Boolean));
  return (db.stockMouvements||[]).filter(m=>refs.has(String(m.articleId||""))||refs.has(String(m.articleBackendId||""))).sort((a,b)=>(b.date||"").localeCompare(a.date||"")||(b.createdAt||"").localeCompare(a.createdAt||""))
}
function stockMvtIsIn(t){return ["entree","achat","retour","retour_employe","retour_site","regularisation_entree"].includes(t)}
function stockMvtIsOut(t){return ["sortie","perte","casse","nouvelle_dotation","renouvellement_dotation","dotation_pret","dotation_pret_mission","reforme"].includes(t)}
function stockArticleRefs(a,extra){
  return new Set([...(extra||[]),a?.id,a?.backendId,a?.code,a?.reference,a?.codeBarre].map(v=>String(v||"")).filter(Boolean));
}
function stockFindArticleByRef(articleId){
  const ref=String(articleId||"").trim();
  if(!ref)return null;
  return (db.stockArticles||[]).find(x=>
    String(x.id||"")===ref||
    String(x.backendId||"")===ref||
    String(x.code||"")===ref||
    String(x.reference||"")===ref||
    String(x.codeBarre||"")===ref
  )||null;
}
function stockArticleInitialQty(a){
  if(!a)return 0;
  if(a.backendId&&a.stockInitial!==undefined&&a.stockInitial!==null&&a.stockInitial!=="")return parseFloat(a.stockInitial)||0;
  if(Array.isArray(a.stockReceptionsGlobales)&&a.stockReceptionsGlobales.length)return stockGlobalStockTotal(a.stockReceptionsGlobales);
  if(Array.isArray(a.stockVariantes)&&a.stockVariantes.length)return stockVariantesTotal(a.stockVariantes);
  return parseFloat(a.stockInitial)||parseFloat(a.quantiteGlobaleRecue)||0;
}
function stockGetActuel(articleId){
  const a=stockFindArticleByRef(articleId);
  if(!a)return 0;
  const refs=stockArticleRefs(a,[articleId]);
  // Filtrer uniquement les mouvements NON encore persistés en PostgreSQL (pas de backendId).
  // Les mouvements persistés sont déjà inclus dans stockInitial (backend maintient article.quantity).
  const mvts=(db.stockMouvements||[]).filter(m=>
    (refs.has(String(m.articleId||""))||refs.has(String(m.articleBackendId||"")))
    &&!m.backendId
  );
  let q=stockArticleInitialQty(a);
  mvts.forEach(m=>{
    const v=parseFloat(m.quantite)||0;
    if(stockMvtIsIn(m.type))q+=v;
    else if(stockMvtIsOut(m.type))q-=v;
    else if(m.type==="ajustement")q=v;
  });
  return q;
}
function stockGetValeur(articleId){
  const a=(db.stockArticles||[]).find(x=>x.id===articleId);
  if(!a)return 0;
  return stockGetActuel(articleId)*(parseFloat(a.prixUnitaire)||0);
}
function stockGetEtat(article){
  const q=stockGetActuel(article.id);
  const seuil=parseFloat(article.seuilAlerte)||0;
  const min=parseFloat(article.stockMin)||0;
  if(q<=0)return{code:"rupture",label:"Rupture",color:"#dc2626",bg:"#fef2f2"};
  if(seuil>0&&q<=seuil)return{code:"alerte",label:"Stock bas",color:"#043970",bg:"#043970"};
  if(min>0&&q<min)return{code:"min",label:"Sous minimum",color:"#ca8a04",bg:"#fefce8"};
  return{code:"ok",label:"OK",color:"#16a34a",bg:"#043970"};
}
function stockGetSocFilter(){return session?.transverse?currentStructureSocieteFilter():(sessionStorage.getItem("mtSociete")||"")}
function stockArticlesFiltered(){
  const soc=stockGetSocFilter();
  let arts=(db.stockArticles||[]).slice();
  if(soc)arts=arts.filter(a=>a.societe===soc);
  return arts;
}
function stockMouvementsFiltered(){
  const soc=stockGetSocFilter();
  const arts=stockArticlesFiltered();
  const ids=new Set(arts.flatMap(a=>[a.id,a.backendId,a.code,a.reference,a.codeBarre]).map(v=>String(v||"")).filter(Boolean));
  let mvts=(db.stockMouvements||[]).slice();
  if(soc)mvts=mvts.filter(m=>ids.has(String(m.articleId||""))||ids.has(String(m.articleBackendId||"")));
  return mvts.sort((a,b)=>(b.date||"").localeCompare(a.date||"")||(b.createdAt||"").localeCompare(a.createdAt||""));
}
function stockNextCode(soc,catCode){
  const prefSoc=(soc||"GEN").split(" ").map(s=>s[0]||"").join("").substring(0,3).toUpperCase();
  const mag=(db.magasins||[]).find(m=>String(m.id)===String(catCode||"")||String(m.nom||"")===String(catCode||""));
  const c=String(mag?.nom||catCode||"GEN").replace(/[^A-Za-z0-9]/g,"").substring(0,3).toUpperCase()||"GEN";
  const prefix=`${prefSoc}-${c}-`;
  const used=(db.stockArticles||[]).map(a=>String(a.code||"")).filter(code=>code.startsWith(prefix));
  const max=used.reduce((n,code)=>{
    const m=code.slice(prefix.length).match(/^(\d+)/);
    return m?Math.max(n,parseInt(m[1],10)||0):n;
  },0);
  return `${prefix}${String(max+1).padStart(4,"0")}`;
}
function stockMonthRange(){const d=new Date();const start=new Date(d.getFullYear(),d.getMonth(),1).toISOString().slice(0,10);const end=d.toISOString().slice(0,10);return{start,end}}
function stockSummaryKPI(){
  const arts=stockArticlesFiltered();
  const mvts=stockMouvementsFiltered();
  const totalArticles=arts.length;
  let totalUnites=0,valeurTotale=0,enRupture=0,enAlerte=0,actifs=0;
  arts.forEach(a=>{
    const q=stockGetActuel(a.id);
    totalUnites+=q;
    valeurTotale+=q*(parseFloat(a.prixUnitaire)||0);
    const e=stockGetEtat(a);
    if(e.code==="rupture")enRupture++;
    else if(e.code==="alerte"||e.code==="min")enAlerte++;
    if(q>0)actifs++;
  });
  const {start}=stockMonthRange();
  const mvtMois=mvts.filter(m=>(m.date||"")>=start);
  const entreesMois=mvtMois.filter(m=>stockMvtIsIn(m.type)).reduce((s,m)=>s+(parseFloat(m.quantite)||0),0);
  const sortiesMois=mvtMois.filter(m=>stockMvtIsOut(m.type)).reduce((s,m)=>s+(parseFloat(m.quantite)||0),0);
  const valEntrees=mvtMois.filter(m=>m.type==="entree").reduce((s,m)=>s+((parseFloat(m.quantite)||0)*(parseFloat(m.prixUnitaire)||0)),0);
  const valSorties=mvtMois.filter(m=>stockMvtIsOut(m.type)).reduce((s,m)=>s+((parseFloat(m.quantite)||0)*(parseFloat(m.prixUnitaire)||0)),0);
  return{totalArticles,totalUnites,valeurTotale,enRupture,enAlerte,actifs,entreesMois,sortiesMois,valEntrees,valSorties};
}
function stockMvtTypeLabel(t){return{entree:"Entrée",achat:"Nouvelle acquisition",retour:"Retour employé",retour_employe:"Reversement employé",retour_site:"Reversement site",regularisation_entree:"Régularisation entrée",sortie:"Sortie",perte:"Perte",casse:"Casse",ajustement:"Ajustement",nouvelle_dotation:"Nouvelle dotation",renouvellement_dotation:"Renouvellement de dotation",dotation_pret:"Dotation à titre de prêt (mission)",reforme:"Réformer"}[t]||t}
function stockMvtTypeColor(t){return{entree:"#16a34a",achat:"#16a34a",retour:"#043970",retour_employe:"#043970",retour_site:"#043970",regularisation_entree:"#16a34a",sortie:"#dc2626",perte:"#043970",casse:"#7c2d12",ajustement:"#7c3aed",nouvelle_dotation:"#dc2626",renouvellement_dotation:"#043970",dotation_pret:"#7c3aed",reforme:"#475569"}[t]||"#64748b"}
function stockMvtTypeIcon(t){return ""}

