function stockExportCSV(){
  const arts=stockArticlesFiltered();
  if(arts.length===0){toast("Aucun article à exporter","error");return}
  const rows=[["Code","Désignation","Société","Catégorie","Sous-catégorie","Marque","Modèle","Référence","Code-barre","Unité","Prix unitaire","Stock initial","Stock actuel","Stock min","Stock max","Seuil alerte","Emplacement","Fournisseur","État"]];
  arts.forEach(a=>{
    const cat=stockGetCategorie(a.societe,a.categorie);
    const q=stockGetActuel(a.id);
    const etat=stockGetEtat(a);
    rows.push([a.code,a.designation,a.societe,cat.label,a.sousCategorie,a.marque,a.modele,a.reference,a.codeBarre,a.unite,a.prixUnitaire,a.stockInitial,q,a.stockMin,a.stockMax,a.seuilAlerte,a.emplacement,a.fournisseur,etat.label]);
  });
  const csv=rows.map(r=>r.map(c=>{const s=String(c==null?"":c);return /[",;\n]/.test(s)?'"'+s.replace(/"/g,'""')+'"':s}).join(";")).join("\n");
  const blob=new Blob(["\ufeff"+csv],{type:"text/csv;charset=utf-8"});
  const url=URL.createObjectURL(blob);
  const a=document.createElement("a");
  a.href=url;a.download="catalogue-stock-"+today()+".csv";a.click();
  URL.revokeObjectURL(url);
  toast("Export CSV téléchargé","success");
}

/* ---- PAIE ---- */
function defaultPaieConfig(){return{snmg:24000,heuresMois:173.33,tauxCnasSalarie:9,tauxCnasPatronal:25,tauxOeuvresSociales:0.5,abattementIRG:40,abattementMinMensuel:1000,abattementMaxMensuel:1500,primeNuit:3000,primePanier:0,primeTransport:0,optimisationPanierMax:0,optimisationTransportMax:0,retenueAbsenceJour:0}}
function paieConfig(){
  if(!db.paieConfig)db.paieConfig=defaultPaieConfig();
  db.paieConfig={...defaultPaieConfig(),...db.paieConfig};
  if(Number(db.paieConfig.abattementMaxMensuel||0)>10000)db.paieConfig.abattementMaxMensuel=1500;
  if(!("tauxOeuvresSociales" in db.paieConfig))db.paieConfig.tauxOeuvresSociales=0.5;
  return db.paieConfig;
}
function defaultPaieRubriques(){
  return [
    {id:"rub_base",code:"BASE",libelle:"Salaire de base",type:"gain",imposable:true,cotisable:true,system:true,actif:true},
    {id:"rub_prime_nuit",code:"PN",libelle:"Prime de nuit",type:"gain",imposable:true,cotisable:true,system:true,actif:true},
    {id:"rub_prime_panier",code:"PANIER",libelle:"Prime panier",type:"gain",imposable:false,cotisable:false,system:true,actif:true},
    {id:"rub_prime_transport",code:"TRANS",libelle:"Prime transport",type:"gain",imposable:false,cotisable:false,system:true,actif:true},
    {id:"rub_panier_variable",code:"PANIER_VAR",libelle:"Prime panier variable",type:"gain",imposable:false,cotisable:false,system:false,actif:true},
    {id:"rub_transport_variable",code:"TRANS_VAR",libelle:"Prime transport variable",type:"gain",imposable:false,cotisable:false,system:false,actif:true},
    {id:"rub_absence",code:"ABS",libelle:"Retenue absence",type:"retenue",imposable:false,cotisable:false,system:true,actif:true},
    {id:"rub_avance",code:"AVS",libelle:"Avance sur salaire",type:"retenue",imposable:false,cotisable:false,system:false,actif:true},
    {id:"rub_rappel",code:"RAPPEL",libelle:"Rappel salaire",type:"gain",imposable:true,cotisable:true,system:false,actif:true},
    {id:"rub_prime_exceptionnelle",code:"PRIME",libelle:"Prime exceptionnelle",type:"gain",imposable:true,cotisable:true,system:false,actif:true}
  ];
}
function paieEnsure(){
  if(!Array.isArray(db.paieRubriques))db.paieRubriques=[];
  if(!Array.isArray(db.paieElements))db.paieElements=[];
  if(!Array.isArray(db.paieBulletins))db.paieBulletins=[];
  if(!Array.isArray(db.paieClotures))db.paieClotures=[];
  if(!Array.isArray(db.paieGrilles))db.paieGrilles=[];
  defaultPaieRubriques().forEach(r=>{if(!db.paieRubriques.some(x=>x.id===r.id||x.code===r.code))db.paieRubriques.push({...r})});
}
function paieAgentFonction(a){return normalizePosteValue(a?.fonction||a?.poste||a?.affectationCourante?.poste||a?.posteContrat||"Non précisé")}
function paieGrilleForAgent(a){
  paieEnsure();
  const fn=paieAgentFonction(a);
  return (db.paieGrilles||[]).find(g=>String(g.fonction||"").toLowerCase()===String(fn||"").toLowerCase()&&(!g.societe||!a?.societe||g.societe===a.societe))||
    (db.paieGrilles||[]).find(g=>String(g.fonction||"").toLowerCase()===String(fn||"").toLowerCase())||null;
}
function paieGrilleBounds(a){
  const cfg=paieConfig();
  const g=paieGrilleForAgent(a);
  return{fonction:paieAgentFonction(a),grille:g,min:Math.max(Number(cfg.snmg||0),Number(g?.min||0)||0),max:Number(g?.max||0)||0,reference:Number(g?.reference||0)||0};
}
function paieIsClosed(ym,societe){
  paieEnsure();
  return (db.paieClotures||[]).some(c=>c.ym===ym&&(!societe||c.societe===societe||c.societe===""));
}
function paieClosedInfo(ym,societe){
  paieEnsure();
  return (db.paieClotures||[]).find(c=>c.ym===ym&&(!societe||c.societe===societe||c.societe===""))||null;
}
function paieElementsFor(agentId,ym){
  paieEnsure();
  return (db.paieElements||[]).filter(e=>e.agentId===agentId&&e.ym===ym);
}
function paieBulletinFor(agentId,ym){
  paieEnsure();
  return (db.paieBulletins||[]).find(b=>b.agentId===agentId&&b.ym===ym)||null;
}
function paieCalcForAgent(a,ym){
  const b=paieBulletinFor(a.id,ym);
  if(b&&b.calcul)return b.calcul;
  return calcPaieAgent(a,ym);
}
function irgBaremeMensuel(base){
  const b=Math.max(0,Number(base)||0);
  let irg=0;
  if(b>20000)irg+=(Math.min(b,40000)-20000)*0.23;
  if(b>40000)irg+=(Math.min(b,80000)-40000)*0.27;
  if(b>80000)irg+=(Math.min(b,160000)-80000)*0.30;
  if(b>160000)irg+=(Math.min(b,320000)-160000)*0.33;
  if(b>320000)irg+=(b-320000)*0.35;
  return Math.max(0,Math.round(irg));
}
function irgSalaireAlgerie(netImposable,cfg){
  const base=Math.max(0,Number(netImposable)||0);
  if(base<=30000)return{irgBrut:0,abattement:0,irg:0,formule:"Exonération <= 30 000 DA"};
  const irgBrut=irgBaremeMensuel(base);
  const taux=Number(cfg.abattementIRG||0)/100;
  const abattement=Math.min(irgBrut,Math.min(Math.max(irgBrut*taux,Number(cfg.abattementMinMensuel||0)),Number(cfg.abattementMaxMensuel||0)));
  let irgApres=Math.max(0,irgBrut-abattement);
  let formule="Barème progressif + abattement IRG";
  if(base>30000&&base<35000){
    irgApres=Math.max(0,(irgApres*(137/51))-(27925/8));
    formule="Formule spéciale 30 001 - 35 000 DA";
  }
  return{irgBrut,abattement,irg:Math.round(irgApres),formule};
}
function calcPaieAgent(a,ym){
  const cfg=paieConfig();
  paieEnsure();
  const salaireNetContractuel=Number(a.salaireNet||0)||0;
  const brutBase=paieBaseBruteForAgent(a);
  const primeNuit=a.affectationCourante?.horaire==="Nuit"?Number(cfg.primeNuit||0):0;
  const fixedElements=[
    {code:"BASE",libelle:"Salaire de base",type:"gain",imposable:true,cotisable:true,montant:brutBase},
    {code:"PN",libelle:"Prime de nuit",type:"gain",imposable:true,cotisable:true,montant:primeNuit},
    {code:"PANIER",libelle:"Prime panier",type:"gain",imposable:false,cotisable:false,montant:Number(cfg.primePanier||0)},
    {code:"TRANS",libelle:"Prime transport",type:"gain",imposable:false,cotisable:false,montant:Number(cfg.primeTransport||0)}
  ].filter(x=>Number(x.montant||0)>0);
  const variableElements=paieElementsFor(a.id,ym||sessionStorage.getItem("paieMois")||today().slice(0,7)).map(e=>{
    const r=(db.paieRubriques||[]).find(x=>x.id===e.rubriqueId)||{};
    return{code:r.code||"",libelle:r.libelle||"Rubrique",type:r.type||"gain",imposable:r.imposable!==false,cotisable:r.cotisable!==false,montant:Number(e.montant||0),note:e.note||""};
  }).filter(x=>x.montant>0);
  const elements=[...fixedElements,...variableElements];
  const gains=elements.filter(e=>e.type!=="retenue").reduce((s,e)=>s+e.montant,0);
  const primes=Math.max(0,gains-brutBase);
  const retenuesRubriques=elements.filter(e=>e.type==="retenue").reduce((s,e)=>s+e.montant,0);
  const gainsCotisables=elements.filter(e=>e.type!=="retenue"&&e.cotisable!==false).reduce((s,e)=>s+e.montant,0);
  const retenuesCotisables=elements.filter(e=>e.type==="retenue"&&e.cotisable!==false).reduce((s,e)=>s+e.montant,0);
  const gainsNonCotisablesImposables=elements.filter(e=>e.type!=="retenue"&&e.cotisable===false&&e.imposable!==false).reduce((s,e)=>s+e.montant,0);
  const gainsNonCotisablesNonImposables=elements.filter(e=>e.type!=="retenue"&&e.cotisable===false&&e.imposable===false).reduce((s,e)=>s+e.montant,0);
  const brutCotisable=Math.max(0,gainsCotisables-retenuesCotisables);
  const cnasSalarie=Math.round(brutCotisable*(Number(cfg.tauxCnasSalarie||0)/100));
  const netSocial=Math.max(0,brutCotisable-cnasSalarie+gainsNonCotisablesImposables);
  const baseIRG=netSocial;
  const irgCalc=irgSalaireAlgerie(baseIRG,cfg);
  const abat=irgCalc.abattement;
  const irg=irgCalc.irg;
  const netAPayer=Math.max(0,netSocial-irg+gainsNonCotisablesNonImposables-retenuesRubriques);
  const cnasPatronal=Math.round(brutCotisable*(Number(cfg.tauxCnasPatronal||0)/100));
  const oeuvresSociales=Math.round(brutCotisable*(Number(cfg.tauxOeuvresSociales||0)/100));
  const coutEmployeur=gains+cnasPatronal+oeuvresSociales;
  return{salaireNetContractuel,brutBase,primeNuit,primes,gains,absences:retenuesRubriques,retenuesRubriques,elements,brutCotisable,cnasSalarie,netSocial,abat,baseIRG,irgBrut:irgCalc.irgBrut,irgFormule:irgCalc.formule,irg,netAPayer,cnasPatronal,oeuvresSociales,coutEmployeur};
}
function paieNetFromBase(base,cfg){
  const brut=Math.max(0,Number(base)||0);
  const cnas=Math.round(brut*(Number(cfg.tauxCnasSalarie||0)/100));
  const netSocial=Math.max(0,brut-cnas);
  const irgCalc=irgSalaireAlgerie(netSocial,cfg);
  const cnasPatronal=Math.round(brut*(Number(cfg.tauxCnasPatronal||0)/100));
  const oeuvresSociales=Math.round(brut*(Number(cfg.tauxOeuvresSociales||0)/100));
  return{brutCotisable:brut,cnasSalarie:cnas,baseIRG:netSocial,irg:irgCalc.irg,netAPayer:Math.max(0,netSocial-irgCalc.irg),cnasPatronal,oeuvresSociales,coutEmployeur:brut+cnasPatronal+oeuvresSociales};
}
function paieBaseBruteForAgent(a){
  const explicit=Number(a?.salaireBase||a?.paieBaseBrute||0)||0;
  if(explicit>0)return explicit;
  const netContractuel=Number(a?.salaireNet||0)||0;
  if(netContractuel>0)return paieOptimizeFromNet(netContractuel,a).base||0;
  return 0;
}
function paieOptimizeFromNet(targetNet,agent){
  const cfg=paieConfig();
  const target=Math.max(0,parseMoneyInput(targetNet)||0);
  const bounds=paieGrilleBounds(agent);
  const minBase=Math.max(0,Number(bounds.min||0));
  const maxBase=Math.max(0,Number(bounds.max||0));
  const panierMax=Math.max(0,Number(cfg.optimisationPanierMax||0));
  const transportMax=Math.max(0,Number(cfg.optimisationTransportMax||0));
  const maxNonTax=panierMax+transportMax;
  const minCalc=paieNetFromBase(minBase,cfg);
  let warning="";
  if(target<=minCalc.netAPayer){
    warning="Net cible inférieur ou égal au net minimal de la grille fonction. La base reste au minimum autorisé.";
    return{target,base:minBase,panier:0,transport:0,nonTaxable:0,warning,bounds,...paieNetFromBase(minBase,cfg)};
  }
  const nonTaxable=Math.min(maxNonTax,Math.max(0,target-minCalc.netAPayer));
  const taxableTarget=Math.max(0,target-nonTaxable);
  let lo=minBase,hi=Math.max(minBase*2,taxableTarget*2,1);
  while(paieNetFromBase(hi,cfg).netAPayer<taxableTarget&&hi<10000000)hi*=1.5;
  for(let i=0;i<48;i++){
    const mid=(lo+hi)/2;
    if(paieNetFromBase(mid,cfg).netAPayer<taxableTarget)lo=mid;else hi=mid;
  }
  const base=Math.round(hi);
  if(maxBase&&base>maxBase){
    const calcMax=paieNetFromBase(maxBase,cfg);
    const remaining=Math.max(0,target-calcMax.netAPayer);
    const nt=Math.min(maxNonTax,remaining);
    warning="Net cible supérieur au maximum de la grille fonction. La base est plafonnée au maximum autorisé.";
    return{target,base:maxBase,panier:Math.min(nt,panierMax),transport:Math.max(0,nt-Math.min(nt,panierMax)),nonTaxable:nt,warning,bounds,...calcMax,netAPayer:calcMax.netAPayer+nt,coutEmployeur:calcMax.coutEmployeur+nt};
  }
  const calc=paieNetFromBase(base,cfg);
  const panier=Math.min(nonTaxable,panierMax);
  const transport=Math.max(0,nonTaxable-panier);
  return{target,base,panier,transport,nonTaxable,warning,bounds,...calc,netAPayer:calc.netAPayer+nonTaxable,coutEmployeur:calc.coutEmployeur+nonTaxable};
}
function paieMonthLabel(ym){const [y,m]=String(ym||"").split("-").map(Number);if(!y||!m)return new Date().toLocaleDateString("fr-FR",{month:"long",year:"numeric"});return new Date(y,m-1,1).toLocaleDateString("fr-FR",{month:"long",year:"numeric"})}
