function devisCalcCoutAutoIRG(salInput){
  const tr=salInput.closest("tr");
  const irg=calcIRGAlgerie(parseFloat(salInput.value)||0);
  const irgInp=tr.querySelector("[name='cc-irg']");
  if(irgInp)irgInp.value=irg;
}

function devisCalcCoutAddRow(){
  const tbody=document.getElementById("cc-tbody");
  if(!tbody)return;
  const n=tbody.querySelectorAll("tr.cc-row").length+1;
  tbody.insertAdjacentHTML("beforeend",devisCalcCoutRowHTML(n));
  const newRow=tbody.lastElementChild;
  const salInp=newRow.querySelector("[name='cc-sal']");
  if(salInp)devisCalcCoutAutoIRG(salInp);
  devisCalcCoutUpdateRow(newRow);
  newRow.querySelector("[name='cc-fn']")?.focus();
}

function devisCalcCoutRenum(){
  document.querySelectorAll("#cc-tbody tr.cc-row").forEach((tr,i)=>{
    const c=tr.querySelector("td:first-child");
    if(c)c.textContent=i+1;
    tr.style.background=i%2===0?"#f8fafc":"#fff";
  });
}

function devisCalcCoutUpdateRow(tr){
  const gi=name=>parseFloat(tr.querySelector("[name='"+name+"']")?.value)||0;
  const salaire=gi("cc-sal"),irg=gi("cc-irg"),fgesPct=gi("cc-fgp");
  const gilet=gi("cc-glt"),parkas=gi("cc-prk"),rangers=gi("cc-rng"),tph=gi("cc-tph"),margePct=gi("cc-mrg");
  const cnas=salaire*0.35;
  const fgestion=salaire*fgesPct/100;
  const conge=salaire/11;
  const ttg=salaire+cnas+irg+fgestion+gilet+parkas+rangers+tph+conge;
  const marge=ttg*margePct/100;
  const ttgFinal=ttg+marge;
  const fmt=v=>v>0?v.toLocaleString("fr-FR",{minimumFractionDigits:2,maximumFractionDigits:2}):"—";
  const s=(cls,v)=>{const el=tr.querySelector("."+cls);if(el)el.textContent=fmt(v);};
  s("cc-cnas",cnas);s("cc-fgestion",fgestion);s("cc-conge",conge);
  s("cc-ttg",ttg);s("cc-marge",marge);s("cc-ibs",marge*0.26);s("cc-formation",salaire*0.02);
  const f=tr.querySelector(".cc-ttgfinal");
  if(f)f.textContent=ttgFinal>0?ttgFinal.toLocaleString("fr-FR",{minimumFractionDigits:2,maximumFractionDigits:2}):"—";
}

function devisCalcCoutUpdate(){
  const g=id=>parseFloat(document.getElementById(id)?.value)||0;
  const salaire=g("cc-salaire"),chargesPct=g("cc-charges"),transport=g("cc-transport"),panier=g("cc-panier");
  const nuitPct=g("cc-nuit"),wePct=g("cc-we"),autresPrimes=g("cc-autresPrimes");
  const fraisGenPct=g("cc-fraisGen"),margePct=g("cc-marge");
  const nbAgents=Math.max(1,parseInt(document.getElementById("cc-nbAgents")?.value)||1);
  const coutAgent=salaire+salaire*chargesPct/100+transport+panier+salaire*nuitPct/100+salaire*wePct/100+autresPrimes;
  const coutTotal=coutAgent*nbAgents;
  const frais=coutTotal*fraisGenPct/100;
  const prixHT=(coutTotal+frais)*(1+margePct/100);
  const tva=prixHT*0.19;
  const set=(id,v)=>{const el=document.getElementById(id);if(el)el.textContent=formatDZD(v);};
  set("cc-r-cout-agent",coutAgent);set("cc-r-cout-total",coutTotal);set("cc-r-frais",frais);
  set("cc-r-ht",prixHT);set("cc-r-tva",tva);set("cc-r-ttc",prixHT+tva);
  set("cc-r-unit",nbAgents>0?prixHT/nbAgents:prixHT);
}

function devisCalcCoutInsererFormulaire(){
  const g=id=>parseFloat(document.getElementById(id)?.value)||0;
  const salaire=g("cc-salaire"),chargesPct=g("cc-charges"),transport=g("cc-transport"),panier=g("cc-panier");
  const nuitPct=g("cc-nuit"),wePct=g("cc-we"),autresPrimes=g("cc-autresPrimes");
  const fraisGenPct=g("cc-fraisGen"),margePct=g("cc-marge");
  const nbAgents=Math.max(1,parseInt(document.getElementById("cc-nbAgents")?.value)||1);
  const designation=(document.getElementById("cc-designation")?.value||"").trim()||"Prestation de gardiennage";
  const unite=document.getElementById("cc-unite")?.value||"Mois";
  const coutAgent=salaire+salaire*chargesPct/100+transport+panier+salaire*nuitPct/100+salaire*wePct/100+autresPrimes;
  const coutTotal=coutAgent*nbAgents;
  const frais=coutTotal*fraisGenPct/100;
  const prixHT=(coutTotal+frais)*(1+margePct/100);
  const prixUnitHT=Math.round(prixHT/nbAgents*100)/100;
  closeModal();
  devisEditorLigneAdd({designation,unite,qte:nbAgents,prixUnitHT,remise:0});
}

function devisCalcCoutInserer(){
  const rows=document.querySelectorAll("#cc-tbody tr.cc-row");
  if(!rows.length){closeModal();return;}
  const lignes=[];
  rows.forEach((tr,i)=>{
    const gi=name=>parseFloat(tr.querySelector("[name='"+name+"']")?.value)||0;
    const designation=(tr.querySelector("[name='cc-fn']")?.value||"").trim()||("Poste "+(i+1));
    const salaire=gi("cc-sal"),irg=gi("cc-irg"),fgesPct=gi("cc-fgp");
    const gilet=gi("cc-glt"),parkas=gi("cc-prk"),rangers=gi("cc-rng"),tph=gi("cc-tph"),margePct=gi("cc-mrg");
    const cnas=salaire*0.35,fgestion=salaire*fgesPct/100,conge=salaire/11;
    const ttg=salaire+cnas+irg+fgestion+gilet+parkas+rangers+tph+conge;
    const ttgFinal=ttg+ttg*margePct/100;
    if(salaire>0||designation)lignes.push({designation,unite:"Mois",qte:1,prixUnitHT:Math.round(ttgFinal*100)/100,remise:0});
  });
  closeModal();
  lignes.forEach(l=>devisEditorLigneAdd(l));
}

function renderCommCatalogue(view){
  const rawList=bySoc(db.catalogue||[]).slice();
  const seenPrestations=new Set();
  const list=rawList.filter(p=>{
    const key=[p.societe,p.code,p.designation].map(v=>String(v||"").trim().toLowerCase()).join("|");
    if(seenPrestations.has(key))return false;
    seenPrestations.add(key);
    return true;
  });
  const CATS_SEC=["Gardiennage","Sécurité incendie","Sécurité électronique","Sécurité événementielle","Ronde et surveillance","Escorte / Transport de fonds","Agent d'accueil","Maître chien","Conseil et audit sécurité","Autre"];
  const byCat={};CATS_SEC.forEach(k=>byCat[k]=[]);list.forEach(p=>{const k=p.categorie||"Autre";if(!byCat[k])byCat[k]=[];byCat[k].push(p);});
  const catBlocks=Object.entries(byCat).filter(([,ps])=>ps.length>0).map(([cat,ps])=>`
    <div class="card p-0 mb-4 overflow-hidden">
      <div style="background:#0f2d5a;padding:10px 16px;display:flex;align-items:center;justify-content:space-between">
        <span style="color:#fff;font-weight:800;font-size:14px">${escapeHTML(cat)}</span>
        <span style="background:rgba(255,255,255,0.15);color:#fff;font-size:11px;font-weight:700;padding:2px 10px;border-radius:20px">${ps.length} prestation${ps.length>1?"s":""}</span>
      </div>
      <table style="width:100%;border-collapse:collapse;font-size:13px">
        <thead><tr style="background:#f1f5f9">
          <th style="padding:8px 12px;text-align:left;font-size:11px;font-weight:700;color:#64748b;border-bottom:1px solid #e2e8f0">Code</th>
          <th style="padding:8px 12px;text-align:left;font-size:11px;font-weight:700;color:#64748b;border-bottom:1px solid #e2e8f0">Désignation</th>
          <th style="padding:8px 12px;text-align:left;font-size:11px;font-weight:700;color:#64748b;border-bottom:1px solid #e2e8f0">Description</th>
          <th style="padding:8px 12px;text-align:center;font-size:11px;font-weight:700;color:#64748b;border-bottom:1px solid #e2e8f0;width:120px">Unité</th>
          <th style="padding:8px 12px;text-align:right;font-size:11px;font-weight:700;color:#64748b;border-bottom:1px solid #e2e8f0;width:130px">Prix HT</th>
          <th style="padding:8px 12px;text-align:right;font-size:11px;font-weight:700;color:#64748b;border-bottom:1px solid #e2e8f0;width:190px">Actions</th>
        </tr></thead>
        <tbody>${ps.map(p=>`<tr style="border-bottom:1px solid #f1f5f9" onmouseover="this.style.background='#f8fafc'" onmouseout="this.style.background=''">
          <td style="padding:8px 12px;font-family:monospace;font-size:11px;color:#64748b">${escapeHTML(p.code||"")}</td>
          <td style="padding:8px 12px;font-weight:700;color:#0f172a">${escapeHTML(p.designation||"")}</td>
          <td style="padding:8px 12px;font-size:12px;color:#475569;max-width:300px">${p.description?`${escapeHTML(p.description.slice(0,80))}${p.description.length>80?"…":""}`:`<span style="color:#94a3b8;font-style:italic">Non renseignée</span>`}</td>
          <td style="padding:8px 12px;text-align:center"><span class="pill pill-indigo" style="font-size:10px;white-space:nowrap">${escapeHTML(p.unite||"—")}</span></td>
          <td style="padding:8px 12px;text-align:right;font-weight:800;color:#043970;white-space:nowrap">${Number(p.prixHT)>0?money(p.prixHT):`<span style="color:#dc2626;font-size:11px">Non renseigné</span>`}</td>
          <td style="padding:8px 12px;text-align:right"><div style="display:flex;gap:4px;justify-content:flex-end">
            <button class="btn btn-ghost text-xs" onclick="openCataloguePrestModal('${p.id}')">Modifier</button>
            <button class="btn btn-danger text-xs" onclick="deletePrest('${p.id}')">Supprimer</button>
          </div></td>
        </tr>`).join("")}</tbody>
      </table>
    </div>`).join("");
  view.innerHTML=`<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px">
    <div><h1 style="font-size:20px;font-weight:800;color:#0f2d5a;margin:0">Catalogue de prestations</h1>
    <p style="font-size:13px;color:#64748b;margin:4px 0 0">${list.length} prestation${list.length>1?"s":""} · Gardiennage & Sécurité</p></div>
    <button class="btn btn-primary" onclick="openCataloguePrestModal()">+ Nouvelle prestation</button>
  </div>
  ${commTabs("catalogue")}
  ${list.length===0?`<div class="card p-10 text-center" style="color:#94a3b8">
    <div style="font-size:48px;margin-bottom:12px">🛡</div>
    <div style="font-weight:700;font-size:15px;margin-bottom:6px">Aucune prestation</div>
    <div style="font-size:13px;margin-bottom:16px">Créez votre premier service de gardiennage ou sécurité</div>
    <button class="btn btn-primary" onclick="openCataloguePrestModal()">+ Créer une prestation</button>
  </div>`:catBlocks}`;
}
function nextPrestCode(){
  const nums=(db.catalogue||[]).map(p=>String(p.code||"").match(/^PREST-(\d+)$/i)).filter(Boolean).map(m=>parseInt(m[1],10)||0);
  const next=(nums.length?Math.max(...nums):0)+1;
  return `PREST-${String(next).padStart(4,"0")}`;
}
function openCataloguePrestModal(id){
  const p=(db.catalogue||[]).find(x=>x.id===id);
  const isEdit=!!p;
  const code=p?.code||nextPrestCode();
  const CATS_SEC=["Gardiennage","Sécurité incendie","Sécurité électronique","Sécurité événementielle","Ronde et surveillance","Escorte / Transport de fonds","Agent d'accueil","Maître chien","Conseil et audit sécurité","Autre"];
  const UNITES=["Agent / mois","Vacation / jour","Vacation / nuit","Forfait mensuel","Forfait journalier","Heure","Prestation"];
  openModal(`<h3 style="font-weight:800;font-size:16px;color:#0f2d5a;margin:0 0 16px">${isEdit?"Modifier prestation":"Nouvelle prestation"}</h3>
    <form onsubmit="event.preventDefault();confirmPrest('${id||""}')">
      <div class="rh-op-grid" style="margin-bottom:12px">
        <label><span style="font-size:12px;font-weight:700;color:#334155">Code</span><input class="input" name="code" value="${escapeHTML(code)}" style="font-family:monospace;background:#f8fafc" readonly/></label>
        <label><span style="font-size:12px;font-weight:700;color:#334155">Société</span><select class="select" name="societe">${SOCIETES.map(s=>`<option ${((p?.societe)||mySoc())===s?"selected":""}>${escapeHTML(s)}</option>`).join("")}</select></label>
      </div>
      <label style="display:block;margin-bottom:12px"><span style="font-size:12px;font-weight:700;color:#334155">Désignation *</span><input class="input" name="designation" value="${escapeHTML(p?.designation||"")}" required style="margin-top:4px;width:100%"/></label>
      <div class="rh-op-grid" style="margin-bottom:12px">
        <label><span style="font-size:12px;font-weight:700;color:#334155">Catégorie</span>
          <select class="select" name="categorie" style="margin-top:4px">${CATS_SEC.map(c=>`<option value="${escapeHTML(c)}" ${(p?.categorie||"Gardiennage")===c?"selected":""}>${escapeHTML(c)}</option>`).join("")}</select>
        </label>
        <label><span style="font-size:12px;font-weight:700;color:#334155">Unité</span>
          <select class="select" name="unite" style="margin-top:4px">${UNITES.map(u=>`<option value="${escapeHTML(u)}" ${(p?.unite||"Agent / mois")===u?"selected":""}>${escapeHTML(u)}</option>`).join("")}</select>
        </label>
      </div>
      <label style="display:block;margin-bottom:12px"><span style="font-size:12px;font-weight:700;color:#334155">Prix HT (DZD) *</span><input class="input" type="number" min="0.01" step="0.01" name="prixHT" value="${p?.prixHT||""}" placeholder="0,00" required style="margin-top:4px;width:100%"/></label>
      <label style="display:block;margin-bottom:16px"><span style="font-size:12px;font-weight:700;color:#334155">Description *</span><textarea class="input" name="description" rows="3" required style="margin-top:4px;width:100%" placeholder="Détails de la prestation, conditions, périmètre d'intervention...">${escapeHTML(p?.description||"")}</textarea></label>
      <div style="display:flex;gap:8px;justify-content:flex-end">
        <button type="button" class="btn btn-ghost" onclick="closeModal()">Annuler</button>
        <button class="btn btn-primary">${isEdit?"Enregistrer les modifications":"Créer la prestation"}</button>
      </div>
    </form>`);
}
async function confirmPrest(id){
  const fd=new FormData(document.querySelector(".modal-bg form"));
  if(!fd.get("designation")){toast("Désignation requise","error");return;}
  if(!(parseFloat(fd.get("prixHT"))>0)){toast("Le prix HT doit être supérieur à zéro","error");return;}
  if(!String(fd.get("description")||"").trim()){toast("Description requise","error");return;}
  db.catalogue=db.catalogue||[];
  let p=id?db.catalogue.find(x=>x.id===id):null;
  const isEdit=!!p;
  const societe=fd.get("societe")||mySoc();
  const designation=String(fd.get("designation")||"").trim();
  const duplicate=db.catalogue.find(x=>x.id!==id&&String(x.societe||"")===String(societe||"")&&String(x.designation||"").trim().toLowerCase()===designation.toLowerCase());
  if(duplicate){toast("Cette prestation existe déjà ("+(duplicate.code||"code inconnu")+")","error");return;}
  if(!p){p={id:uid("ct"),createdAt:new Date().toISOString()};db.catalogue.push(p)}
  p.code=isEdit?(p.code||fd.get("code")||nextPrestCode()):nextPrestCode();
  p.societe=societe;
  p.designation=designation;
  p.categorie=fd.get("categorie")||"Gardiennage";
  p.unite=fd.get("unite")||"Agent / mois";
  p.prixHT=parseFloat(fd.get("prixHT"))||0;
  p.description=String(fd.get("description")||"").trim();
  p.updatedAt=new Date().toISOString();
  try{await sgdiApi("/api/irongs/collections/catalogue",{method:"PUT",body:{data:db.catalogue},legacy:false});}catch(e){toast("Erreur de sauvegarde : "+(e.message||e),"error");return;}
  closeModal();toast(isEdit?"Prestation modifiée":"Prestation créée","success");renderView();
}
async function deletePrest(id){
  if(!confirm("Supprimer cette prestation ?"))return;
  db.catalogue=(db.catalogue||[]).filter(p=>p.id!==id);
  try{await sgdiApi("/api/irongs/collections/catalogue",{method:"PUT",body:{data:db.catalogue},legacy:false});}catch(e){toast("Erreur : "+(e.message||e),"error");return;}
  toast("Prestation supprimée","success");renderView();
}
function renderCommTarifs(view){
  const cat=bySoc(db.catalogue||[]);
  const byCat={};cat.forEach(p=>{const k=p.categorie||"—";if(!byCat[k])byCat[k]=[];byCat[k].push(p)});
  view.innerHTML=`<h1 class="text-2xl font-bold mb-2">💲 Tarification</h1><p class="text-slate-500 text-sm mb-4">${cat.length} prestations · Vue par catégorie</p>
    ${commTabs("tarifs")}
    ${Object.keys(byCat).length===0?`<div class="card p-10 text-center text-slate-500">Aucun tarif. Créez d'abord des prestations dans le catalogue.</div>`:Object.entries(byCat).map(([c,ps])=>{const moy=ps.reduce((s,p)=>s+(p.prixHT||0),0)/ps.length;const min=Math.min(...ps.map(p=>p.prixHT||0));const max=Math.max(...ps.map(p=>p.prixHT||0));return`<div class="card p-4 mb-4"><div class="flex items-center justify-between mb-3"><h3 class="font-bold text-lg">${escapeHTML(c)}</h3><div class="text-xs text-slate-500">${ps.length} tarifs · Min ${money(min)} · Max ${money(max)} · Moy ${money(moy)}</div></div><div class="overflow-hidden"><table><thead><tr><th>Code</th><th>Désignation</th><th>Unité</th><th>Prix HT</th></tr></thead><tbody>${ps.sort((a,b)=>(a.prixHT||0)-(b.prixHT||0)).map(p=>`<tr><td class="font-mono text-xs">${safe(p.code)}</td><td>${escapeHTML(p.designation||"")}</td><td class="text-xs">${safe(p.unite)}</td><td class="font-bold">${money(p.prixHT)}</td></tr>`).join("")}</tbody></table></div></div>`}).join("")}`;
}
function renderCommStats(view){
  const prospects=bySoc(db.prospects||[]);const clients=bySoc(db.clients||[]);const opps=bySoc(db.opportunites||[]);const visites=bySoc(db.visites||[]);
  const sources={};prospects.forEach(p=>{const k=p.source||"—";sources[k]=(sources[k]||0)+1});
  const structures={};clients.forEach(c=>{const k=c.structure||"—";structures[k]=(structures[k]||0)+1});
  const oppByEtape={};ETAPES_OPP.forEach(e=>oppByEtape[e]=opps.filter(o=>o.etape===e));
  const totalProsp=prospects.length||1;
  view.innerHTML=`<h1 class="text-2xl font-bold mb-2">📈 Statistiques commerciales</h1>
    ${commTabs("stats")}
    <div class="grid grid-2 gap-4 mb-4">
      <div class="card p-5"><h3 class="font-bold mb-3">Sources de prospects</h3>${Object.entries(sources).sort((a,b)=>b[1]-a[1]).map(([k,n])=>{const pct=Math.round(n/totalProsp*100);return`<div class="text-sm mb-2"><div class="flex justify-between mb-1"><span>${escapeHTML(k)}</span><span class="text-slate-500">${n} (${pct}%)</span></div><div class="h-2 bg-slate-100 rounded-full"><div class="h-full bg-blue-500 rounded-full" style="width:${pct}%"></div></div></div>`}).join("")||`<div class="text-sm text-slate-400">Aucune donnée.</div>`}</div>
      <div class="card p-5"><h3 class="font-bold mb-3">Clients par structure</h3>${Object.entries(structures).sort((a,b)=>b[1]-a[1]).map(([k,n])=>{const total=clients.length||1;const pct=Math.round(n/total*100);return`<div class="text-sm mb-2"><div class="flex justify-between mb-1"><span>${escapeHTML(k)}</span><span class="text-slate-500">${n} (${pct}%)</span></div><div class="h-2 bg-slate-100 rounded-full"><div class="h-full bg-emerald-500 rounded-full" style="width:${pct}%"></div></div></div>`}).join("")||`<div class="text-sm text-slate-400">Aucune donnée.</div>`}</div>
    </div>
    <div class="card p-5 mb-4"><h3 class="font-bold mb-3">Funnel de conversion</h3><div class="grid grid-cols-6 gap-2">${ETAPES_OPP.map(e=>{const ps=oppByEtape[e];const t=ps.reduce((s,o)=>s+(o.montant||0),0);const tot=opps.length||1;const pct=Math.round(ps.length/tot*100);return`<div class="card p-3 bg-slate-50 text-center"><div class="text-xs uppercase text-slate-500 mb-1">${e}</div><div class="text-2xl font-bold ${e==="gagnee"?"text-emerald-600":e==="perdue"?"text-red-600":"text-amber-600"}">${ps.length}</div><div class="text-xs text-slate-500">${pct}%</div><div class="text-xs text-slate-500 mt-1">${money(t)}</div></div>`}).join("")}</div></div>
    <div class="card p-5"><h3 class="font-bold mb-3">Activité (visites/contacts)</h3><div class="text-3xl font-bold">${visites.length}</div><div class="text-xs text-slate-500">${visites.filter(v=>v.date>=today()).length} à venir · ${visites.filter(v=>v.date<today()).length} passées</div></div>`;
}

/* ============ DRH MODULE (transverse) ============ */
function drhTabs(active){return ""}
function drhMedDaysSince(isoStr){
  if(!isoStr)return null;
  const d=isoStr.slice(0,10);
  return daysBetween(d,today());
}
function drhMedPendingCount(a){
  if(!a||!a.finRelationAt||a.finRelationDotationReversee)return 0;
  let n=0;
  const daysSinceSortie=drhMedDaysSince(a.finRelationAt);
  if(daysSinceSortie>=3&&!a.finRelationMed1SentAt)n++;
  if(a.finRelationMed1SentAt&&drhMedDaysSince(a.finRelationMed1SentAt)>=7&&!a.finRelationMed2SentAt)n++;
  if(a.finRelationMed2SentAt&&drhMedDaysSince(a.finRelationMed2SentAt)>=7&&!a.finRelationGendarmerieSentAt)n++;
  return n;
}
function renderDRHMiseEnDemeure(view){
  const soc=drhActiveSocieteFilter();
  const sortants=(db.agents||[]).filter(a=>a.statut==="sortant"&&!a.finRelationDotationReversee&&a.finRelationAt&&(!soc||!a.societe||a.societe===soc));
  const allDone=(db.agents||[]).filter(a=>a.statut==="sortant"&&a.finRelationDotationReversee&&a.finRelationAt&&(!soc||!a.societe||a.societe===soc));
  const pendingCount=sortants.reduce((n,a)=>n+drhMedPendingCount(a),0);
  const rows=sortants.map(a=>{
    const nom=((a.nom||"")+" "+(a.prenom||"")).trim();
    const daysSince=drhMedDaysSince(a.finRelationAt)||0;
    const med1Due=daysSince>=3&&!a.finRelationMed1SentAt;
    const med2Due=a.finRelationMed1SentAt&&drhMedDaysSince(a.finRelationMed1SentAt)>=7&&!a.finRelationMed2SentAt;
    const genDue=a.finRelationMed2SentAt&&drhMedDaysSince(a.finRelationMed2SentAt)>=7&&!a.finRelationGendarmerieSentAt;
    const sent1=a.finRelationMed1SentAt?`<span class="pill pill-green text-xs">MED1 envoyée le ${formatDate(a.finRelationMed1SentAt.slice(0,10))}</span>`:``;
    const sent2=a.finRelationMed2SentAt?`<span class="pill pill-green text-xs">MED2 envoyée le ${formatDate(a.finRelationMed2SentAt.slice(0,10))}</span>`:``;
    const sentG=a.finRelationGendarmerieSentAt?`<span class="pill pill-blue text-xs">Gendarmerie le ${formatDate(a.finRelationGendarmerieSentAt.slice(0,10))}</span>`:``;
    const btns=[];
    if(med1Due)btns.push(`<button class="btn btn-danger text-xs" onclick="genMed(event,'${a.id}',1)">Émettre MED n°1</button>`);
    if(med2Due)btns.push(`<button class="btn btn-danger text-xs" onclick="genMed(event,'${a.id}',2)">Émettre MED n°2</button>`);
    if(genDue)btns.push(`<button class="btn btn-danger text-xs" onclick="genMed(event,'${a.id}',3)">Lettre Gendarmerie</button>`);
    if(!med1Due&&!med2Due&&!genDue&&!a.finRelationMed1SentAt){
      const jRestants=3-daysSince;
      btns.push(`<span class="text-xs text-slate-400">MED1 disponible dans ${jRestants} j</span>`);
    }
    return `<tr>
      <td><div class="font-semibold">${escapeHTML(nom)}</div><div class="text-xs font-mono text-slate-500">${escapeHTML(a.matricule||"—")}</div></td>
      <td class="text-xs">${escapeHTML(a.societe||"—")}</td>
      <td class="text-xs">${formatDate(a.dateSortie||"")}</td>
      <td class="text-xs text-center">${daysSince} j</td>
      <td><div class="flex flex-col gap-1">${sent1}${sent2}${sentG}</div></td>
      <td><div class="flex gap-1 flex-wrap">${btns.join("")}</div></td>
    </tr>`;
  }).join("");
  const doneRows=allDone.length?`<div class="card p-4 mt-4"><div class="font-black text-sm text-slate-500 mb-2">DOSSIERS CLÔTURÉS (dotation reversée)</div><table><thead><tr><th>Employé</th><th>Sortie</th><th>Reversement</th></tr></thead><tbody>${allDone.map(a=>`<tr><td>${escapeHTML(((a.nom||"")+" "+(a.prenom||"")).trim())}</td><td class="text-xs">${formatDate(a.dateSortie||"")}</td><td class="text-xs">${formatDate(a.finRelationReversementDate||"")}</td></tr>`).join("")}</tbody></table></div>`:"";
  view.innerHTML=`<div class="flex justify-between items-start gap-3 mb-4 flex-wrap">
    <div><h1 class="text-2xl font-black">MISE EN DEMEURE</h1>
    <p class="text-sm text-slate-500">Documents automatiques — Fin de relation de travail · Dotation non reversée</p></div>
    <div class="flex gap-2">
      ${pendingCount?`<span class="pill pill-red">${pendingCount} action(s) requise(s)</span>`:`<span class="pill pill-green">Aucune action requise</span>`}
    </div>
  </div>
  <div class="card p-4 mb-4 bg-amber-50 border border-amber-200 text-sm text-amber-900">
    <b>Procédure :</b> MED n°1 (72h après sortie) → MED n°2 (J+7) → Lettre Brigade de Gendarmerie (J+14). Chaque document est généré automatiquement dès l'échéance atteinte.
  </div>
  ${sortants.length===0?`<div class="card p-8 text-center text-slate-500">Aucun dossier en instance de mise en demeure.</div>`:
  `<div class="card overflow-x-auto"><table><thead><tr><th>Employé</th><th>Société</th><th>Date sortie</th><th class="text-center">Jours écoulés</th><th>Documents émis</th><th>Actions</th></tr></thead><tbody>${rows}</tbody></table></div>`}
  ${doneRows}`;
}
async function genMed(evt,agentId,num){
  evt&&evt.stopPropagation();
  const a=(db.agents||[]).find(x=>x.id===agentId);if(!a)return;
  const nom=((a.nom||"")+" "+(a.prenom||"")).trim();
  const now=new Date().toISOString();
  if(num===1){a.finRelationMed1SentAt=now;a.finRelationMed1Date=today();}
  else if(num===2){a.finRelationMed2SentAt=now;a.finRelationMed2Date=today();}
  else{a.finRelationGendarmerieSentAt=now;a.finRelationGendramerieDate=today();}
  try{if(a.backendId)await SGDI.employees.update(a.backendId,employeeApiPayload(a));}
  catch(e){console.warn("genMed save failed",e);}
  saveDB();
  openMedPrintWindow(a,num);
  renderSidebar();renderView();
}
function openMedPrintWindow(a,num){
  const nom=((a.nom||"")+" "+(a.prenom||"")).trim();
  const dateDoc=today();
  const ref="MED"+num+"-"+(a.matricule||a.id||"SGDI")+"-"+dateDoc.replaceAll("-","");
  const isBrigade=num===3;
  const titre=isBrigade?"LETTRE ADRESSÉE À LA BRIGADE DE GENDARMERIE":("MISE EN DEMEURE N°"+num);
  const objet=isBrigade
    ?`Monsieur le Commandant de Brigade,\n\nNous avons l'honneur de porter à votre connaissance que Monsieur/Madame <b>${escapeHTML(nom)}</b>, titulaire du matricule <b>${escapeHTML(a.matricule||"—")}</b>, anciennement employé(e) de notre société, a fait l'objet d'une décision de fin de contrat le <b>${formatDate(a.dateSortie||"")}</b>.\n\nMalgré deux mises en demeure successives, en date du <b>${formatDate(a.finRelationMed1Date||"")}</b> et du <b>${formatDate(a.finRelationMed2Date||"")}</b>, l'intéressé(e) n'a pas procédé au reversement de la dotation matérielle qui lui a été attribuée dans le cadre de ses fonctions, estimée à <b>${a.stcDeductionReforme?money(a.stcDeductionReforme):"un montant à déterminer"}</b>.\n\nNous sollicitons votre intervention afin de récupérer le matériel de la société et prendre les mesures légales qui s'imposent.`
    :`Par la présente, nous mettons en demeure Monsieur/Madame <b>${escapeHTML(nom)}</b>, matricule <b>${escapeHTML(a.matricule||"—")}</b>, ex-employé(e) de notre société, de procéder au reversement de l'intégralité de la dotation matérielle mise à sa disposition dans le cadre de ses fonctions.\n\nDans le cas où il ne serait pas procédé audit reversement dans un délai de <b>7 (sept) jours</b> à compter de la date de la présente, nous nous verrions dans l'obligation de saisir les autorités compétentes pour le recouvrement du matériel et des sommes dues.`;
  const html=`<!doctype html><html><head><meta charset="utf-8"><title>${titre}</title>
<style>@page{size:A4 portrait;margin:20mm}*{box-sizing:border-box}body{margin:0;background:#fff;color:#111;font-family:"Times New Roman",Times,serif;font-size:13.5px;line-height:1.6}
.actions{position:sticky;top:0;display:flex;gap:8px;justify-content:flex-end;padding:8px;background:#fff;border-bottom:1px solid #e2e8f0;margin-bottom:8mm}
.actions button{border:0;border-radius:8px;background:#043970;color:#fff;font:700 13px Arial;padding:8px 16px;cursor:pointer}
.doc{width:170mm;margin:0 auto}
.logo{width:30mm;height:30mm;object-fit:contain;display:block;margin:0 auto 6mm}
.ref{text-align:right;font-size:11px;font-family:Arial,sans-serif;margin-bottom:8mm;color:#475569}
.title{text-align:center;font-size:17px;font-weight:900;text-transform:uppercase;letter-spacing:.2px;font-family:Arial,sans-serif;margin:0 0 8mm;text-decoration:underline}
.objet{margin:0 0 8mm;font-family:Arial,sans-serif;font-size:12px}<b>.objet b{font-family:inherit}</b>
.body{text-align:justify;margin-bottom:8mm}
.sign{margin-top:18mm;text-align:right;font-weight:900;font-family:Arial,sans-serif}
.footer{border-top:1px solid #d7dde8;margin-top:10mm;padding-top:3mm;text-align:center;font-size:9px;font-family:Arial,sans-serif;color:#475569}
@media print{.actions{display:none!important}}
</style></head><body>
<div class="actions no-print"><button onclick="window.print()">Imprimer</button><button onclick="window.close()" style="background:#64748b">Fermer</button></div>
<div class="doc">
  <img class="logo" src="/static/sgdi-icon-192.png" alt="logo">
  <div class="ref"><b>Réf :</b> ${escapeHTML(ref)}<br><b>Date :</b> ${formatDate(dateDoc)}</div>
  ${isBrigade?`<div class="objet"><b>À Monsieur le Commandant de Brigade de Gendarmerie</b></div>`:`<div class="objet"><b>À l'attention de :</b> ${escapeHTML(nom)}<br><b>Ancien matricule :</b> ${escapeHTML(a.matricule||"—")}</div>`}
  <div class="title">${titre}</div>
  <div class="body"><p>${objet}</p>
  <p>Veuillez agréer, ${isBrigade?"Monsieur le Commandant,":"Monsieur/Madame,"} l'expression de nos sincères salutations.</p></div>
  <div class="sign">La Direction Générale</div>
  <div class="footer">${escapeHTML(a.societe||"SGDI")} — ${titre} · ${escapeHTML(ref)} · ${formatDate(dateDoc)}</div>
</div></body></html>`;
  const w=window.open("","_blank","width=860,height=700");
  if(w){w.document.write(html);w.document.close();}else{toast("Impression bloquée par le navigateur","warn");}
}
function renderElementsSortants(view){
  const isDrh=isDrhModuleContext();
  const isOps=isOpsEffectifContext();
  const soc=isDrh?drhActiveSocieteFilter():(currentStructureSocieteFilter()||mySoc()||"");
  const sortants=(db.agents||[]).filter(a=>a.statut==="sortant"&&(!soc||!a.societe||a.societe===soc));
  const rows=sortants.map(a=>{
    const nom=escapeHTML(((a.nom||"")+" "+(a.prenom||"")).trim());
    const mat=escapeHTML(a.matricule||a.code||"—");
    const soc_=escapeHTML(a.societe||"");
    const ds=a.dateSortie?formatDate(a.dateSortie):"—";
    const dotRev=a.finRelationDotationReversee
      ?`<span class="badge" style="background:#dcfce7;color:#166534">✓ Reversée</span>`
      :`<span class="badge" style="background:#fee2e2;color:#991b1b">⚠ En attente</span>`;
    const stc=a.stcCongeReliquat!=null?`${a.stcCongeReliquat} j`:"—";
    const ded=a.stcDeductionReforme?`-${money(a.stcDeductionReforme)}`:"";
    const med=isDrh?(()=>{
      if(!a.finRelationAt)return"—";
      const p=drhMedPendingCount(a);
      if(!p&&a.finRelationGendarmerieSentAt)return`<span class="badge" style="background:#dcfce7;color:#166534">Clôturé</span>`;
      if(!p)return`<span class="text-xs text-slate-400">—</span>`;
      const t=!a.finRelationMed1SentAt?"MED n°1":!a.finRelationMed2SentAt?"MED n°2":"Lettre gend.";
      return`<span class="badge" style="background:#fef3c7;color:#92400e">${t}</span>`;
    })():"";
    const openLink=`<a class="btn btn-ghost text-xs" href="#/agents/${employeeRouteId(a)}" onclick="setFicheContext('${isDrh?"drh":"ops"}')">Ouvrir →</a>`;
    const drhCols=isDrh?`<td>${dotRev}</td><td class="text-xs text-center">${stc}${ded?`<br><span class="text-red-600 text-xs">${ded}</span>`:""}</td><td>${med}</td>`:"";
    const opsCols=isOps?`<td class="text-xs">${escapeHTML(a.fonction||a.poste||"—")}</td>`:"";
    return`<tr><td><div class="font-semibold text-sm">${nom}</div><div class="text-xs text-slate-400">${mat}</div></td><td class="text-xs">${soc_}</td><td class="text-xs">${ds}</td>${drhCols}${opsCols}<td>${openLink}</td></tr>`;
  });
  const thDrh=isDrh?`<th>Dotation</th><th>STC congés</th><th>MED</th>`:"";
  const thOps=isOps?`<th>Poste</th>`:"";
  view.innerHTML=`<div class="effectif-page">
    <div class="${isDrh?"drh-effectif-list-header":"card p-4 mb-4 flex items-center justify-between gap-3 flex-wrap"}">
      <div><h1 class="text-2xl font-black">ÉLÉMENTS SORTANTS</h1><p class="text-xs text-slate-400 mt-0.5">${sortants.length} employé(s) sortant${soc?` · ${escapeHTML(soc)}`:""}</p></div>
    </div>
    ${sortants.length===0
      ?`<div class="card p-10 text-center text-slate-500">Aucun employé SORTANT.</div>`
      :`<div class="card overflow-hidden"><table class="effectif-table">
        <thead><tr><th>Employé</th><th>Société</th><th>Date sortie</th>${thDrh}${thOps}<th>Action</th></tr></thead>
        <tbody>${rows.join("")}</tbody>
      </table></div>`}
  </div>`;
}
function renderDRH(view,sub,arg){
  if(sub==="dashboard")return renderDRHDashboard(view);
  if(sub==="conges")return renderDRHCongesPersonnel(view);
  if(sub==="social")return renderDRHSocial(view,arg);
  if(sub==="mise_en_demeure")return renderDRHMiseEnDemeure(view);
  if(sub==="stats")return renderDRHStats(view);
  if(sub==="stats_societe")return renderDRHStatsSociete(view);
  if(sub==="stats_theme")return renderDRHStatsTheme(view);
  if(sub==="stats_fonction")return renderDRHStatsFonction(view);
  if(sub==="stats_categorie")return renderDRHStatsCategorie(view);
  if(sub==="stats_salaire")return renderDRHStatsSalaire(view);
  if(sub==="stats_affectation")return renderDRHStatsAffectation(view);
  renderDRHDashboard(view);
}
function drhLeaveCalendarDate(value){
  const raw=String(value||"").slice(0,10);
  if(!/^\d{4}-\d{2}-\d{2}$/.test(raw))return null;
  const [y,m,d]=raw.split("-").map(Number);
  const date=new Date(Date.UTC(y,m-1,d));
  return date.getUTCFullYear()===y&&date.getUTCMonth()===m-1&&date.getUTCDate()===d?date:null;
}
function drhLeaveAddMonths(date,count){
  const y=date.getUTCFullYear(),m=date.getUTCMonth()+count,d=date.getUTCDate();
  const last=new Date(Date.UTC(y,m+1,0)).getUTCDate();
  return new Date(Date.UTC(y,m,Math.min(d,last)));
}
function drhLeaveEntitlement(dateRecrutement,asOf=today()){
  const start=drhLeaveCalendarDate(dateRecrutement),end=drhLeaveCalendarDate(asOf);
  if(!start||!end||end<start)return 0;
  let months=(end.getUTCFullYear()-start.getUTCFullYear())*12+(end.getUTCMonth()-start.getUTCMonth());
  let anchor=drhLeaveAddMonths(start,months);
  if(anchor>end){months--;anchor=drhLeaveAddMonths(start,months)}
  const next=drhLeaveAddMonths(start,months+1);
  const period=Math.max(1,(next-anchor)/86400000);
  const partial=Math.max(0,(end-anchor)/86400000)/period;
  return Math.round((months+partial)*2.5*100)/100;
}
function filterDrhCongesPersonnel(value){
  const q=String(value||"").trim().toLowerCase();
  document.querySelectorAll("#drh-conges-personnel tbody tr[data-searchable]").forEach(row=>row.style.display=!q||String(row.dataset.q||"").includes(q)?"":"none");
}
function renderDRHCongesPersonnel(view){
  const soc=drhActiveSocieteFilter();
  const agents=drhAgentsList().slice().sort((a,b)=>String(a.nom||"").localeCompare(String(b.nom||""))||String(a.prenom||"").localeCompare(String(b.prenom||"")));
  const rows=agents.map(a=>{
    const name=((a.nom||"")+" "+(a.prenom||"")).trim();
    const code=a.matricule||a.code||"";
    const recruited=a.dateRecrutement||a.dateEntree||"";
    const contractEnd=employeePositionContractEndDate(a);
    const entitlement=recruited?drhLeaveEntitlement(recruited):null;
    const q=[name,code,recruited,contractEnd].join(" ").toLowerCase();
    return `<tr data-searchable data-q="${escapeHTML(q)}"><td class="font-semibold"><a href="#/agents/${employeeRouteId(a)}" class="hover:underline">${escapeHTML(name||"—")}</a></td><td class="font-mono font-bold text-amber-700">${escapeHTML(code||"—")}</td><td class="text-xs">${recruited?formatDate(recruited):"—"}</td><td class="text-xs">${contractEnd?formatDate(contractEnd):"—"}</td><td class="font-black" style="color:#043970">${entitlement===null?"—":entitlement.toLocaleString("fr-FR",{minimumFractionDigits:2,maximumFractionDigits:2})+" jours"}</td></tr>`;
  }).join("");
  view.innerHTML=`<div class="flex items-start justify-between gap-3 mb-4 flex-wrap"><div><h1 class="text-2xl font-black">CONGÉS</h1><p class="text-sm text-slate-500">Droits acquis du personnel · 2,5 jours par mois depuis la date de recrutement${soc?` · ${escapeHTML(drhSocieteLabel(soc))}`:""}.</p></div><span class="pill pill-blue">${agents.length} personne(s)</span></div>
    <div class="card p-4 mb-4"><input class="input" type="search" placeholder="Rechercher par nom, prénom ou code..." oninput="filterDrhCongesPersonnel(this.value)"/></div>
    <div id="drh-conges-personnel" class="card overflow-x-auto"><table><thead><tr><th>NOM PRÉNOM</th><th>CODE</th><th>DATE DE RECRUTEMENT</th><th>DATE DE FIN DE CONTRAT</th><th>DROIT CONGÉ</th></tr></thead><tbody>${rows||`<tr><td colspan="5" class="text-center text-slate-500 p-8">Aucun personnel enregistré.</td></tr>`}</tbody></table></div>`;
}
function drhBars(entries,color){
  const max=Math.max(1,...entries.map(e=>e[1]));
  if(!entries.length)return`<div class="text-sm text-slate-400">Aucune donnée.</div>`;
  return entries.sort((a,b)=>b[1]-a[1]).map(([k,n])=>{const pct=Math.round(n/max*100);return`<div class="text-sm mb-2"><div class="flex justify-between mb-1"><span class="font-medium">${escapeHTML(String(k||"—"))}</span><span class="text-slate-500">${n}</span></div><div class="h-2 bg-slate-100 rounded-full"><div class="h-full rounded-full" style="width:${pct}%;background:${color}"></div></div></div>`}).join("");
}
function drhChartCard(title,subtitle,body){
  return `<section class="card p-5 min-h-[260px]"><div class="flex items-start justify-between gap-3 mb-3"><div><h3 class="font-black text-sm">${escapeHTML(title)}</h3>${subtitle?`<div class="text-xs text-slate-500 mt-1">${escapeHTML(subtitle)}</div>`:""}</div></div>${body}</section>`;
}
function drhMonthlyKeys(count=12){
  const out=[];
  for(let i=count-1;i>=0;i--){const d=new Date();d.setDate(1);d.setMonth(d.getMonth()-i);out.push(d.toISOString().slice(0,7))}
  return out;
}
function drhMonthShort(m){const [y,mo]=String(m||"").split("-");return `${mo||""}/${String(y||"").slice(2)}`}
function drhSvgLine(series,labels,color="#043970",fill=false){
  const values=Array.isArray(series)?series:[];
  const max=Math.max(1,...values);
  const step=values.length>1?300/(values.length-1):300;
  const points=values.map((v,i)=>`${i*step},${88-(v/max*72)}`);
  const area=fill&&points.length?`<polygon points="0,92 ${points.join(" ")} 300,92" fill="${color}" opacity=".13"/>`:"";
  return `<svg viewBox="0 0 320 118" style="width:100%;height:150px;display:block">
    <line x1="0" y1="92" x2="304" y2="92" stroke="#e2e8f0" stroke-width="1"/>
    ${area}<polyline points="${points.join(" ")}" fill="none" stroke="${color}" stroke-width="4" stroke-linecap="round" stroke-linejoin="round"/>
    ${values.map((v,i)=>`<circle cx="${i*step}" cy="${88-(v/max*72)}" r="3.5" fill="#fff" stroke="${color}" stroke-width="3"><title>${escapeHTML(String(v))}</title></circle>`).join("")}
    ${(labels||[]).filter((_,i)=>i===0||i===labels.length-1||i%3===0).map((l,i)=>{const idx=labels.indexOf(l);return`<text x="${idx*step}" y="112" font-size="10" fill="#64748b">${escapeHTML(drhMonthShort(l))}</text>`}).join("")}
  </svg>`;
}
function drhSvgGroupedBars(labels,series){
  const colors=["#043970","#047857","#dc2626","#7c3aed"];
  const max=Math.max(1,...series.flatMap(s=>s.values||[]));
  const groupW=labels.length?300/labels.length:300;
  const barW=Math.max(5,(groupW-8)/Math.max(1,series.length));
  return `<svg viewBox="0 0 320 140" style="width:100%;height:170px;display:block">
    <line x1="0" y1="104" x2="304" y2="104" stroke="#e2e8f0"/>
    ${labels.map((label,i)=>series.map((s,j)=>{const v=(s.values||[])[i]||0;const h=v/max*86;return`<rect x="${i*groupW+4+j*barW}" y="${104-h}" width="${Math.max(4,barW-2)}" height="${h}" rx="3" fill="${colors[j%colors.length]}"><title>${escapeHTML(s.name)}: ${v}</title></rect>`}).join("")).join("")}
    ${labels.filter((_,i)=>i===0||i===labels.length-1||i%3===0).map(l=>{const idx=labels.indexOf(l);return`<text x="${idx*groupW+2}" y="124" font-size="10" fill="#64748b">${escapeHTML(drhMonthShort(l))}</text>`}).join("")}
  </svg><div class="flex flex-wrap gap-3 text-xs text-slate-500">${series.map((s,i)=>`<span><b style="color:${colors[i%colors.length]}">●</b> ${escapeHTML(s.name)}</span>`).join("")}</div>`;
}
function drhSvgDonut(entries){
  const colors=["#043970","#047857","#f59e0b","#dc2626","#7c3aed","#0891b2","#475569"];
  const rows=(entries||[]).filter(([,n])=>Number(n)>0);
  const total=rows.reduce((s,[,n])=>s+Number(n||0),0)||1;
  let acc=0;
  const rings=rows.map(([label,n],i)=>{const value=Number(n||0);const dash=value/total*100;const node=`<circle cx="70" cy="70" r="46" fill="none" stroke="${colors[i%colors.length]}" stroke-width="18" stroke-dasharray="${dash} ${100-dash}" stroke-dashoffset="${25-acc}" pathLength="100"><title>${escapeHTML(label)}: ${value}</title></circle>`;acc+=dash;return node}).join("");
  return `<div class="grid grid-cols-1 md:grid-cols-2 gap-3 items-center"><svg viewBox="0 0 140 140" style="width:100%;max-height:180px"><circle cx="70" cy="70" r="46" fill="none" stroke="#e2e8f0" stroke-width="18"/>${rings}<text x="70" y="73" text-anchor="middle" font-size="20" font-weight="900" fill="#0f172a">${total}</text></svg><div class="space-y-2 text-sm">${rows.map(([label,n],i)=>`<div class="flex justify-between gap-2"><span><b style="color:${colors[i%colors.length]}">●</b> ${escapeHTML(label)}</span><b>${n}</b></div>`).join("")||`<div class="text-slate-400">Aucune donnée.</div>`}</div></div>`;
}
function drhSvgStacked(entries){
  const total=(entries||[]).reduce((s,[,n])=>s+Number(n||0),0)||1;
  const colors=["#047857","#f59e0b","#c2410c","#dc2626","#7c3aed","#475569"];
  let offset=0;
  return `<div class="h-8 rounded-lg overflow-hidden bg-slate-100 flex mb-3">${(entries||[]).map(([label,n],i)=>{const pct=Number(n||0)/total*100;return`<div title="${escapeHTML(label)}: ${n}" style="width:${pct}%;background:${colors[i%colors.length]}"></div>`}).join("")}</div>
  <div class="grid grid-cols-2 gap-2 text-xs">${(entries||[]).map(([label,n],i)=>{const pct=Math.round(Number(n||0)/total*100);offset+=pct;return`<div class="flex justify-between gap-2"><span><b style="color:${colors[i%colors.length]}">●</b> ${escapeHTML(label)}</span><b>${n} · ${pct}%</b></div>`}).join("")}</div>`;
}
function drhSvgRadar(entries){
  const rows=(entries||[]).slice(0,6);
  const max=Math.max(1,...rows.map(([,n])=>Number(n||0)));
  const center=80,r=58;
  const pt=(i,scale=1)=>{const a=-Math.PI/2+(Math.PI*2*i/Math.max(1,rows.length));return[center+Math.cos(a)*r*scale,center+Math.sin(a)*r*scale]};
  const poly=rows.map(([,n],i)=>pt(i,Number(n||0)/max).join(",")).join(" ");
  return `<svg viewBox="0 0 160 180" style="width:100%;height:210px;display:block">
    ${[.25,.5,.75,1].map(s=>`<polygon points="${rows.map((_,i)=>pt(i,s).join(",")).join(" ")}" fill="none" stroke="#e2e8f0"/>`).join("")}
    <polygon points="${poly}" fill="#043970" opacity=".16" stroke="#043970" stroke-width="3"/>
    ${rows.map(([label,n],i)=>{const [x,y]=pt(i,1.14);return`<text x="${x}" y="${y}" text-anchor="middle" font-size="9" fill="#475569">${escapeHTML(String(label).slice(0,14))}</text>`}).join("")}
  </svg>`;
}
function drhHeatmap(rows,cols,valueFn){
  const vals=[];rows.forEach(r=>cols.forEach(c=>vals.push(Number(valueFn(r,c)||0))));
  const max=Math.max(1,...vals);
  return `<div class="overflow-x-auto"><table class="w-full text-xs"><thead><tr><th></th>${cols.map(c=>`<th class="p-1 text-center">${escapeHTML(c)}</th>`).join("")}</tr></thead><tbody>${rows.map(r=>`<tr><td class="p-1 font-semibold">${escapeHTML(r)}</td>${cols.map(c=>{const v=Number(valueFn(r,c)||0);const o=.08+(v/max*.82);return`<td class="p-1 text-center font-bold rounded" style="background:rgba(4,57,112,${o});color:${o>.45?"#fff":"#0f172a"}">${v||""}</td>`}).join("")}</tr>`).join("")}</tbody></table></div>`;
}
function agentSocialData(a){
  if(!a)return{};
  if(!a.social||typeof a.social!=="object")a.social={};
  if(!a.social.numeroCnas&&(a.numeroCnas||a.cnas))a.social.numeroCnas=a.numeroCnas||a.cnas;
  if(!a.social.numeroChifa&&(a.numeroChifa||a.chifa))a.social.numeroChifa=a.numeroChifa||a.chifa;
  if(!a.social.statutCnas)a.social.statutCnas=a.social.numeroCnas?"declare":"a_declarer";
  if(!a.social.statutChifa)a.social.statutChifa=a.social.numeroChifa?"active":"absente";
  return a.social;
}
function socialCnasOk(a){const s=agentSocialData(a);return s.statutCnas==="declare"&&String(s.numeroCnas||"").trim()}
function socialChifaOk(a){const s=agentSocialData(a);return ["active","valide"].includes(String(s.statutChifa||""))&&String(s.numeroChifa||"").trim()}
function socialAlertLevel(a){
  if(!socialCnasOk(a))return"cnas";
  if(!socialChifaOk(a))return"chifa";
  return"ok";
}
function socialStatusPill(type,value){
  const v=String(value||"").toLowerCase();
  if(type==="cnas"){
    if(v==="declare")return`<span class="pill pill-green">CNAS déclarée</span>`;
    if(v==="en_cours")return`<span class="pill pill-amber">CNAS en cours</span>`;
    return`<span class="pill pill-red">CNAS à déclarer</span>`;
  }
  if(v==="active"||v==="valide")return`<span class="pill pill-green">Chifa active</span>`;
  if(v==="en_attente")return`<span class="pill pill-amber">Chifa en attente</span>`;
  if(v==="expiree")return`<span class="pill pill-red">Chifa expirée</span>`;
  return`<span class="pill pill-gray">Chifa absente</span>`;
}
function socialAgentSearchText(a){
  const s=agentSocialData(a);
  return [a.nom,a.prenom,a.matricule,a.societe,a.fonction,a.poste,s.numeroCnas,s.numeroChifa,s.observations].join(" ").toLowerCase();
}
