function ensureNiveauxAcces(){
  if(!db)return[];
  if(!Array.isArray(db.niveauxAcces))db.niveauxAcces=[];
  const existing=new Set(db.niveauxAcces.map(n=>n&&n.code).filter(Boolean));
  defaultNiveauxAcces().forEach(n=>{if(!existing.has(n.code))db.niveauxAcces.push({...n})});
  const legacy={lecture:"H1",ecriture:"H2",validation:"H3",administration:"H5"};
  (db.users||[]).forEach(u=>{if(legacy[u.niveau])u.niveau=legacy[u.niveau]});
  return db.niveauxAcces.sort((a,b)=>(Number(a.weight)||0)-(Number(b.weight)||0));
}
