// ATLAS AI ASSISTANT WIDGET
// ═══════════════════════════════════════════════════════════════════════════
(function(){
  const SUGGESTIONS=[
    "Comment créer un employé ?",
    "Expliquer la dotation matériel",
    "Comment faire une affectation OPS ?",
    "Créer une facture client",
  ];

  let aiOpen=false;
  let aiHistory=[];
  let aiTyping=false;

  function aiMount(){
    document.getElementById("atlas-ai-widget")?.remove();
  }

  window.aiToggle=function(){
    aiOpen=!aiOpen;
    if(aiOpen)aiOpenPanel();else aiClosePanel();
  };

  window.aiOpenPanel=function(){
    aiOpen=true;
    const host=document.getElementById("atlas-ai-widget");
    if(!host)return;
    const fab=document.getElementById("ai-fab");
    if(fab)fab.style.display="none";
    const sugg=SUGGESTIONS.map(s=>`<button class="ai-suggestion" onclick="aiSendSuggestion('${s.replace(/'/g,"\\'")}')">${s}</button>`).join("");
    const panel=document.createElement("div");
    panel.className="ai-panel";
    panel.id="ai-panel";
    panel.innerHTML=`
      <div class="ai-panel-head">
        <div class="ai-panel-head-avatar">🤖</div>
        <div class="ai-panel-head-info">
          <div class="ai-panel-head-name">ATLAS IA</div>
          <div class="ai-panel-head-status">● Assistant système en ligne</div>
        </div>
        <button class="ai-panel-voice ai-panel-voice-toggle" id="ai-voice-toggle" onclick="aiToggleVoice()" title="Désactiver la voix" aria-pressed="true">Voix ON</button>
        <button class="ai-panel-voice" onclick="aiTestVoice()" title="Tester la voix">Test</button>
        <button class="ai-panel-voice" onclick="aiTestSound()" title="Tester le son">Son</button>
        <button class="ai-panel-close" onclick="aiClosePanel()" title="Fermer">✕</button>
      </div>
      <div class="ai-messages" id="ai-messages">
        <div class="ai-msg ai-msg-ai">Bonjour ! Je suis ATLAS IA. Posez-moi une question sur DRH, OPS, Matériel, Commercial ou Finances.</div>
      </div>
      <div class="ai-suggestions" id="ai-suggestions">${sugg}</div>
      <div class="ai-input-bar">
        <textarea class="ai-input" id="ai-input" rows="1" placeholder="Posez votre question..." onkeydown="aiInputKeydown(event)" oninput="aiAutoResize(this)"></textarea>
        <button class="ai-send" id="ai-send" onclick="aiSend()" title="Envoyer">➤</button>
      </div>`;
    host.appendChild(panel);
    _sgdiUpdateVoiceToggle();
    if(aiHistory.length){
      aiHistory.forEach(m=>{
        aiAppendMessage(m.content,m.role==="user"?"user":"ai");
      });
    }
    setTimeout(()=>document.getElementById("ai-input")?.focus(),100);
  };

  window.aiClosePanel=function(){
    aiOpen=false;
    const panel=document.getElementById("ai-panel");
    if(panel)panel.remove();
    const fab=document.getElementById("ai-fab");
    if(fab)fab.style.display="";
  };

  window.aiSendSuggestion=function(text){
    const input=document.getElementById("ai-input");
    if(input){input.value=text;aiAutoResize(input)}
    aiSend();
    const sugg=document.getElementById("ai-suggestions");
    if(sugg)sugg.style.display="none";
  };

  window.aiInputKeydown=function(e){
    if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();aiSend()}
  };

  window.aiAutoResize=function(el){
    el.style.height="auto";
    el.style.height=Math.min(el.scrollHeight,100)+"px";
  };

  window.aiTestVoice=function(){
    const ok=_sgdiSpeakText("Bonjour. Je suis ATLAS, votre assistante intelligente.");
    if(ok&&typeof toast==="function")toast("Test voix lancé","info");
    else if(!_sgdiVoiceEnabled()&&typeof toast==="function")toast("Voix désactivée","info");
    aiAppendMessage(_sgdiVoiceDiagnostic(),"ai");
  };

  window.aiToggleVoice=function(){
    const enabled=!_sgdiVoiceEnabled();
    _sgdiSetVoiceEnabled(enabled);
    if(typeof toast==="function")toast(enabled?"Voix activée":"Voix désactivée","info");
    aiAppendMessage(enabled?"Voix ATLAS activée.":"Voix ATLAS désactivée.","ai");
  };

  window.aiTestSound=function(){
    const ok=_sgdiPlayTestBeep();
    if(ok&&typeof toast==="function")toast("Test son lancé","info");
    aiAppendMessage(ok?"Test son lancé : si vous n'entendez aucun bip, le son du site ou du navigateur est bloqué.":"Test son bloqué par le navigateur.","ai");
  };

  function aiAppendMessage(text,role){
    const box=document.getElementById("ai-messages");
    if(!box)return;
    const div=document.createElement("div");
    div.className="ai-msg ai-msg-"+role;
    div.textContent=text;
    box.appendChild(div);
    box.scrollTop=box.scrollHeight;
    return div;
  }

  function aiCurrentContext(){
    const route=location.hash||"";
    const titleEl=document.querySelector("#view h1, main h1, #view h2, main h2");
    const title=titleEl?String(titleEl.textContent||"").replace(/\s+/g," ").trim():"";
    const actionTexts=[...document.querySelectorAll("#view button, main button")]
      .map(btn=>String(btn.textContent||btn.getAttribute("title")||"").replace(/\s+/g," ").trim())
      .filter(Boolean)
      .slice(0,12);
    return {
      route,
      societe:session?.societe||"",
      module:session?.transverse||"",
      title,
      actions:actionTexts
    };
  }

  window.aiSend=async function(){
    if(aiTyping)return;
    const input=document.getElementById("ai-input");
    const send=document.getElementById("ai-send");
    if(!input)return;
    const msg=input.value.trim();
    if(!msg)return;
    input.value="";
    aiAutoResize(input);
    const sugg=document.getElementById("ai-suggestions");
    if(sugg)sugg.style.display="none";
    aiAppendMessage(msg,"user");
    aiHistory.push({role:"user",content:msg});
    aiTyping=true;
    if(send)send.disabled=true;
    const typingEl=aiAppendMessage("…","ai ai-typing");
    try{
      const data=await sgdiApi("/assistant/chat",{
        method:"POST",
        legacy:false,
        body:{message:msg,history:aiHistory.slice(-10,-1),context:aiCurrentContext()}
      });
      if(typingEl)typingEl.remove();
      aiAppendMessage(data.response,"ai");
      aiHistory.push({role:"assistant",content:data.response});
    }catch(e){
      if(typingEl)typingEl.remove();
      aiAppendMessage("Assistant indisponible : "+(e.message||"vérifiez votre session puis réessayez."),"ai");
    }finally{
      aiTyping=false;
      if(send)send.disabled=false;
      setTimeout(()=>input.focus(),50);
    }
  };

  // Monter le widget dès que le DOM est prêt
  if(document.readyState==="loading")
    document.addEventListener("DOMContentLoaded",aiMount);
  else
    aiMount();
})();
